		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;Mathura&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;Dwarkadhish Temple,&amp;nbsp;Govardhan Hill&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;Kanyakumari&lt;/td&gt;
