			&lt;td style=&quot;text-align: center;&quot;&gt;Chennai&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;Government Museum, Valluvar Kottam, St. George Fort,&amp;nbsp;&amp;nbsp;Arignar Anna Zoological Park.&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;Mysuru&lt;/td&gt;
