&lt;/table&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;मैसूर&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;वृंदावन उद्यान एक विशाल और प्यारा उद्यान है।&lt;/li&gt;
	&lt;li&gt;उद्यान कावेरी नदी के पार बनाए गए हैं।&lt;/li&gt;
	&lt;li&gt;यह प्रसिद्ध कृष्णराज सागर बांध के निकट स्थित है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;background-color:(255, 255, 255);width:330px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;स्थान&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;प्रसिद्ध ऐतिहासिक स्थान&lt;/strong&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;मनाली&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;कुल्लू हिल्स, हडिम्बा मंदिर&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;मोहाली&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;फतेह बुर्ज,जयंती देवी मंदिर&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;मथुरा&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;द्वारकाधीश मंदिर, गोवर्धन हिल&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;कन्याकुमारी&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;विवेकानंद रॉक मेमोरियल, सरवानी शक्तिपीठ श्री कन्या कुमारी भगवती अम्मन मंदिर।&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;मदुराइ&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;मीनाक्षी मंदिर, कूडल अज़गर मंदिर।&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;चेन्नई&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;सरकार संग्रहालय, वल्लुवर कोट्टम, सेंट जॉर्ज किला, अरिग्नार अन्ना जूलॉजिकल पार्क।&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;मैसूर&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;मैसूर पैलेस, वृंदावन गार्डन, केआरएस बांध, चामुंडेश्वरी मंदिर।&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;Akbar.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Dahsala system -&amp;nbsp;&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;Raja Todar Mal,&lt;/strong&gt; finance minister of Akbar, brought a new system of revenue collection known as the&lt;strong&gt; zabti system or dahshala system&lt;/strong&gt;.&amp;nbsp;&lt;/li&gt;
		&lt;li&gt;Under this system, a careful survey of crop yields and prices that has been&amp;nbsp;cultivated for a period of&lt;strong&gt;&amp;nbsp;ten&amp;nbsp;years&lt;/strong&gt; was taken.&amp;nbsp;&lt;/li&gt;
		&lt;li&gt;This share of the state was determined for the various cate&amp;shy;gories of lands on the basis of the fertility of the soil and the produce of the last ten years.&amp;nbsp;&lt;/li&gt;
		&lt;li&gt;The land was divided into four categories -
		&lt;ul&gt;
			&lt;li&gt;&lt;strong&gt;Polaj&lt;/strong&gt;&amp;nbsp;- cultivated every year&lt;/li&gt;
			&lt;li&gt;&lt;strong&gt;Parauti&lt;/strong&gt; - once in two years&lt;/li&gt;
			&lt;li&gt;&lt;strong&gt;Chachar &lt;/strong&gt;- once in three or four years&lt;/li&gt;
			&lt;li&gt;&lt;strong&gt;Banjar&lt;/strong&gt; - once in five or more years&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;Payment of revenue was made generally &lt;strong&gt;in cash&lt;/strong&gt;.&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;strong&gt;&lt;u&gt;अकबर&lt;/u&gt;&lt;/strong&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;दहसाल प्रणाली&lt;/strong&gt;&lt;strong&gt; -&amp;nbsp;&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;अकबर के वित्त मंत्री &lt;strong&gt;राजा टोडर मल&lt;/strong&gt; ने राजस्व संग्रह की एक नई प्रणाली लाई, जिसे &lt;strong&gt;ज़बती प्रणाली या दशाला प्रणाली&lt;/strong&gt; के रूप में जाना जाता है।&amp;nbsp;&lt;/li&gt;
		&lt;li&gt;इस प्रणाली के तहत, फसल की पैदावार और &lt;strong&gt;दस वर्ष&lt;/strong&gt; की अवधि के लिए खेती की गई कीमतों का सावधानीपूर्वक सर्वेक्षण किया गया था।&lt;/li&gt;
		&lt;li&gt;राज्य का यह हिस्सा मृदा की उर्वरता और पिछले दस वर्षों की उपज के आधार पर भूमि की विभिन्न श्रेणियों के लिए निर्धारित किया गया था।&lt;/li&gt;
		&lt;li&gt;जमीन को चार श्रेणियों में बांटा गया था -
		&lt;ul&gt;
			&lt;li&gt;&lt;strong&gt;पोलाज&lt;/strong&gt; - हर वर्ष खेती की जाती है&lt;/li&gt;
			&lt;li&gt;&lt;strong&gt;परौती&lt;/strong&gt; - दो वर्ष में एक बार&lt;/li&gt;
			&lt;li&gt;&lt;strong&gt;चाचर&lt;/strong&gt; - तीन या चार वर्ष में एक बार&lt;/li&gt;
			&lt;li&gt;&lt;strong&gt;बंजर&lt;/strong&gt; - पाँच या अधिक वर्षों में एक बार&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;राजस्व का भुगतान आम तौर पर नकद में किया जाता था।&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;Four Stars of Destiny&lt;/strong&gt;&lt;/u&gt;.&amp;nbsp;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;MM Naravane&lt;/strong&gt;&amp;#39;s book&amp;nbsp;&lt;strong&gt;Four Stars of Destiny&lt;/strong&gt;&amp;nbsp;revealed insights on China Border Crisis.&lt;/li&gt;
&lt;/ul&gt;
&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;

&lt;ul&gt;
	&lt;li&gt;The memoir of former Indian Army Chief General M M Naravane is titled &amp;quot;Four Stars of Destiny.&amp;quot;&lt;/li&gt;
	&lt;li&gt;This memoir discloses details of a key conversation between Gen Naravane and Defence Minister Rajnath Singh, on August 31, 2020, during the tense situation at the Line of Actual Control (LAC) in eastern Ladakh involving movements of Chinese PLA tanks and troops.&lt;/li&gt;
	&lt;li&gt;Gen Naravane recalled the operational response decided during the LAC standoff with China.&lt;/li&gt;
	&lt;li&gt;Press Trust of India published excerpts from the memoir on December 18, 2023.&lt;/li&gt;
	&lt;li&gt;Publisher Penguin Random House has been asked to refrain from further sharing of excerpts or soft copies of the book until the review by the Indian Army is completed.&lt;/li&gt;
&lt;/ul&gt;<br><br>सही उत्तर &lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;फोर स्टार्स ऑफ डेस्टिनी&lt;/span&gt;&lt;/u&gt; हैं।&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;एम.एम. नरवणे&lt;/strong&gt; की पुस्तक &lt;strong&gt;फोर स्टार्स ऑफ डेस्टिनी&lt;/strong&gt; ने चीन सीमा संकट पर अंतर्दृष्टि का खुलासा किया।&lt;/li&gt;
&lt;/ul&gt;
&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;

&lt;ul&gt;
	&lt;li&gt;पूर्व भारतीय सेना प्रमुख जनरल एम एम नरवणे के संस्मरण का शीर्षक &amp;quot;फोर स्टार्स ऑफ डेस्टिनी&amp;quot; है।&lt;/li&gt;
	&lt;li&gt;यह संस्मरण 31 अगस्त, 2020 को पूर्वी लद्दाख में वास्तविक नियंत्रण रेखा (LAC) पर चीनी PLA&amp;nbsp;टैंक और सैनिकों की गतिविधियों से जुड़ी तनावपूर्ण स्थिति के दौरान जनरल नरवणे और रक्षा मंत्री राजनाथ सिंह के बीच हुई एक महत्वपूर्ण बातचीत के विवरण का खुलासा करता है।&lt;/li&gt;
	&lt;li&gt;जनरल नरवणे ने चीन के साथ LAC पर गतिरोध के दौरान तय की गई ऑपरेशनल प्रतिक्रिया को याद किया।&lt;/li&gt;
	&lt;li&gt;प्रेस ट्रस्ट ऑफ इंडिया ने 18 दिसंबर, 2024 को संस्मरण के अंश प्रकाशित किए।&lt;/li&gt;
	&lt;li&gt;प्रकाशक पेंगुइन रैंडम हाउस को भारतीय सेना द्वारा समीक्षा पूरी होने तक पुस्तक के अंश या सॉफ्ट प्रतियां साझा करने से परहेज करने के लिए कहा गया है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;&quot;&gt;The correct answer&lt;span class=&quot;highlight-keywords&quot; style=&quot;&quot;&gt;&amp;nbsp;is&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 1&lt;/span&gt;,&amp;nbsp; i.e.,&amp;nbsp;&lt;u&gt;&lt;strong&gt;Consumer Price Index&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li style=&quot;&quot;&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Wholesale Price Index (WPI)&lt;/span&gt;&amp;nbsp;was the main index for measurement of&lt;span class=&quot;highlight-keywords&quot; style=&quot;&quot;&gt;&amp;nbsp;inflation&lt;/span&gt;&amp;nbsp;in India&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;till April 2014&lt;/span&gt;&amp;nbsp;when RBI adopted a new&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Consumer Price Index (CPI)&lt;/span&gt;&amp;nbsp;(combined) as the key measure of&lt;span class=&quot;highlight-keywords&quot; style=&quot;&quot;&gt;&amp;nbsp;inflation&lt;/span&gt;.&lt;/li&gt;
	&lt;li style=&quot;&quot;&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;CPI calculates the difference in the price&lt;/span&gt;&amp;nbsp;of commodities and services such as food, medical care, education, electronics, etc, which Indian consumers buy for use.&lt;/li&gt;
	&lt;li style=&quot;&quot;&gt;&lt;strong&lt;span class=&quot;highlight-keywords&quot; style=&quot;&quot;&gt;&amp;gt;Inflation refers to the&amp;nbsp;&lt;span class=&quot;highlight-keywords&quot; style=&quot;&quot;&gt;ris&lt;/span&gt;e in the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;prices of most goods and services of daily or common use&lt;/span&gt;, such as food, clothing, housing, recreation, transport, consumer staples, etc. I&lt;span style=&quot;font-weight: 700;&quot;&gt;nflation measures the average price change&lt;/span&gt;&amp;nbsp;in a basket of commodities and services over time.&lt;/strong&lt;span&gt;&lt;/li&gt;
	&lt;li style=&quot;&quot;&gt;The opposite and rare fall in the price index of t&lt;span class=&quot;highlight-keywords&quot; style=&quot;&quot;&gt;his&lt;/span&gt;&amp;nbsp;basket of items&lt;span class=&quot;highlight-keywords&quot; style=&quot;&quot;&gt;&amp;nbsp;is&lt;/span&gt;&amp;nbsp;called &amp;lsquo;&lt;span style=&quot;font-weight: 700;&quot;&gt;deflation&lt;/span&gt;&amp;rsquo;.&lt;span class=&quot;highlight-keywords&quot; style=&quot;&quot;&gt;&amp;nbsp;Inflation&lt;/span&gt;&lt;span class=&quot;highlight-keywords&quot; style=&quot;&quot;&gt;&amp;nbsp;is&lt;/span&gt;&amp;nbsp;indicative of the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;decrease in the purchasing power&lt;/span&gt;&amp;nbsp;of a unit of a country&amp;rsquo;s currency. T&lt;span class=&quot;highlight-keywords&quot; style=&quot;&quot;&gt;his&lt;/span&gt;&lt;span class=&quot;highlight-keywords&quot; style=&quot;&quot;&gt;&amp;nbsp;is&lt;/span&gt;&amp;nbsp;&lt;strong&lt;span class=&quot;highlight-keywords&quot; style=&quot;&quot;&gt;&amp;gt;measured in percentages.&lt;/strong&lt;span&gt;&lt;/li&gt;
	&lt;li style=&quot;&quot;&gt;These are some of the chief reasons for the increase in prices:
	&lt;ul style=&quot;&quot;&gt;
		&lt;li style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;High demand and low production or supply of multiple commodities&lt;/span&gt;&amp;nbsp;create a demand-supply gap, which leads to a&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;hike in prices&lt;/span&gt;.&lt;/li&gt;
		&lt;li style=&quot;&quot;&gt;Excess circulation of money leads to&lt;span class=&quot;highlight-keywords&quot; style=&quot;&quot;&gt;&amp;nbsp;inflation&lt;/span&gt;&amp;nbsp;as&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;money loses its purchasing power&lt;/span&gt;.&lt;/li&gt;
		&lt;li style=&quot;&quot;&gt;With people having more money, they also tend to spend more, which causes increased demand.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p style=&quot;&quot;&gt;सही उत्तर &lt;span style=&quot;font-weight: 700;&quot;&gt;विकल्प 3&amp;nbsp;&lt;/span&gt;अर्थात् , &lt;u&gt;&lt;strong&gt;उपभोक्ता मूल्य सूचकांक&lt;/strong&gt;&lt;/u&gt;&amp;nbsp;&lt;span style=&quot;background-color: rgb(255, 165, 0);&quot;&gt;है।&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;थोक मूल्य सूचकांक (WPI)&lt;/span&gt; &lt;span style=&quot;font-weight: 700;&quot;&gt;अप्रैल 2014 तक&lt;/span&gt; भारत में &lt;span class=&quot;highlight-keywords&quot; style=&quot;&quot;&gt;मुद्रास्फीति की&lt;/span&gt; माप के लिए मुख्य सूचकांक था जब RBI ने &lt;span class=&quot;highlight-keywords&quot; style=&quot;&quot;&gt;मुद्रास्फीति&lt;/span&gt; के प्रमुख उपाय के रूप में एक नई&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;उपभोक्ता मूल्य सूचकांक (CPI)&lt;/span&gt; (संयुक्त) अपनाया।&lt;/li&gt;
	&lt;li style=&quot;&quot;&gt;CPI&amp;nbsp;खाद्य, चिकित्सा देखभाल, शिक्षा, इलेक्ट्रॉनिक्स, आदि जैसी वस्तुओं और सेवाओं &lt;span style=&quot;font-weight: 700;&quot;&gt;की कीमत में अंतर की गणना करता है&lt;/span&gt;, जिसे भारतीय उपभोक्ता द्वारा उपयोग के लिए खरीदा जाता हैं।&lt;/li&gt;
	&lt;li style=&quot;&quot;&gt;&lt;strong&lt;span class=&quot;highlight-keywords&quot; style=&quot;&quot;&gt; &amp;gt;मुद्रास्फीति का तात्पर्य दैनिक या &lt;strong&gt;सामान्य उपयोग की अधिकांश वस्तुओं और सेवाओं,&lt;/strong&gt; जैसे खाद्य, वस्त्र, आवास, मनोरंजन, परिवहन, उपभोक्ता स्टेपल आदि की कीमतों में वृद्धि से है। &lt;strong&gt;मुद्रास्फीति समय के साथ वस्तुओं और सेवाओं की विविध समूह में औसत मूल्य परिवर्तन को मापती है।&lt;/strong&gt;&lt;/strong&lt;span&gt;&lt;/li&gt;
	&lt;li style=&quot;&quot;&gt;वस्तुओं की इस विविध समूह&amp;nbsp;के मूल्य सूचकांक में विपरीत और असामान्य गिरावट को &amp;#39;&lt;strong&gt;अपस्फीति&lt;/strong&gt;&amp;#39; कहा जाता है। मुद्रास्फीति किसी देश की मुद्रा की एक इकाई की &lt;strong&gt;क्रय शक्ति में कमी का सूचक है।&lt;/strong&gt; &lt;strong&gt;इसे प्रतिशत में मापा जाता है।&lt;/strong&gt;&lt;strong&lt;span class=&quot;highlight-keywords&quot; style=&quot;&quot;&gt; &lt;/strong&lt;span&gt;&lt;/li&gt;
	&lt;li style=&quot;&quot;&gt;&lt;u&gt;&lt;strong&gt;कीमतों में वृद्धि के ये कुछ प्रमुख कारण हैं:&lt;/strong&gt;&lt;/u&gt;
	&lt;ul style=&quot;&quot;&gt;
		&lt;li style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;उच्च मांग और कई वस्तुओं के कम उत्पादन या आपूर्ति से&lt;/span&gt; मांग-आपूर्ति का अंतर पैदा होता है, जिससे &lt;span style=&quot;font-weight: 700;&quot;&gt;कीमतों में बढ़ोतरी होती है&lt;/span&gt; ।&lt;/li&gt;
		&lt;li style=&quot;&quot;&gt;धन के अत्यधिक संचलन से मुद्रास्फीति बढ़ती है &lt;strong&gt;क्योंकि धन अपनी क्रय शक्ति खो देता है।&lt;/strong&gt;&lt;br /&gt;
		&lt;/li&gt;
		&lt;li style=&quot;&quot;&gt;लोगों के पास अधिक धन होने के कारण वे अधिक खर्च भी करते हैं, जिससे मांग बढ़ती है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;strong&gt;&lt;u&gt;Groundnut&lt;/u&gt;.&lt;/strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;Dryland Farming:&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;In India, the dryland farming is largely confined to the regions having annual rainfall less than 75 cm.&amp;nbsp;&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;These regions grow hardy and drought resistant crops such as &lt;strong&gt;pulses, ragi, bajra, moong, gram and guar (fodder crops)&lt;/strong&gt; and practice various measures of &lt;strong&gt;soil moisture conservation and rain water harvesting.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;Groundnut:&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;India produces about 18.8 per cent of the total groundnut production in the world (2018).&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;It is &lt;strong&gt;largely a rainfed kharif crop of drylands.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;But in &lt;strong&gt;southern India, it is cultivated during rabi season as well.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;It covers about &lt;strong&gt;3.6 per cent of total cropped area in the country.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Gujarat, Rajasthan, Tamil Nadu, Telangana, Andhra Pradesh, Karnataka and Maharashtra are the leading producers.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Yield of groundnut is comparatively high in Tamil Nadu where it is partly irrigated.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;But its &lt;strong&gt;yield is low in Telangana, Andhra Pradesh and Karnataka&lt;/strong&gt;.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width:350px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td&gt;&lt;strong&gt;Sugarcane&lt;/strong&gt;&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;Sugarcane is a crop of &lt;strong&gt;tropical areas.&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;Under rainfed conditions, it is cultivated in sub-humid and humid climates.&lt;/li&gt;
				&lt;li&gt;But it is &lt;strong&gt;largely an irrigated crop&lt;/strong&gt; in India.&lt;/li&gt;
				&lt;li&gt;In Indo-Gangetic plain, its cultivation is &lt;strong&gt;largely concentrated in Uttar Pradesh.&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;Sugarcane growing area in western India is &lt;strong&gt;spread over Maharashtra and Gujarat.&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;In &lt;strong&gt;southern India, it is cultivated in irrigated tracts of Karnataka, Tamil Nadu, Telangana and Andhra Pradesh.&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;India was the &lt;strong&gt;second largest producer of sugarcane after Brazil in 2018.&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;It accounts for about &lt;strong&gt;19.7 per cent of the world production of sugarcane.&lt;/strong&gt;&amp;nbsp;&lt;/li&gt;
				&lt;li&gt;But it occupies&lt;strong&gt; only 2.4 per cent of total cropped area in the country.&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;&lt;strong&gt;Uttar Pradesh produces about two-fifth of sugarcane of the country.&amp;nbsp;&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;&lt;strong&gt;Maharashtra, Karnataka, Tamil Nadu, and Andhra Pradesh&lt;/strong&gt; are other leading producers of this crop where &lt;strong&gt;yield level of sugarcane is high.&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;&lt;strong&gt;Its yield is low in northern India.&lt;/strong&gt;&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;Jute&lt;/strong&gt;&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;Jute is used for making coarse cloth, bags, sacks and decorative items.&amp;nbsp;&lt;/li&gt;
				&lt;li&gt;It is a &lt;strong&gt;cash crop in West Bengal and adjoining eastern parts of the country.&amp;nbsp;&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;At present, &lt;strong&gt;India produces about three-fifth of jute production of the world.&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;&lt;strong&gt;West Bengal accounts for about three-fourth of the production&lt;/strong&gt; in the country.&amp;nbsp;&lt;/li&gt;
				&lt;li&gt;&lt;strong&gt;Bihar and Assam &lt;/strong&gt;are other jute growing areas.&lt;/li&gt;
				&lt;li&gt;Being concentrated only in a few states, this &lt;strong&gt;crop accounts for only about 0.5 per cent of total cropped area in the country.&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;&lt;strong&gt;Bihar is ranked 2nd in terms of Jute production.&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;&lt;strong&gt;Purnia District has the highest production of Jute in Bihar.&lt;/strong&gt;&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;Wheat&lt;/strong&gt;&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;Wheat is the &lt;strong&gt;second most important cereal crop in India after rice&lt;/strong&gt;.&lt;/li&gt;
				&lt;li&gt;India produces about &lt;strong&gt;12.8 per cent of total wheat production of world (2017).&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;It is primarily a &lt;strong&gt;crop of temperate zone.&lt;/strong&gt;
				&lt;ul&gt;
					&lt;li&gt;Hence, its cultivation in India is done &lt;strong&gt;during winter i.e.,&amp;nbsp;rabi season.&lt;/strong&gt;&lt;/li&gt;
				&lt;/ul&gt;
				&lt;/li&gt;
				&lt;li&gt;About &lt;strong&gt;85 per cent of total area under this crop is concentrated in north &lt;/strong&gt;and central regions of the country i.e. IndoGangetic Plain, Malwa Plateau and Himalayas up to 2,700 m altitude.&lt;/li&gt;
				&lt;li&gt;Being a rabi crop, it is &lt;strong&gt;mostly grown under irrigated conditions.&amp;nbsp;&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;&lt;strong&gt;But it is a rainfed crop in Himalayan highlands and parts of Malwa plateau in Madhya Pradesh.&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;About&lt;strong&gt; 14 per cent of the total cropped area in the country is under wheat cultivation.&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;&lt;strong&gt;Uttar Pradesh, Madhya Pradesh, Punjab, Haryana and Rajasthan are leading wheat producing states.&lt;/strong&gt;&amp;nbsp;&lt;/li&gt;
				&lt;li&gt;The &lt;strong&gt;yield level of wheat is very high (above 4,000 k.g. per ha) in Punjab and Haryana whereas, Uttar Pradesh, Rajasthan and Bihar have moderate yields.&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;The states like &lt;strong&gt;Madhya Pradesh, Himachal Pradesh and Jammu and Kashmir growing wheat under rainfed conditions have low yield.&lt;/strong&gt;&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;<br><br>&lt;p&gt;सही &lt;span style=&quot;&quot;&gt;उत्तर&amp;nbsp;&lt;/span&gt;&lt;u&gt;&lt;strong&gt;मूंगफली&lt;/strong&gt;&lt;/u&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;है&lt;/span&gt;।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;शुष्क भूमि खेती:&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;भारत में, शुष्क भूमि की खेती काफी हद तक 75 सेमी से कम वार्षिक वर्षा वाले क्षेत्रों तक ही सीमित है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;ये क्षेत्र कठोर और सूखा प्रतिरोधी फसलें उगाते &lt;span style=&quot;&quot;&gt;हैं,&amp;nbsp;&lt;/span&gt;जैसे&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;दाल, रागी, बाजरा, मूंग, चना और ग्वार (चारा फसल)&lt;/span&gt;&amp;nbsp;हैं और &lt;strong&gt;मृदा की नमी संरक्षण और वर्षा जल संचयन &lt;/strong&gt;के विभिन्न उपायों का अभ्यास करते हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;मूंगफली:&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;भारत विश्व (2018) में कुल मूंगफली उत्पादन का लगभग 18.8 प्रतिशत उत्पादन करता है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;यह&lt;strong&gt; बड़े पैमाने पर शुष्क क्षेत्रों की वर्षा आधारित खरीफ फसल &lt;/strong&gt;है।&lt;/li&gt;
	&lt;li&gt;लेकिन &lt;strong&gt;दक्षिण भारत &lt;/strong&gt;में&lt;strong&gt; इसकी खेती रबी के मौसम में भी की जाती है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;यह &lt;strong&gt;देश में कुल फसली क्षेत्र का &lt;/strong&gt;लगभग &lt;strong&gt;3.6 प्रतिशत है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;गुजरात, राजस्थान, तमिलनाडु, तेलंगाना, आंध्र प्रदेश, कर्नाटक और महाराष्ट्र प्रमुख उत्पादक हैं।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;मूंगफली की उपज तमिलनाडु में तुलनात्मक रूप से अधिक है जहां यह आंशिक रूप से सिंचित है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;लेकिन &lt;strong&gt;तेलंगाना, आंध्र प्रदेश और कर्नाटक में &lt;/strong&gt;इसकी &lt;strong&gt;उपज कम है।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot; width: 350px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;गन्ना&amp;nbsp;&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;&lt;span style=&quot;&quot;&gt;गन्ना &lt;strong&gt;उष्णकटिबंधीय क्षेत्रों &lt;/strong&gt;की फसल है।&lt;/span&gt;&lt;/li&gt;
				&lt;li&gt;&lt;span style=&quot;&quot;&gt;​&lt;/span&gt;&lt;span style=&quot;&quot;&gt;वर्षा आधारित परिस्थितियों में, इसकी खेती उप-आर्द्र और आर्द्र जलवायु में की जाती है।&lt;/span&gt;&lt;/li&gt;
				&lt;li&gt;&lt;span style=&quot;&quot;&gt;लेकिन यह भारत में &lt;strong&gt;काफी हद तक एक सिंचित फसल&lt;/strong&gt; है।&lt;/span&gt;&lt;/li&gt;
				&lt;li&gt;&lt;span style=&quot;&quot;&gt;सिंधु-गंगा के मैदान में, इसकी खेती&lt;strong&gt; काफी हद तक उत्तर प्रदेश में केंद्रित&lt;/strong&gt; है।&lt;/span&gt;&lt;/li&gt;
				&lt;li&gt;&lt;span style=&quot;&quot;&gt;पश्चिमी भारत में गन्ना उत्पादक क्षेत्र&lt;strong&gt; महाराष्ट्र और गुजरात में फैला &lt;/strong&gt;हुआ है।&lt;/span&gt;&lt;/li&gt;
				&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;दक्षिण भारत में इसकी खेती कर्नाटक, तमिलनाडु, तेलंगाना और आंध्र प्रदेश के सिंचित क्षेत्रों में की जाती है।&lt;/span&gt;&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;2018 में ब्राजील के बाद &lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;&quot;&gt;भारत &lt;/span&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;गन्ने का दूसरा सबसे बड़ा उत्पादक &lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;&quot;&gt;था।&lt;/span&gt;&lt;/li&gt;
				&lt;li&gt;&lt;span style=&quot;&quot;&gt;यह &lt;strong&gt;विश्व के गन्ने के उत्पादन का लगभग 19.7 प्रतिशत&lt;/strong&gt; है।&lt;/span&gt;&lt;/li&gt;
				&lt;li&gt;&lt;span style=&quot;&quot;&gt;लेकिन यह &lt;strong&gt;देश में कुल फसली क्षेत्र का केवल 2.4&lt;/strong&gt; &lt;strong&gt;प्रतिशत &lt;/strong&gt;है।&lt;/span&gt;&lt;/li&gt;
				&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;उत्तर प्रदेश देश का लगभग दो-पांचवां गन्ना पैदा करता है।&lt;/span&gt;&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;महाराष्ट्र, कर्नाटक, तमिलनाडु और आंध्र प्रदेश इस फसल के &lt;/strong&gt;अन्य प्रमुख उत्पादक हैं जहां &lt;strong&gt;गन्ने की उपज का स्तर अधिक है।&lt;/strong&gt;&lt;/span&gt;&lt;/li&gt;
				&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;उत्तर भारत में इसकी उपज कम है।&lt;/span&gt;&lt;/strong&gt;&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;जूट&lt;/span&gt;&lt;/strong&gt;&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;&lt;span style=&quot;&quot;&gt;जूट का उपयोग मोटा कपड़ा, बैग, बोरी और सजावटी सामान बनाने के लिए किया जाता है।&lt;/span&gt;&lt;/li&gt;
				&lt;li&gt;&lt;span style=&quot;&quot;&gt;यह&lt;strong&gt; पश्चिम बंगाल और देश के आसपास के पूर्वी हिस्सों में एक नकदी फसल &lt;/strong&gt;है।&lt;/span&gt;&lt;/li&gt;
				&lt;li&gt;&lt;span style=&quot;&quot;&gt;वर्तमान में,&lt;strong&gt; भारत दुनिया के जूट उत्पादन का लगभग तीन-पांचवां उत्पादन करता है।&lt;/strong&gt;&lt;/span&gt;&lt;/li&gt;
				&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;पश्चिम बंगाल देश के उत्पादन का लगभग तीन-चौथाई हिस्सा है।&lt;/span&gt;&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;बिहार और असम&lt;/strong&gt; अन्य जूट उत्पादक क्षेत्र हैं।&lt;/span&gt;&lt;/li&gt;
				&lt;li&gt;&lt;span style=&quot;&quot;&gt;केवल कुछ राज्यों में केंद्रित होने के कारण, यह &lt;strong&gt;फसल देश में कुल फसली क्षेत्र का लगभग 0.5 प्रतिशत है।&lt;/strong&gt;&lt;/span&gt;&lt;/li&gt;
				&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;जूट उत्पादन में बिहार का दूसरा स्थान है।&lt;/span&gt;&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;बिहार में पूर्णिया जिले में जूट का सर्वाधिक उत्पादन होता है।&lt;/span&gt;&lt;/strong&gt;&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;गेहूं&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;चावल के बाद भारत में &lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;&quot;&gt;गेहूँ &lt;/span&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;दूसरी सबसे महत्वपूर्ण अनाज की फसल &lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;&quot;&gt;है।&lt;/span&gt;&lt;/li&gt;
				&lt;li&gt;&lt;span style=&quot;&quot;&gt;भारत &lt;strong&gt;विश्व (2017) के कुल गेहूं उत्पादन का लगभग 12.8 प्रतिशत &lt;/strong&gt;उत्पादन करता है।&lt;/span&gt;&lt;/li&gt;
				&lt;li&gt;&lt;span style=&quot;&quot;&gt;यह मुख्य रूप से &lt;strong&gt;समशीतोष्ण क्षेत्र की फसल&lt;/strong&gt; है।&lt;/span&gt;
				&lt;ul&gt;
					&lt;li&gt;&lt;span style=&quot;&quot;&gt;अत: भारत में इसकी खेती &lt;strong&gt;शीतकाल&lt;/strong&gt; &lt;strong&gt;अर्थात रबी ऋतु में &lt;/strong&gt;की जाती है।&lt;/span&gt;&lt;/li&gt;
				&lt;/ul&gt;
				&lt;/li&gt;
				&lt;li&gt;&lt;span style=&quot;&quot;&gt;इस &lt;strong&gt;फसल के तहत कुल क्षेत्रफल का लगभग 85 प्रतिशत देश के उत्तर&lt;/strong&gt; और मध्य क्षेत्रों में केंद्रित है, अर्थात&amp;nbsp;सिंधु गंगा का मैदान, मालवा का पठार और हिमालय 2,700 मीटर की ऊँचाई तक।&lt;/span&gt;&lt;/li&gt;
				&lt;li&gt;&lt;span style=&quot;&quot;&gt;रबी की फसल होने के कारण, यह &lt;strong&gt;ज्यादातर सिंचित परिस्थितियों में उगाई जाती है।&lt;/strong&gt;&lt;/span&gt;&lt;/li&gt;
				&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;लेकिन यह मध्य प्रदेश में हिमालयी उच्चभूमि और मालवा पठार के कुछ हिस्सों में वर्षा आधारित फसल है।&lt;/span&gt;&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;देश में कुल फसली क्षेत्र का लगभग 14 प्रतिशत गेहूँ की खेती के अधीन है।&lt;/span&gt;&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;उत्तर प्रदेश, मध्य प्रदेश, पंजाब, हरियाणा और राजस्थान प्रमुख गेहूँ उत्पादक राज्य हैं।&lt;/strong&gt;&lt;/span&gt;&lt;/li&gt;
				&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;पंजाब और हरियाणा में &lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;गेहूँ&amp;nbsp;&lt;/span&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;का उपज स्तर बहुत अधिक (4,000 किलोग्राम प्रति हेक्टेयर से ऊपर) है, जबकि उत्तर प्रदेश, राजस्थान और बिहार में मध्यम उपज है।&lt;/span&gt;&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;मध्य प्रदेश, हिमाचल प्रदेश और जम्मू-कश्मीर &lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;&quot;&gt;जैसे राज्यों &lt;/span&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;में वर्षा आधारित परिस्थितियों में गेहूँ उगाने से उपज कम होती है।&lt;/span&gt;&lt;/strong&gt;&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;Option &lt;strong&gt;3&lt;/strong&gt; is correct, i.e.&amp;nbsp;&lt;u&gt;&lt;strong&gt;Savanna - Africa&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Savanna grassland&lt;/strong&gt;&lt;/u&gt; is found in the hot zone(10-30 degree N &amp;amp; S) with the Sudan climate type.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Los Llanos&lt;/strong&gt; is a vast tropical grassland plain situated to the east of the Andes in Colombia and Venezuela, in northwestern South America.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Steppe or temperate grassland &lt;/strong&gt;is found in the warm Temperate zone(30-45 degrees N &amp;amp; S) with the central continental(steppe) climate type.​&lt;/li&gt;
&lt;/ul&gt;

