&lt;ul&gt;
	&lt;li style=&quot;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;India 2020&lt;/span&gt;&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li style=&quot;&quot;&gt;In this book, Dr APJ Abdul Kalam and his close associate&lt;strong&gt; YS Rajan&lt;/strong&gt; examine &lt;strong&gt;India&amp;#39;s strengths and weaknesses&lt;/strong&gt; to offer a vision of how India can be among the &lt;strong&gt;world&amp;#39;s first five economic powers in the year 2020.&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;img alt=&quot;9780143423683: India 2020: A Vision for the New Millennium, packaging may  vary - Kalam, A P J Abdul: 0143423681 - AbeBooks&quot; src=&quot;//cdn.testbook.com/images/production/quesImages/qImage32052.png&quot; /&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li style=&quot;&quot;&gt;&lt;strong&gt;Some of the Famous books &amp;amp; their Author:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li style=&quot;&quot;&gt;&lt;strong&gt;Dr APJ Abdul Kalam&lt;/strong&gt;: India 2020, Wings of Fire, Ignited Minds, Turning Points, Target 3 billion.&lt;/li&gt;
		&lt;li style=&quot;&quot;&gt;&lt;strong&gt;Pranab Mukherjee&lt;/strong&gt;: Thoughts and Reflections, The Coalition years, The turbulent years ( 1980-1996), Beyond Survival.&lt;/li&gt;
		&lt;li style=&quot;&quot;&gt;&lt;strong&gt;Prasoon Joshi&lt;/strong&gt;: Sunshine Lane, Thinking Aloud, Dhoop ke Sikke.&lt;/li&gt;
		&lt;li style=&quot;&quot;&gt;&lt;strong&gt;Ram Nath kovind&lt;/strong&gt;: The Republic Ethic (July 2017- July 2018).&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p style=&quot;&quot;&gt;सही उत्तर&amp;nbsp;&lt;strong&gt;&lt;u&gt;डॉ.&lt;/u&gt;&lt;/strong&gt;&lt;u&gt;&lt;strong&gt; ए.पी.जे.&amp;nbsp;अब्दुल कलाम&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li style=&quot;&quot;&gt;&lt;strong&gt;इंडिया 2020&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li style=&quot;&quot;&gt;&lt;strong&gt;वर्ष 2020 तक&amp;nbsp;भारत दुनिया की प्रथम पांच आर्थिक शक्तियों&lt;/strong&gt; में कैसे शामिल हो सकता है, इस संबंध में एक विज़न प्रस्तुत करने के लिए इस पुस्तक में डॉ. ए.पी.जे. अब्दुल कलाम और उनके करीबी सहयोगी &lt;strong&gt;वाईएस राजन&lt;/strong&gt; ने &lt;strong&gt;भारत की ताकत और कमजोरियों &lt;/strong&gt;की समीक्षा की है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;img alt=&quot;9780143423683: India 2020: A Vision for the New Millennium, packaging may  vary - Kalam, A P J Abdul: 0143423681 - AbeBooks&quot; src=&quot;//cdn.testbook.com/images/production/quesImages/qImage32052.png&quot; /&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li style=&quot;&quot;&gt;&lt;strong&gt;कुछ प्रसिद्ध पुस्तकें और उनके लेखक:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li style=&quot;&quot;&gt;&lt;strong&gt;डॉ. ए.पी.जे. अब्दुल कलाम: &lt;/strong&gt;भारत 2020, विंग्स ऑफ फायर, इग्नाइटेड माइंड्स, टर्निंग पॉइंट्स, टारगेट 3 बिलियन।&lt;/li&gt;
		&lt;li style=&quot;&quot;&gt;&lt;strong&gt;प्रणब मुखर्जी: &lt;/strong&gt;थॉट्स एंड रिफ्लेक्शन, द कोअलिशन इयर्स, द टर्बुलेंट इयर्स (1980-1996), बियॉन्ड सर्वाइवल।&lt;/li&gt;
		&lt;li style=&quot;&quot;&gt;&lt;strong&gt;प्रसून जोशी: &lt;/strong&gt;सनशाइन लेन, थिंकिंग अलाउड, धूप के सिक्के&amp;nbsp;।&lt;/li&gt;
		&lt;li style=&quot;&quot;&gt;&lt;strong&gt;राम नाथ कोविंद:&lt;/strong&gt; द रिपब्लिक एथिक (जुलाई 2017- जुलाई 2018)&amp;nbsp;।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

questions.statement:
&lt;p&gt;Match the following ICC Under-19 World Cup titles won by India with their host countries.&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width:500px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td&gt;&lt;strong&gt;Year&lt;/strong&gt;&lt;/td&gt;
			&lt;td&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Host Country&lt;/span&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;2000&lt;/td&gt;
			&lt;td&gt;Sri Lanka&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;2008&lt;/td&gt;
			&lt;td&gt;Malaysia&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;2012&lt;/td&gt;
			&lt;td&gt;Australia&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;<br>&lt;p&gt;भारत द्वारा जीते गए आईसीसी अंडर-19 विश्व कप खिताबों को उनके मेजबान देशों के साथ सुमेलित करें।&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width:500px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td&gt;&lt;strong&gt;वर्ष&lt;/strong&gt;&lt;/td&gt;
			&lt;td&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;मेजबान देश&lt;/span&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;2000&lt;/td&gt;
			&lt;td&gt;श्रीलंका&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;2008&lt;/td&gt;
			&lt;td&gt;मलेशिया&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;2012&lt;/td&gt;
			&lt;td&gt;ऑस्ट्रेलिया&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;

questions.explanation:
&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;2000&amp;ndash;Sri Lanka, 2008&amp;ndash;Malaysia, 2012&amp;ndash;Australia.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;India has won multiple ICC Under-19 World Cup titles across different host nations.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;India won the 2000 U-19 World Cup hosted by Sri Lanka.&lt;/li&gt;
	&lt;li&gt;The 2008 title was secured in Malaysia.&lt;/li&gt;
	&lt;li&gt;Australia hosted the tournament won by India in 2012.&lt;/li&gt;
	&lt;li&gt;These wins contributed to India&amp;rsquo;s record sixth title in 2026.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;ICC Under-19 World Cup is a biennial international youth cricket tournament.&lt;/li&gt;
	&lt;li&gt;Host country refers to the nation responsible for venues and tournament logistics.&lt;/li&gt;
	&lt;li&gt;India is the most successful team in U-19 World Cup history.&lt;/li&gt;
	&lt;li&gt;The tournament serves as a platform for future international cricketers.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर है &lt;u&gt;&lt;strong&gt;2000-श्रीलंका, 2008-मलेशिया, 2012-ऑस्ट्रेलिया।&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;समाचार में&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;भारत ने विभिन्न मेजबान देशों में कई आईसीसी अंडर-19 विश्व कप खिताब जीते हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;मुख्य बिंदु&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;भारत ने श्रीलंका द्वारा आयोजित 2000 अंडर-19 विश्व कप जीता।&lt;/li&gt;
	&lt;li&gt;2008 का खिताब मलेशिया में हासिल किया गया था।&lt;/li&gt;
	&lt;li&gt;ऑस्ट्रेलिया ने 2012 में भारत द्वारा जीता गया टूर्नामेंट आयोजित किया था।&lt;/li&gt;
	&lt;li&gt;इन जीतों ने 2026 में भारत के रिकॉर्ड छठे खिताब में योगदान दिया।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;अतिरिक्त जानकारी&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;आईसीसी अंडर-19 विश्व कप एक द्विवार्षिक अंतरराष्ट्रीय युवा क्रिकेट टूर्नामेंट है।&lt;/li&gt;
	&lt;li&gt;मेजबान देश का तात्पर्य उन राष्ट्रों से है जो स्थानों और टूर्नामेंट लॉजिस्टिक्स के लिए जिम्मेदार हैं।&lt;/li&gt;
	&lt;li&gt;भारत अंडर-19 विश्व कप इतिहास में सबसे सफल टीम है।&lt;/li&gt;
	&lt;li&gt;यह टूर्नामेंट भविष्य के अंतरराष्ट्रीय क्रिकेटरों के लिए एक मंच के रूप में कार्य करता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The Correct Answer is&amp;nbsp;​&lt;u&gt;&lt;strong&gt;Light. Innovation. Society&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;International Day of Light: 16 May.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;452&quot; data-start=&quot;378&quot;&gt;
	&lt;p data-end=&quot;452&quot; data-start=&quot;380&quot;&gt;&lt;strong data-end=&quot;410&quot; data-start=&quot;380&quot;&gt;International Day of Light&lt;/strong&gt; is celebrated on &lt;strong data-end=&quot;438&quot; data-start=&quot;428&quot;&gt;May 16&lt;/strong&gt; every year.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;500&quot; data-start=&quot;453&quot;&gt;
	&lt;p data-end=&quot;500&quot; data-start=&quot;455&quot;&gt;It was first celebrated on &lt;strong data-end=&quot;497&quot; data-start=&quot;482&quot;&gt;16 May 2018&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;598&quot; data-start=&quot;501&quot;&gt;
	&lt;p data-end=&quot;598&quot; data-start=&quot;503&quot;&gt;The day marks the &lt;strong data-end=&quot;572&quot; data-start=&quot;521&quot;&gt;first successful operation of the laser in 1960&lt;/strong&gt; by &lt;strong data-end=&quot;595&quot; data-start=&quot;576&quot;&gt;Theodore Maiman&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;718&quot; data-start=&quot;599&quot;&gt;
	&lt;p data-end=&quot;718&quot; data-start=&quot;601&quot;&gt;The day shows how &lt;strong data-end=&quot;657&quot; data-start=&quot;619&quot;&gt;light and light-based technologies&lt;/strong&gt; help in science, culture, art, education, and development.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;769&quot; data-start=&quot;719&quot;&gt;
	&lt;p data-end=&quot;769&quot; data-start=&quot;721&quot;&gt;The theme is &lt;strong data-end=&quot;767&quot; data-start=&quot;734&quot;&gt;&amp;quot;Light. Innovation. Society.&amp;quot;&lt;/strong&gt;&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;877&quot; data-start=&quot;770&quot;&gt;
	&lt;p data-end=&quot;877&quot; data-start=&quot;772&quot;&gt;In &lt;strong data-end=&quot;783&quot; data-start=&quot;775&quot;&gt;2015&lt;/strong&gt;, the &lt;strong data-end=&quot;820&quot; data-start=&quot;789&quot;&gt;International Year of Light&lt;/strong&gt; raised awareness about the role of light in our lives.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;968&quot; data-start=&quot;878&quot;&gt;
	&lt;p data-end=&quot;968&quot; data-start=&quot;880&quot;&gt;The celebration helps people understand how light &lt;strong data-end=&quot;967&quot; data-start=&quot;930&quot;&gt;improves life and drives progress&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर है &lt;u&gt;&lt;strong&gt;प्रकाश। नवाचार। समाज।&lt;/strong&gt;&lt;/u&gt;।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;अंतर्राष्ट्रीय प्रकाश दिवस: 16 मई।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;452&quot; data-start=&quot;378&quot;&gt;
	&lt;p data-end=&quot;452&quot; data-start=&quot;380&quot;&gt;&lt;strong data-end=&quot;410&quot; data-start=&quot;380&quot;&gt;अंतर्राष्ट्रीय प्रकाश दिवस&lt;/strong&gt; हर साल &lt;strong data-end=&quot;438&quot; data-start=&quot;428&quot;&gt;16 मई&lt;/strong&gt; को मनाया जाता है।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;500&quot; data-start=&quot;453&quot;&gt;
	&lt;p data-end=&quot;500&quot; data-start=&quot;455&quot;&gt;इसे पहली बार &lt;strong data-end=&quot;497&quot; data-start=&quot;482&quot;&gt;16 मई 2018&lt;/strong&gt; को मनाया गया था।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;598&quot; data-start=&quot;501&quot;&gt;
	&lt;p data-end=&quot;598&quot; data-start=&quot;503&quot;&gt;यह दिन &lt;strong data-end=&quot;572&quot; data-start=&quot;521&quot;&gt;1960 में लेज़र के पहले सफल संचालन&lt;/strong&gt; को चिह्नित करता है, जो &lt;strong data-end=&quot;595&quot; data-start=&quot;576&quot;&gt;थियोडोर मैमन&lt;/strong&gt; द्वारा किया गया था।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;718&quot; data-start=&quot;599&quot;&gt;
	&lt;p data-end=&quot;718&quot; data-start=&quot;601&quot;&gt;यह दिन दिखाता है कि कैसे &lt;strong data-end=&quot;657&quot; data-start=&quot;619&quot;&gt;प्रकाश और प्रकाश-आधारित प्रौद्योगिकियाँ&lt;/strong&gt; विज्ञान, संस्कृति, कला, शिक्षा और विकास में मदद करती हैं।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;769&quot; data-start=&quot;719&quot;&gt;
	&lt;p data-end=&quot;769&quot; data-start=&quot;721&quot;&gt;इसका विषय &lt;strong data-end=&quot;767&quot; data-start=&quot;734&quot;&gt;&amp;quot;प्रकाश। नवाचार। समाज।&amp;quot;&lt;/strong&gt; है।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;877&quot; data-start=&quot;770&quot;&gt;
	&lt;p data-end=&quot;877&quot; data-start=&quot;772&quot;&gt;&lt;strong data-end=&quot;783&quot; data-start=&quot;775&quot;&gt;2015&lt;/strong&gt; में, &lt;strong data-end=&quot;820&quot; data-start=&quot;789&quot;&gt;अंतर्राष्ट्रीय प्रकाश वर्ष&lt;/strong&gt; ने हमारे जीवन में प्रकाश की भूमिका के बारे में जागरूकता बढ़ाई।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;968&quot; data-start=&quot;878&quot;&gt;
	&lt;p data-end=&quot;968&quot; data-start=&quot;880&quot;&gt;इस उत्सव से लोगों को यह समझने में मदद मिलती है कि कैसे प्रकाश &lt;strong data-end=&quot;967&quot; data-start=&quot;930&quot;&gt;जीवन को बेहतर बनाता है और प्रगति को बढ़ावा देता है&lt;/strong&gt;।&lt;/p&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;Sarnath&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Lord Buddha gave his first sermon at Sarnath&lt;/strong&gt;&lt;/u&gt;.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Gautam Buddha&lt;/strong&gt;:

	&lt;ul&gt;
		&lt;li&gt;His real name was&amp;nbsp;&lt;strong&gt;Siddharth&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;At the age of 29, he renounced home, this was his Mahabhiniskramana.&lt;/li&gt;
		&lt;li&gt;At the age of 35, under a&amp;nbsp;&lt;strong&gt;peepal tree at Uruvella (Bodh Gaya)&lt;/strong&gt;&amp;nbsp;on the bank of river&amp;nbsp;&lt;strong&gt;Niranjana&lt;/strong&gt;, he attained&amp;nbsp;&lt;strong&gt;&lt;em&gt;Nirvana&amp;nbsp;&lt;/em&gt;&lt;/strong&gt;after 49 days of&amp;nbsp;continuous meditation&amp;nbsp;he got fully&amp;nbsp;enlightened (Buddha or Tathagat).&lt;/li&gt;
		&lt;li&gt;He delivered his&lt;strong&gt;&amp;nbsp;first sermon at Sarnath&amp;nbsp;&lt;/strong&gt;to his five&amp;nbsp;disciples.
		&lt;ul&gt;
			&lt;li&gt;This is known as&lt;strong&gt;&lt;em&gt;&amp;nbsp;Dharmachaka Pravartana&lt;/em&gt;&lt;/strong&gt;&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;He died&amp;nbsp;in 483 BC at&amp;nbsp;&lt;strong&gt;Kushinagar&lt;/strong&gt;.&amp;nbsp;
		&lt;ul&gt;
			&lt;li&gt;This is known as&amp;nbsp;&lt;strong&gt;&lt;em&gt;Mahaparinirvana&lt;/em&gt;&lt;/strong&gt;.&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Vaishali &lt;/strong&gt;was the capital of&amp;nbsp;&lt;strong&gt;Vrijji mahajanapada.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Magadh &lt;/strong&gt;was the capital of the &lt;strong&gt;Maurya Dynasty.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर&amp;nbsp;&lt;u&gt;&lt;strong&gt;सारनाथ&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;भगवान बुद्ध ने &lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सारनाथ में&amp;nbsp;&lt;/span&gt;&lt;strong&gt;अपना पहला उपदेश दिया था।&lt;/strong&gt;&lt;/u&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;गौतम बुद्ध&lt;/strong&gt;:

	&lt;ul&gt;
		&lt;li&gt;उनका असली नाम &lt;strong&gt;सिद्धार्थ&lt;/strong&gt; था।&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;&quot;&gt;उन्होंने&amp;nbsp;&lt;/span&gt;29 वर्ष की आयु में घर त्याग दिया। इस घटना को&amp;nbsp;महाभिनिष्क्रमण कहा जाता है।
		&lt;ul&gt;
			&lt;li&gt;&lt;strong&gt;निरंजना &lt;/strong&gt;नदी के तट पर &lt;strong&gt;उरुवेला (बोधगया) में एक पीपल&lt;/strong&gt; के पेड़ के नीचे 49 दिनों के निरंतर ध्यान के बाद&lt;em&gt;&lt;strong&gt; &lt;/strong&gt;&lt;/em&gt;35 वर्ष की आयु में उन्हें&amp;nbsp;&lt;em&gt;&lt;strong&gt;निर्वाण &lt;/strong&gt;&lt;/em&gt;प्राप्त हुआ, जिसके बाद वह बुद्ध और तथागत कहलाए।&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;उन्होंने अपना &lt;strong&gt;पहला उपदेश सारनाथ&lt;/strong&gt; में अपने पांच शिष्यों को दिया।
		&lt;ul&gt;
			&lt;li&gt;इसे &lt;em&gt;&lt;strong&gt;धर्मचक्रप्रवर्तन&lt;/strong&gt;&lt;/em&gt; के नाम से जाना जाता है।&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;उनकी मृत्यु 483 ईसा पूर्व में &lt;strong&gt;कुशीनगर&lt;/strong&gt; में हुई।&amp;nbsp;
		&lt;ul&gt;
			&lt;li&gt;इसे &lt;em&gt;&lt;strong&gt;महापरिनिर्वाण&lt;/strong&gt;&lt;/em&gt; के नाम से जाना जाता है।&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;वज्जि&amp;nbsp;&lt;/strong&gt;&lt;strong&gt;महाजनपद&lt;/strong&gt; की राजधानी &lt;span style=&quot;font-weight: 700; &quot;&gt;वैशाली&amp;nbsp;&lt;/span&gt;थी।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;मौर्य राजवंश&lt;/strong&gt; की राजधानी &lt;span style=&quot;font-weight: 700; &quot;&gt;मगध&amp;nbsp;&lt;/span&gt;थी।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Adrien Brody (Best Actor), Jon M. Chu (Best Director).&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Adrien Brody won Best Actor for his performance in The Brutalist, while Jon M. Chu won Best Director for Wicked at the 2025 Critics Choice Awards.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Adrien Brody w&lt;/strong&gt;as recognized for his performance in &lt;strong&gt;The Brutalist, securing the Best Actor award.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Jon M. Chu&amp;rsquo;s surprise win for Best Director (Wicked) &lt;/strong&gt;was met with loud applause, as he was not nominated for an Oscar.&lt;/li&gt;
	&lt;li&gt;Other notable winners include &lt;strong&gt;Demi Moore (The Substance, Best Actress)&lt;/strong&gt; and&lt;strong&gt; Zoe Salda&amp;ntilde;a (Emilia P&amp;eacute;rez, Best Supporting Actress).&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;The Critics Choice Awards also honored television, with &lt;strong&gt;Shogun winning Best Drama Series.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Other Major Film Awards:&lt;/span&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Best Picture:&lt;/span&gt;&lt;/u&gt; Anora&lt;/li&gt;
		&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Best Actress:&lt;/span&gt;&lt;/u&gt; Demi Moore (The Substance)&lt;/li&gt;
		&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Best Supporting Actor:&lt;/span&gt;&lt;/u&gt; Kieran Culkin (A Real Pain)&lt;/li&gt;
		&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Best Supporting Actress:&lt;/span&gt;&lt;/u&gt; Zoe Salda&amp;ntilde;a (Emilia P&amp;eacute;rez)&lt;/li&gt;
		&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Best Comedy:&lt;/span&gt;&lt;/u&gt; A Real Pain &amp;amp; Deadpool &amp;amp; Wolverine (tie)&lt;/li&gt;
		&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Best Adapted Screenplay:&lt;/span&gt;&lt;/u&gt; Conclave&lt;/li&gt;
		&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Best Original Screenplay:&lt;/span&gt;&lt;/u&gt; The Substance&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;एड्रियन ब्रॉडी (सर्वश्रेष्ठ अभिनेता), जॉन एम. चू (सर्वश्रेष्ठ निर्देशक) है।&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;2025 के क्रिटिक्स चॉइस अवॉर्ड्स में एड्रियन ब्रॉडी ने द ब्रूटालिस्ट में अपने प्रदर्शन के लिए सर्वश्रेष्ठ अभिनेता का पुरस्कार जीता, जबकि जॉन एम. चू ने विकेड के लिए सर्वश्रेष्ठ निर्देशक का पुरस्कार जीता।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;एड्रियन ब्रॉडी को द ब्रूटालिस्ट में उनके प्रदर्शन के लिए पहचाना गया, जिससे उन्हें सर्वश्रेष्ठ अभिनेता का पुरस्कार मिला।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;सर्वश्रेष्ठ निर्देशक (विकेड) के लिए जॉन एम. चू की आश्चर्यजनक जीत&lt;/strong&gt; को जोरदार तालियों की गड़गड़ाहट के साथ स्वीकार किया गया, क्योंकि उन्हें ऑस्कर के लिए नामांकित नहीं किया गया था।&lt;/li&gt;
	&lt;li&gt;अन्य उल्लेखनीय विजेताओं में &lt;strong&gt;डेमी मूर (द सब्सटांस, सर्वश्रेष्ठ अभिनेत्री)&lt;/strong&gt; और &lt;strong&gt;ज़ो साल्डाना (एमिलिया पेरेज़, सर्वश्रेष्ठ सहायक अभिनेत्री) शामिल हैं।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;क्रिटिक्स चॉइस अवॉर्ड्स ने टेलीविजन को भी सम्मानित किया, जिसमें &lt;strong&gt;शोगुन ने सर्वश्रेष्ठ ड्रामा सीरीज़ जीती।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;अन्य प्रमुख फिल्म पुरस्कार:&lt;/span&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;सर्वश्रेष्ठ चित्र:&lt;/span&gt;&lt;/u&gt; अनोरा&lt;/li&gt;
		&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;सर्वश्रेष्ठ अभिनेत्री:&lt;/span&gt;&lt;/u&gt; डेमी मूर (द सब्सटांस)&lt;/li&gt;
		&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;सर्वश्रेष्ठ सहायक अभिनेता:&lt;/span&gt;&lt;/u&gt; कीरन कल्किन (ए रियल पेन)&lt;/li&gt;
		&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;सर्वश्रेष्ठ सहायक अभिनेत्री:&lt;/span&gt;&lt;/u&gt; ज़ो साल्डाना (एमिलिया पेरेज़)&lt;/li&gt;
		&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;सर्वश्रेष्ठ कॉमेडी:&lt;/span&gt;&lt;/u&gt; ए रियल पेन और डेडपूल और वूल्वरिन (टाई)&lt;/li&gt;
		&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;सर्वश्रेष्ठ रूपांतरित पटकथा:&lt;/span&gt;&lt;/u&gt; कॉन्क्लेव&lt;/li&gt;
		&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;सर्वश्रेष्ठ मूल पटकथा:&lt;/span&gt;&lt;/u&gt; द सब्सटांस&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;color:(33, 37, 41);&quot;&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Bangladesh.&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul style=&quot;color:(33, 37, 41);&quot;&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Bangladesh&lt;/span&gt;&lt;/u&gt;&amp;nbsp;is a country in South Asia.

	&lt;ul&gt;
		&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;People&amp;#39;s Republic of Bangladesh&lt;/span&gt;&amp;nbsp;is the official name of Bangladesh.&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Dhaka&lt;/span&gt;&amp;nbsp;is the capital of Bangladesh.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;Bangladesh shares land borders with:
	&lt;ul&gt;
		&lt;li&gt;India to the west, north, and east.&lt;/li&gt;
		&lt;li&gt;Myanmar to the southeast.&lt;/li&gt;
		&lt;li&gt;Bay of Bengal to the south.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color:(33, 37, 41);&quot;&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Bangladesh&lt;/span&gt;&lt;/u&gt;&amp;nbsp;shares the longest border with India.&lt;/li&gt;
	&lt;li&gt;Bangladesh&amp;nbsp;shares a&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;4,096-kilometre-long&amp;nbsp;&lt;/span&gt;(2,545 mi) international border with India.&lt;/li&gt;
	&lt;li&gt;Bangladesh&amp;ndash;India border is the&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;fifth-longest land border&lt;/span&gt;&amp;nbsp;in the world.&lt;/li&gt;
	&lt;li&gt;Five Indian states that share their border with Bangladesh:
	&lt;ol&gt;
		&lt;li&gt;Assam.&lt;/li&gt;
		&lt;li&gt;Tripura.&lt;/li&gt;
		&lt;li&gt;Mizoram.&lt;/li&gt;
		&lt;li&gt;Meghalaya.&lt;/li&gt;
		&lt;li&gt;West Bengal.&lt;/li&gt;
	&lt;/ol&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;color:(33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color:(33, 37, 41);&quot;&gt;
	&lt;li&gt;The countries sharing the land borders with India are:
	&lt;ol&gt;
		&lt;li&gt;China.&lt;/li&gt;
		&lt;li&gt;Bhutan.&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Nepal.&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Pakistan.&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;Afghanistan.&lt;/li&gt;
		&lt;li&gt;Bangladesh.&lt;/li&gt;
		&lt;li&gt;Myanmar.&lt;/li&gt;
	&lt;/ol&gt;

	&lt;ul&gt;
		&lt;li&gt;India shares the least land boundary with&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Afghanistan.&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;China&lt;/span&gt;&amp;nbsp;is the largest country that shares land borders with India.&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Bhutan&lt;/span&gt;&amp;nbsp;is the smallest country that shares land borders with India.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p style=&quot;color:(33, 37, 41);&quot;&gt;सही उत्तर&amp;nbsp;&lt;u&gt;&lt;strong&gt;बांग्लादेश&amp;nbsp;&lt;/strong&gt;&lt;/u&gt;है।&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul style=&quot;color:(33, 37, 41);&quot;&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;बांग्लादेश&lt;/strong&gt;&lt;/u&gt; दक्षिण एशिया का एक देश है।

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;पीपुल्स रिपब्लिक ऑफ बांग्लादेश&lt;/strong&gt; बांग्लादेश का आधिकारिक नाम है।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;ढाका&lt;/strong&gt; बांग्लादेश की राजधानी है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;बांग्लादेश निम्नलिखित के साथ भूमि सीमा साझा करता है:
	&lt;ul&gt;
		&lt;li&gt;पश्चिम, उत्तर और पूर्व में भारत&lt;/li&gt;
		&lt;li&gt;दक्षिण पूर्व में म्यांमार&lt;/li&gt;
		&lt;li&gt;दक्षिण में बंगाल की खाड़ी&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color:(33, 37, 41);&quot;&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;बांग्लादेश&lt;/strong&gt;&lt;/u&gt; भारत के साथ सबसे लंबी सीमा साझा करता है।&lt;/li&gt;
	&lt;li&gt;बांग्लादेश भारत के साथ &lt;strong&gt;4,096 किलोमीटर लंबी &lt;/strong&gt;(2,545 मील) अंतरराष्ट्रीय सीमा साझा करता है।&lt;/li&gt;
	&lt;li&gt;बांग्लादेश-भारत सीमा दुनिया की &lt;strong&gt;पांचवीं सबसे लंबी भूमि सीमा&lt;/strong&gt; है।&lt;/li&gt;
	&lt;li&gt;पांच भारतीय राज्य जो बांग्लादेश के साथ अपनी सीमा साझा करते हैं:
	&lt;ol&gt;
		&lt;li&gt;असम&lt;/li&gt;
		&lt;li&gt;त्रिपुरा&lt;/li&gt;
		&lt;li&gt;मिजोरम&lt;/li&gt;
		&lt;li&gt;मेघालय&lt;/li&gt;
		&lt;li&gt;पश्चिम बंगाल&lt;/li&gt;
	&lt;/ol&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;color:(33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color:(33, 37, 41);&quot;&gt;
	&lt;li&gt;भारत के साथ भूमि सीमा साझा करने वाले देश हैं:
	&lt;ol&gt;
		&lt;li&gt;चीन&lt;/li&gt;
		&lt;li&gt;भूटान&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;नेपाल&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;पाकिस्तान&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;अफगानिस्तान&lt;/li&gt;
		&lt;li&gt;बांग्लादेश&lt;/li&gt;
		&lt;li&gt;म्यांमार&lt;/li&gt;
	&lt;/ol&gt;

	&lt;ul&gt;
		&lt;li&gt;भारत &lt;strong&gt;अफगानिस्तान&lt;/strong&gt; के साथ सबसे कम भूमि सीमा साझा करता है।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;चीन&lt;/strong&gt; भारत के साथ भूमि सीमा साझा करने वाला सबसे बड़ा देश है।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;भूटान&lt;/strong&gt; भारत के साथ भूमि सीमा साझा करने वाला सबसे छोटा देश है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span&gt;&lt;u&gt;&lt;strong&gt;Mahanadi river&lt;/strong&gt;&lt;/u&gt;.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;span style=&quot;font-family: var(--bs-body-font-family); font-size: var(--bs-body-font-size); font-weight: var(--bs-body-font-weight); text-align: var(--bs-body-text-align);&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;River Mahanadi originates&amp;nbsp;&lt;/span&gt;from&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Sihawa Mountain&lt;/span&gt;&amp;nbsp;near a village in&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Raipur&lt;/span&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;, Chhattisgarh.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;The&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;nbsp;Mahanadi River system&lt;/span&gt;&amp;nbsp;is the&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;third largest in peninsular India&lt;/span&gt;&amp;nbsp;after Godavari and Krishna, and the&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;largest river in Odisha state&lt;/span&gt;.
	&lt;ul&gt;
		&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Mahanadi (&amp;ldquo;Great River&amp;rdquo;)&amp;nbsp;&lt;/span&gt;follows a&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;total course of 560 miles (900 km)&lt;/span&gt;&amp;nbsp;and has an&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;estimated drainage area of 51,000 square miles (132,100 square km)&lt;/span&gt;.&lt;/li&gt;
		&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;catchment area&amp;nbsp;&lt;/span&gt;of the river extends to&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Chhattisgarh, Madhya Pradesh, Odisha, Jharkhand, and Maharashtra&lt;/span&gt;.&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Tributaries&lt;/span&gt;
		&lt;ul&gt;
			&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Seonath&lt;/span&gt;,&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Hasdeo&lt;/span&gt;,&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Mand&lt;/span&gt;, and&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Ib&lt;/span&gt;&amp;nbsp;join Mahanadi from the&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;left&amp;nbsp;&lt;/span&gt;whereas,&lt;/li&gt;
			&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Ong&lt;/span&gt;,&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Tel&lt;/span&gt;, and&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Jonk&lt;/span&gt;&amp;nbsp;join it from&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;nbsp;the right&lt;/span&gt;.&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;At Sambalpur, the&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;nbsp;Hirakud Dam&lt;/span&gt;&amp;nbsp;on the river&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;(the longest dam in India)&lt;/span&gt;&amp;nbsp;has formed a&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;man-made lake&amp;nbsp;&lt;/span&gt;35 miles (55 km) long; the dam has several hydroelectric generators.&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;It enters the&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Odisha plains near Cuttack&amp;nbsp;&lt;/span&gt;and&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;nbsp;enters the Bay of Bengal at False Point&amp;nbsp;&lt;/span&gt;by several channels.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Malwa plateau&lt;/strong&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;  text-align: justify;&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&lt;u&gt;​&lt;/u&gt;&lt;/span&gt;&lt;/span&gt;Indian plateau region known as the Malwa Plateau. It is bordered to the&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;north by the Madhya Bharat Plateau&lt;/span&gt;&amp;nbsp;and Bundelkhand Upland,&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;to the east and south by the Vindhya Range, and to the west by the Gujarat Plains&lt;/span&gt;. The plateau, which is of volcanic origin,&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;spans southeast Rajasthan state and central Madhya Pradesh state. The Sanskrit word malav is where the name Malwa comes from (part of the abode of Laksmi [goddess of wealth]).&lt;/span&gt;&amp;nbsp;The Maurya, Gupta, and Paramara empires alternately dominated the plateau; during this time, numerous Buddhist temples and monuments (such as the stupas at Sanchi), known for their architecture and sculpture, were also constructed. In 1390 CE, the Muslims took control of the plateau, which then belonged to the Maratha empire. It was given to the British in 1817.&lt;/li&gt;
		&lt;li&gt;The Malwa Plateau has an elevation range of 500 to 600 metres (about 1,650 to 2,000 feet). Sandstone hills and solitary mesas, as well as remnants of old lava flows, may be seen scattered throughout the plateau. The&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Mahi River drains the western portion of the area&lt;/span&gt;, the&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Chambal River the middle, and the Betwa River and the headwaters of the Dhasan and Ken rivers the eastern portion. Additionally, there are the Parbati, Sipra, Gambhir, and Choti Kali Sindh rivers, all of whose valleys are bordered by terraced hills. Savanna-style vegetation is present, with sporadic teak and sal (Shorea robusta) woods.&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर&amp;nbsp;&lt;u&gt;&lt;strong&gt;महानदी नदी&lt;/strong&gt;&lt;/u&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot; &quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;span style=&quot;font-family: var(--bs-body-font-family); font-size: var(--bs-body-font-size); font-weight: var(--bs-body-font-weight); text-align: var(--bs-body-text-align);&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;महानदी नदी छत्तीसगढ़ के रायपुर&lt;/strong&gt; में एक गांव के निकट &lt;strong&gt;सिहावा पर्वत&lt;/strong&gt; से निकलती है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;महानदी नदी प्रणाली&lt;/strong&gt; &lt;strong&gt;प्रायद्वीपीय भारत&lt;/strong&gt; में गोदावरी और कृष्णा के बाद &lt;strong&gt;तीसरी सबसे बड़ी&lt;/strong&gt; और &lt;strong&gt;ओडिशा राज्य की सबसे बड़ी नदी&lt;/strong&gt; है।
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;महानदी (&amp;quot;महान नदी&amp;quot;)&lt;/strong&gt; &lt;strong&gt;560 मील (900 किमी) के कुल मार्ग&lt;/strong&gt; का अनुसरण करती है और इसका &lt;strong&gt;अनुमानित जल निकासी क्षेत्र 51,000 वर्ग मील (132,100 वर्ग किमी)&lt;/strong&gt; है।&lt;/li&gt;
		&lt;li&gt;नदी का &lt;strong&gt;जलग्रहण क्षेत्र छत्तीसगढ़, मध्य प्रदेश, उड़ीसा, झारखंड और महाराष्ट्र&lt;/strong&gt; तक फैला है।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;सहायक नदियाँ&lt;/strong&gt;
		&lt;ul&gt;
			&lt;li&gt;&lt;strong&gt;शिवनाथ, हसदेव, मांड&lt;/strong&gt; और &lt;strong&gt;इब&lt;/strong&gt; महानदी में &lt;strong&gt;बाईं&lt;/strong&gt; ओर से जुड़ते हैं जबकि,&lt;/li&gt;
			&lt;li&gt;&lt;strong&gt;ओंग, टेल&lt;/strong&gt; और &lt;strong&gt;जोंक&lt;/strong&gt; इसमें &lt;strong&gt;दाईं&lt;/strong&gt; ओर से जुड़ते हैं।&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;संबलपुर में, नदी पर &lt;strong&gt;हीराकुंड बांध (भारत में सबसे लंबा बांध)&lt;/strong&gt; ने 35 मील (55 किमी) लंबी &lt;strong&gt;मानव निर्मित झील&lt;/strong&gt; बनाई है; बांध में कई पनबिजली&amp;nbsp;जनित्र हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;यह &lt;strong&gt;कटक के निकट ओडिशा के मैदानों&lt;/strong&gt; में प्रवेश करती है और कई चैनलों द्वारा &lt;strong&gt;फाल्स प्वाइंट पर बंगाल की खाड़ी में प्रवेश&lt;/strong&gt; करती है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;मालवा का पठार&lt;/strong&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;भारतीय पठारी क्षेत्र को मालवा पठार के नाम से जाना जाता है। यह &lt;strong&gt;उत्तर में मध्य भारत पठार&lt;/strong&gt; और बुंदेलखंड उच्चभूमि, &lt;strong&gt;पूर्व और दक्षिण में विंध्य शृंखला और पश्चिम में गुजरात के मैदानों&lt;/strong&gt; से घिरा है। पठार, जहाँ ज्वालामुखी उत्पत्ति होती है, &lt;strong&gt;दक्षिण-पूर्व राजस्थान राज्य और मध्य मध्य प्रदेश राज्य तक फैला है।&amp;nbsp;संस्कृत शब्द मालव से मालवा नाम आया है (लक्ष्मी [धन की देवी] के निवास का भाग)।&lt;/strong&gt; मौर्य, गुप्त और परमार साम्राज्य बारी-बारी से पठार पर हावी रहे; इस समय के दौरान, कई बौद्ध मंदिरों और स्मारकों (जैसे सांची में स्तूप), जो उनकी वास्तुकला और मूर्तिकला के लिए जाने जाते हैं, का भी निर्माण किया गया था। 1390 CE में, मुसलमानों ने पठार पर अधिकार कर लिया, जो तब मराठा साम्राज्य का था। यह 1817 में अंग्रेजों को दे दिया गया था।&lt;/li&gt;
		&lt;li&gt;मालवा पठार की ऊँचाई सीमा 500 से 600 मीटर (लगभग 1,650 से 2,000 फीट) है। बलुआ पत्थर की पहाड़ियाँ और एकांत मेसा, साथ ही पुराने लावा प्रवाह के अवशेष पूरे पठार में बिखरे देखे जा सकते हैं। &lt;strong&gt;माही नदी क्षेत्र के पश्चिमी भाग, चंबल नदी मध्य, और बेतवा नदी और धसान और केन नदियों के ऊपरी भाग को पूर्वी भाग में प्रवाहित करती है।&lt;/strong&gt; &lt;strong&gt;इसके अतिरिक्त, पारबती, शिप्रा, गंभीर, और छोटी काली सिंध नदियाँ हैं, जिनकी सभी घाटियाँ सोपानी पहाड़ियों से घिरी हैं। छिटपुट सागौन और साल (शोरिया रोबस्टा) की लकड़ियों के साथ सवाना-शैली की वनस्पति मौजूद है।&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;2017&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Manipur Chief Minister N Biren Singh resigned&lt;/strong&gt; nearly two years after ethnic violence erupted in the state.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;He &lt;strong&gt;submitted his resignation to Governor Ajay Kumar Bhalla&lt;/strong&gt; amid talks of a no-confidence motion and floor test by Congress.&lt;/li&gt;
	&lt;li&gt;Singh &lt;strong&gt;expressed gratitude to the central government&lt;/strong&gt; for its interventions and developmental work in his resignation letter.&lt;/li&gt;
	&lt;li&gt;His resignation &lt;strong&gt;followed a meeting with Union Home Minister Amit Shah&lt;/strong&gt; in New Delhi.&lt;/li&gt;
	&lt;li&gt;The BJP holds &lt;strong&gt;32 seats in the 60-member Manipur Assembly&lt;/strong&gt;, with support from &lt;strong&gt;five NPF MLAs and six JD(U) MLAs&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;The &lt;strong&gt;National People&amp;#39;s Party (NPP) withdrew support&lt;/strong&gt;, but BJP still had a majority.&lt;/li&gt;
	&lt;li&gt;Speculation arose that &lt;strong&gt;MLAs seeking a leadership change&lt;/strong&gt; might defy the party whip in a floor test.&lt;/li&gt;
	&lt;li&gt;The &lt;strong&gt;Congress holds five seats&lt;/strong&gt;, while the opposition NPP has &lt;strong&gt;seven MLAs&lt;/strong&gt;, along with &lt;strong&gt;three Independents and two Kuki People&amp;#39;s Alliance MLAs&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Manipur&amp;#39;s 7th Assembly session was scheduled for February 10&lt;/strong&gt;, just a day after Singh&amp;#39;s resignation.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Ethnic violence since May 2023&lt;/strong&gt; has led to &lt;strong&gt;over 250 deaths and thousands displaced&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;The BJP government &lt;strong&gt;faced scrutiny for its handling of the crisis&lt;/strong&gt; and peace restoration efforts.&lt;/li&gt;
	&lt;li&gt;A day before resigning, Singh stated that his government &lt;strong&gt;was making all efforts to restore peace and unity&lt;/strong&gt; in the state.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;2017&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;मणिपुर के मुख्यमंत्री एन. बीरेन सिंह ने&lt;/strong&gt; राज्य में जातीय हिंसा भड़कने के लगभग दो साल बाद इस्तीफा दे दिया।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;कांग्रेस द्वारा अविश्वास प्रस्ताव और फ्लोर टेस्ट की बातचीत के बीच उन्होंने &lt;strong&gt;राज्यपाल अजय कुमार भल्ला को अपना इस्तीफा सौंप दिया&lt;/strong&gt;।&lt;/li&gt;
	&lt;li&gt;सिंह ने अपने इस्तीफे के पत्र में &lt;strong&gt;केंद्र सरकार के हस्तक्षेप और विकास कार्यों के लिए आभार व्यक्त किया&lt;/strong&gt;।&lt;/li&gt;
	&lt;li&gt;नई दिल्ली में &lt;strong&gt;केंद्रीय गृह मंत्री अमित शाह के साथ मुलाकात के बाद&lt;/strong&gt; उनका इस्तीफा आया।&lt;/li&gt;
	&lt;li&gt;भाजपा के पास &lt;strong&gt;60 सदस्यीय मणिपुर विधानसभा में 32 सीटें हैं&lt;/strong&gt;, जिसमें &lt;strong&gt;पाँच एनपीएफ विधायकों और छह जद (&lt;/strong&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;U&lt;/span&gt;&lt;strong&gt;) विधायकों का समर्थन&lt;/strong&gt; है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;नेशनल पीपुल्स पार्टी (&lt;/strong&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;NPP&lt;/span&gt;&lt;strong&gt;) ने समर्थन वापस ले लिया&lt;/strong&gt;, लेकिन भाजपा के पास अभी भी बहुमत था।&lt;/li&gt;
	&lt;li&gt;ऐसी अटकलें लगाई गईं कि &lt;strong&gt;नेतृत्व परिवर्तन चाहने वाले विधायक&lt;/strong&gt; फ्लोर टेस्ट में पार्टी व्हिप को चुनौती दे सकते हैं।&lt;/li&gt;
	&lt;li&gt;कांग्रेस के पास &lt;strong&gt;पाँच सीटें हैं&lt;/strong&gt;, जबकि विपक्षी &lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;NPP &lt;/span&gt;के पास &lt;strong&gt;सात विधायक हैं&lt;/strong&gt;, साथ ही &lt;strong&gt;तीन निर्दलीय और दो कुकी पीपुल्स एलायंस विधायक हैं&lt;/strong&gt;।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;मणिपुर का 7वां विधानसभा सत्र 10 फरवरी के लिए निर्धारित था&lt;/strong&gt;, सिंह के इस्तीफे के ठीक एक दिन बाद।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;मई 2023 से जातीय हिंसा&lt;/strong&gt; से &lt;strong&gt;250 से अधिक मौतें और हजारों लोग विस्थापित हुए हैं।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;भाजपा सरकार को &lt;strong&gt;संकट को संभालने और शांति बहाली के प्रयासों के लिए जांच का सामना करना पड़ा&lt;/strong&gt;।&lt;/li&gt;
	&lt;li&gt;इस्तीफा देने से एक दिन पहले, सिंह ने कहा था कि उनकी सरकार राज्य में &lt;strong&gt;शांति और एकता बहाल करने के लिए हर संभव प्रयास कर रही है&lt;/strong&gt;।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;&lt;u&gt;CONCEPT:&lt;/u&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Importance of Carbon: &lt;/strong&gt;Carbon is found in various forms on the &lt;strong&gt;Earth&lt;/strong&gt;.

	&lt;ul&gt;
		&lt;li&gt;It occurs in the &lt;strong&gt;elemental &lt;/strong&gt;form as &lt;strong&gt;diamonds&lt;/strong&gt; and &lt;strong&gt;graphite&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;In the &lt;strong&gt;combined state&lt;/strong&gt;, it is found as &lt;strong&gt;carbon dioxide&lt;/strong&gt; in the &lt;strong&gt;atmosphere&lt;/strong&gt;, as &lt;strong&gt;carbonate &lt;/strong&gt;and &lt;b&gt;hydro carbonate&lt;/b&gt;&amp;nbsp;&lt;strong&gt;salts &lt;/strong&gt;in various minerals, while all life-forms are based on&lt;strong&gt; carbon-containing molecules&lt;/strong&gt; like &lt;strong&gt;proteins, carbohydrates, fats&amp;nbsp;nucleic acids&lt;/strong&gt; and &lt;strong&gt;vitamins&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;The &lt;strong&gt;endoskeletons &lt;/strong&gt;and &lt;strong&gt;exoskeletons&lt;/strong&gt; of various &lt;strong&gt;animals&lt;/strong&gt; are also formed from &lt;strong&gt;carbonate salts&lt;/strong&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;Carbon cycle:&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Carbon is incorporated into &lt;strong&gt;life-forms&lt;/strong&gt; through the basic process of&lt;strong&gt; photosynthesis&lt;/strong&gt; which is performed in the presence of &lt;strong&gt;Sunlight&lt;/strong&gt; by all life-forms that contain &lt;strong&gt;chlorophyll&lt;/strong&gt;. This process &lt;strong&gt;converts carbon dioxide from the atmosphere&lt;/strong&gt; or &lt;strong&gt;dissolved in water &lt;/strong&gt;into &lt;strong&gt;glucose molecules&lt;/strong&gt;. These glucose molecules are either &lt;strong&gt;converted &lt;/strong&gt;into other &lt;strong&gt;substances&lt;/strong&gt; or &lt;strong&gt;used to provide energy&lt;/strong&gt; for the &lt;strong&gt;synthesis &lt;/strong&gt;of other &lt;strong&gt;biologically important molecules&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;The &lt;strong&gt;utilisation of glucose&lt;/strong&gt; to &lt;strong&gt;provide energy&lt;/strong&gt; to living things involves the process of &lt;strong&gt;respiration &lt;/strong&gt;in which &lt;strong&gt;oxygen&lt;/strong&gt; may or may not be used to convert &lt;strong&gt;glucose back into carbon dioxide&lt;/strong&gt;. This &lt;strong&gt;carbon dioxide&lt;/strong&gt; then &lt;strong&gt;goes&lt;/strong&gt; &lt;strong&gt;back into the atmosphere&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;Another process that&amp;nbsp;adds to the &lt;strong&gt;carbon dioxide in the atmosphere &lt;/strong&gt;is the process of &lt;strong&gt;combustion&lt;/strong&gt; where &lt;strong&gt;fuels are burnt &lt;/strong&gt;to provide energy for various needs like &lt;strong&gt;heating, cooking, transportation&lt;/strong&gt; and &lt;strong&gt;industrial processes&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;In fact, the &lt;strong&gt;percentage of carbon dioxide &lt;/strong&gt;in the &lt;strong&gt;atmosphere&lt;/strong&gt; is said to have &lt;strong&gt;doubled &lt;/strong&gt;since the &lt;strong&gt;industrial revolution&lt;/strong&gt; when &lt;strong&gt;human beings &lt;/strong&gt;started &lt;strong&gt;burning fossil fuels&lt;/strong&gt; on a very large scale.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Carbon&lt;/strong&gt;, like water, is thus &lt;strong&gt;cycled &lt;/strong&gt;repeatedly through different forms by the &lt;strong&gt;various physica&lt;/strong&gt;l and &lt;strong&gt;biological activities&lt;/strong&gt;.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/20/09/F1_Utkarsha_Madhu_05.09.20_D1.png&quot; style=&quot;width: 453px; height: 329px;&quot; /&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;u&gt;EXPLANATION:&lt;/u&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Plants take the &lt;strong&gt;atmospheric carbon&amp;nbsp;dioxide&lt;/strong&gt; in presence of &lt;strong&gt;Sunlight &lt;/strong&gt;and do &lt;strong&gt;photosynthesis&lt;/strong&gt; and produce &lt;strong&gt;glucose&lt;/strong&gt; and oxygen as a byproduct.&lt;/li&gt;
	&lt;li&gt;The plants are &lt;strong&gt;not able to &lt;/strong&gt;take &lt;strong&gt;carbon directly&lt;/strong&gt; from&amp;nbsp;&lt;strong&gt;carbonate rocks&lt;/strong&gt; and &lt;strong&gt;fossil fuels&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;In order to &lt;strong&gt;use&lt;/strong&gt; the &lt;strong&gt;carbon by plants&lt;/strong&gt;, it is necessary that carbon is taken as&amp;nbsp;&lt;strong&gt;atmospheric carbon&amp;nbsp;dioxide&lt;/strong&gt;.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;&lt;strong&gt;&lt;u&gt;सिद्धांत:&lt;/u&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;कार्बन का महत्व:&lt;/strong&gt; कार्बन &lt;strong&gt;पृथ्वी&lt;/strong&gt; पर विभिन्न रूपों में पाया जाता है।

	&lt;ul&gt;
		&lt;li&gt;यह &lt;strong&gt;हीरे&lt;/strong&gt; और &lt;strong&gt;ग्रेफाइट के&lt;/strong&gt; रूप में &lt;strong&gt;मौलिक&lt;/strong&gt; रूप में होता है।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;संयुक्त अवस्था में&lt;/strong&gt;, यह &lt;strong&gt;वातावरण&lt;/strong&gt; में &lt;strong&gt;कार्बन डाइऑक्साइड&lt;/strong&gt;, विभिन्न खनिजों में &lt;strong&gt;कार्बोनेट&lt;/strong&gt; और &lt;b&gt;हाइड्रो कार्बोनेट&lt;/b&gt; &lt;strong&gt;लवण के&lt;/strong&gt; रूप में पाया जाता है, जबकि सभी जीवन-रूप &lt;strong&gt;प्रोटीन, कार्बोहाइड्रेट, वसा न्यूक्लिक एसिड&lt;/strong&gt; और &lt;strong&gt;विटामिन&lt;/strong&gt; जैसे &lt;strong&gt;कार्बन युक्त अणुओं&lt;/strong&gt; पर आधारित होते हैं।&lt;/li&gt;
		&lt;li&gt;विभिन्न &lt;strong&gt;जानवरों के&lt;/strong&gt; &lt;strong&gt;एंडोस्केलेटन&lt;/strong&gt; और &lt;strong&gt;एक्सोस्केलेटन&lt;/strong&gt; भी &lt;strong&gt;कार्बोनेट लवण&lt;/strong&gt; से बनते हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;कार्बन चक्र:&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;कार्बन को &lt;strong&gt;प्रकाश संश्लेषण&lt;/strong&gt; की मूल प्रक्रिया के माध्यम से &lt;strong&gt;जीवन-रूपों&lt;/strong&gt; में शामिल किया जाता &lt;strong&gt;है,&lt;/strong&gt; जो सभी जीवन-रूपों द्वारा &lt;strong&gt;क्लोरोफिल&lt;/strong&gt; युक्त &lt;strong&gt;सूर्य&lt;/strong&gt; के &lt;strong&gt;प्रकाश&lt;/strong&gt; की उपस्थिति में किया जाता &lt;strong&gt;है&lt;/strong&gt; । यह प्रक्रिया &lt;strong&gt;वातावरण से कार्बन डाइऑक्साइड को परिवर्तित करती है&lt;/strong&gt; या &lt;strong&gt;पानी&lt;/strong&gt; में &lt;strong&gt;ग्लूकोज के अणुओं&lt;/strong&gt; में &lt;strong&gt;घुल जाती है&lt;/strong&gt; । इन ग्लूकोज अणुओं को या तो अन्य &lt;strong&gt;पदार्थों&lt;/strong&gt; में &lt;strong&gt;परिवर्तित&lt;/strong&gt; किया &lt;strong&gt;जाता है&lt;/strong&gt; या अन्य &lt;strong&gt;जैविक रूप से महत्वपूर्ण अणुओं&lt;/strong&gt; के &lt;strong&gt;संश्लेषण&lt;/strong&gt; के लिए &lt;strong&gt;ऊर्जा प्रदान करने के लिए उपयोग किया जाता है&lt;/strong&gt;।&lt;/li&gt;
	&lt;li&gt;जीवित चीजों को &lt;strong&gt;ऊर्जा प्रदान&lt;/strong&gt; करने के &lt;strong&gt;लिए&lt;/strong&gt; &lt;strong&gt;ग्लूकोज के उपयोग में&lt;/strong&gt; &lt;strong&gt;श्वसन&lt;/strong&gt; की प्रक्रिया शामिल है जिसमें &lt;strong&gt;ऑक्सीजन&lt;/strong&gt; &lt;strong&gt;को कार्बन डाइऑक्साइड में वापस ग्लूकोज में&lt;/strong&gt; परिवर्तित करने के लिए &lt;strong&gt;ऑक्सीजन का&lt;/strong&gt; उपयोग किया जा सकता है या नहीं। यह &lt;strong&gt;कार्बन डाइऑक्साइड&lt;/strong&gt; फिर &lt;strong&gt;वायुमंडल में&lt;/strong&gt; &lt;strong&gt;चला जाता&lt;/strong&gt; &lt;strong&gt;है&lt;/strong&gt;।&lt;/li&gt;
	&lt;li&gt;एक अन्य प्रक्रिया जो &lt;strong&gt;वायुमंडल में कार्बन डाइऑक्साइड&lt;/strong&gt; को जोड़ती है, &lt;strong&gt;दहन&lt;/strong&gt; की प्रक्रिया है जहां &lt;strong&gt;हीटिंग, खाना पकाने, परिवहन&lt;/strong&gt; और &lt;strong&gt;औद्योगिक प्रक्रियाओं&lt;/strong&gt; जैसी विभिन्न आवश्यकताओं के लिए ऊर्जा प्रदान करने के लिए &lt;strong&gt;ईंधन जलाया&lt;/strong&gt; जाता &lt;strong&gt;है&lt;/strong&gt;।&lt;/li&gt;
	&lt;li&gt;वास्तव में, &lt;strong&gt;औद्योगिक क्रांति के&lt;/strong&gt; बाद से &lt;strong&gt;वातावरण&lt;/strong&gt; में &lt;strong&gt;कार्बन डाइऑक्साइड&lt;/strong&gt; का &lt;strong&gt;प्रतिशत&lt;/strong&gt; &lt;strong&gt;दोगुना हो&lt;/strong&gt; गया, जब &lt;strong&gt;मानव&lt;/strong&gt; ने बहुत बड़े पैमाने पर &lt;strong&gt;जीवाश्म ईंधन जलाना&lt;/strong&gt; शुरू किया।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;कार्बन&lt;/strong&gt;, पानी की तरह, &lt;strong&gt;विभिन्न भौतिक&lt;/strong&gt;&amp;nbsp;और &lt;strong&gt;जैविक गतिविधियों&lt;/strong&gt; द्वारा विभिन्न रूपों के माध्यम से बार-बार &lt;strong&gt;चक्रित&lt;/strong&gt; किया &lt;strong&gt;जाता है&lt;/strong&gt;।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/20/09/F1_Utkarsha_Madhu_05.09.20_D1.png&quot; style=&quot;width: 453px; height: 329px;&quot; /&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;u&gt;व्याख्या:&lt;/u&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;पौधे &lt;strong&gt;सूर्य&lt;/strong&gt; के &lt;strong&gt;प्रकाश की&lt;/strong&gt; उपस्थिति में &lt;strong&gt;वायुमंडलीय कार्बन डाइऑक्साइड&lt;/strong&gt; लेते हैं और &lt;strong&gt;प्रकाश संश्लेषण&lt;/strong&gt; करते हैं और एक उपोत्पाद के रूप में &lt;strong&gt;ग्लूकोज&lt;/strong&gt; और ऑक्सीजन का उत्पादन करते &lt;strong&gt;हैं&lt;/strong&gt; ।&lt;/li&gt;
	&lt;li&gt;पौधे &lt;strong&gt;कार्बोनेट चट्टानों&lt;/strong&gt; और &lt;strong&gt;जीवाश्म ईंधन&lt;/strong&gt; से &lt;strong&gt;सीधे कार्बन&lt;/strong&gt; लेने में &lt;strong&gt;सक्षम नहीं&lt;/strong&gt; हैं।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;पौधों द्वारा कार्बन&lt;/strong&gt; का &lt;strong&gt;उपयोग&lt;/strong&gt; करने के लिए, यह आवश्यक है कि कार्बन को &lt;strong&gt;वायुमंडलीय कार्बन डाइऑक्साइड &lt;/strong&gt;के रूप में लिया जाए।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;strong&gt;Option 3 &lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;list-style-type: disc;&quot;&gt;
	&lt;li&gt;Concerns have been raised about proposed &amp;ldquo;turtle trails&amp;rdquo; near mass nesting beaches of Olive Ridley turtles in Odisha, as anthropogenic disturbances can disrupt arribada events.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;list-style-type: disc;&quot;&gt;
	&lt;li&gt;Arribada refers to the phenomenon of mass nesting by sea turtles at specific beaches within a short, synchronized time window.&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Hence, Option C is correct.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;Offshore migration to pelagic waters is a general life-cycle behaviour of sea turtles and is not termed arribada.&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Hence, Option A is incorrect.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;Synchronized hatching linked to lunar cycles may occur in some reptiles but does not define arribada, which specifically denotes mass nesting.&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;nbsp;Hence, Option B is incorrect.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;Nearshore juvenile congregation following upwelling is an ecological aggregation pattern, not the nesting phenomenon termed arribada.&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Hence, Option D is incorrect.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;list-style-type: disc;&quot;&gt;
	&lt;li&gt;Olive Ridley turtles are listed as Vulnerable on the IUCN Red List and protected under Schedule I of the Wildlife (Protection) Act, 1972.&lt;/li&gt;
	&lt;li&gt;Major arribada sites in India include Gahirmatha and Rushikulya in Odisha.&lt;/li&gt;
	&lt;li&gt;Light pollution, beach construction and unregulated tourism disrupt nesting behaviour.&lt;/li&gt;
	&lt;li&gt;Nesting beaches fall within Coastal Regulation Zone (CRZ) norms notified under the Environment (Protection) Act, 1986.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर है &lt;strong&gt;विकल्प 3&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;समाचार में&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;list-style-type: disc;&quot;&gt;
	&lt;li&gt;ओडिशा में ओलिव रिडले कछुओं के सामूहिक घोंसले के शिकार तटों के पास प्रस्तावित &amp;quot;कछुआ ट्रेल्स&amp;quot; के बारे में चिंता जताई गई है, क्योंकि मानवजनित गड़बड़ी अरिबाडा की घटनाओं को बाधित कर सकती है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;मुख्य बिंदु&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;list-style-type: disc;&quot;&gt;
	&lt;li&gt;अरिबाडा से तात्पर्य एक छोटे, सिंक्रनाइज़ समय विंडो के भीतर विशिष्ट समुद्र तटों पर समुद्री कछुओं द्वारा सामूहिक घोंसले बनाने की घटना से है। &lt;strong&gt;इसलिए, विकल्प C सही है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;पलेजिक जल में अपतटीय प्रवास समुद्री कछुओं का एक सामान्य जीवन-चक्र व्यवहार है और इसे अरिबाडा नहीं कहा जाता है। &lt;strong&gt;इसलिए, विकल्प A गलत है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;चंद्र चक्रों से जुड़ी सिंक्रनाइज़ हैचिंग कुछ सरीसृपों में हो सकती है लेकिन अरिबाडा को परिभाषित नहीं करती है, जो विशेष रूप से सामूहिक घोंसले को दर्शाता है। &lt;strong&gt;इसलिए, विकल्प B गलत है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;ऊपर उठने के बाद किनारे के पास किशोरों का जमाव एक पारिस्थितिक एकत्रीकरण पैटर्न है, न कि घोंसले की घटना जिसे अरिबाडा कहा जाता है। &lt;strong&gt;इसलिए, विकल्प D गलत है।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;अतिरिक्त जानकारी&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;list-style-type: disc;&quot;&gt;
	&lt;li&gt;ओलिव रिडले कछुओं को IUCN रेड लिस्ट में असुरक्षित के रूप में सूचीबद्ध किया गया है और वन्यजीव (संरक्षण) अधिनियम, 1972 की अनुसूची I के तहत संरक्षित किया गया है।&lt;/li&gt;
	&lt;li&gt;भारत में प्रमुख अरिबाडा स्थलों में ओडिशा में गहिरमाथा और रुशिकुल्या शामिल हैं।&lt;/li&gt;
	&lt;li&gt;प्रकाश प्रदूषण, समुद्र तट निर्माण और अनियमित पर्यटन घोंसले के शिकार व्यवहार को बाधित करते हैं।&lt;/li&gt;
	&lt;li&gt;घोंसले के शिकार समुद्र तट पर्यावरण (संरक्षण) अधिनियम, 1986 के तहत अधिसूचित तटीय विनियमन क्षेत्र (CRZ) मानदंडों के अंतर्गत आते हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Surprise Strikes and Counter-Insurgency Operations.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;The Indian Army is establishing 25 Bhairav Battalions, which will focus on surprise strikes, counter-insurgency operations, reconnaissance, and high-mobility missions, particularly along volatile borders with China and Pakistan.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;The Bhairav Battalions are a new hybrid combat model, blending infantry and Special Forces capabilities for terrain-specific missions.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;These units will be deployed for high-speed operations, cross-border strikes, deep reconnaissance, and to relieve Special Forces of less critical tasks.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Five Bhairav Battalions are already operational, with plans to raise 25 battalions in total, focusing on northern borders, insurgency zones, and rapid mobilization areas.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Insights from Operation Sindoor highlighted the need for these agile, versatile units to bridge gaps between infantry and Special Forces for faster, more coordinated responses.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Bhairav Battalions&lt;/strong&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;These battalions are designed to operate in diverse combat scenarios, utilizing rapid mobility and cross-border strikes to counter insurgency and other asymmetrical threats.&lt;/li&gt;
		&lt;li&gt;With a mix of infantry, artillery, and air defence personnel, they are adaptable to various terrains and conditions.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Key Transformations in the Indian Army&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;Ashni Platoons:&lt;/strong&gt; Special units within infantry for drone operations, surveillance, and loitering munitions.&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;Rudra Brigades:&lt;/strong&gt; Combined arms units for autonomous battlefield dominance using cutting-edge technology.&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;Shaktibaan Regiments:&lt;/strong&gt; Focus on unmanned warfare with swarm drones and precision strike capabilities.&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;Divyastra Batteries:&lt;/strong&gt; Advanced artillery systems integrating drones for real-time target tracking and precision engagement.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Vision for Modernization&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;The introduction of these units reflects the shift towards AI-assisted, network-centric warfare, offering flexibility and tech-enabled battlefield readiness.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;आश्चर्यजनक हमले और आतंकवाद विरोधी अभियान&lt;/strong&gt;&lt;/u&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;भारतीय सेना 25 भैरव बटालियनों की स्थापना कर रही है, जो विशेष रूप से चीन और पाकिस्तान के साथ अस्थिर सीमाओं पर आश्चर्यजनक हमलों, आतंकवाद विरोधी अभियानों, टोही और उच्च गतिशीलता मिशनों पर ध्यान केंद्रित करेंगी।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;भैरव बटालियन एक नया हाइब्रिड युद्ध मॉडल है, जो इलाके-विशिष्ट मिशनों के लिए इन्फैंट्री और स्पेशल फोर्सेज क्षमताओं का मिश्रण है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;इन इकाइयों को उच्च गति संचालन, सीमा पार हमलों, गहरी टोही के लिए और स्पेशल फोर्सेज को कम महत्वपूर्ण कार्यों से राहत देने के लिए तैनात किया जाएगा।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;पांच भैरव बटालियन पहले से ही चालू हैं, कुल 25 बटालियन बढ़ाने की योजना है, जो उत्तरी सीमाओं, विद्रोह क्षेत्रों और तेजी से जुटाए जाने वाले क्षेत्रों पर ध्यान केंद्रित कर रही हैं।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;ऑपरेशन सिंदूर से मिली जानकारी ने इन्फैंट्री और स्पेशल फोर्सेज के बीच तेजी से, अधिक समन्वित प्रतिक्रियाओं के लिए अंतराल को पाटने के लिए इन चुस्त, बहुमुखी इकाइयों की आवश्यकता पर प्रकाश डाला।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;भैरव बटालियन&lt;/strong&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;ये बटालियन विभिन्न युद्ध परिदृश्यों में संचालित करने के लिए डिज़ाइन किए गए हैं, जो विद्रोह और अन्य विषम खतरों का मुकाबला करने के लिए तेजी से गतिशीलता और सीमा पार हमलों का उपयोग करते हैं।&lt;/li&gt;
		&lt;li&gt;इन्फैंट्री, तोपखाने और वायु रक्षा कर्मियों के मिश्रण के साथ, वे विभिन्न इलाकों और स्थितियों के अनुकूल हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;भारतीय सेना में प्रमुख परिवर्तन&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;अशनी प्लाटून:&lt;/strong&gt; ड्रोन संचालन, निगरानी और मंडराने वाले गोला-बारूद के लिए इन्फैंट्री के भीतर विशेष इकाइयाँ।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;रुद्र ब्रिगेड:&lt;/strong&gt; अत्याधुनिक तकनीक का उपयोग करके स्वायत्त युद्धक्षेत्र प्रभुत्व के लिए संयुक्त हथियार इकाइयाँ।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;शक्तिबाण रेजिमेंट:&lt;/strong&gt; झुंड ड्रोन और सटीक हमले क्षमताओं के साथ मानव रहित युद्ध पर ध्यान केंद्रित करें।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;दिव्यास्त्र बैटरी:&lt;/strong&gt; वास्तविक समय लक्ष्य ट्रैकिंग और सटीक जुड़ाव के लिए ड्रोन को एकीकृत करने वाली उन्नत तोपखाने प्रणाली।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;आधुनिकीकरण के लिए विजन&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;इन इकाइयों की शुरूआत AI-सहायता प्राप्त, नेटवर्क-केंद्रित युद्ध की ओर बदलाव को दर्शाती है, जो लचीलापन और तकनीक-सक्षम युद्धक्षेत्र तत्परता प्रदान करती है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;XChat.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Elon Musk has launched XChat, a new messaging platform, as a competitor to WhatsApp, Telegram, and WeChat.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Security Features:&lt;/strong&gt; XChat offers Bitcoin-style encryption, disappearing messages, and end-to-end encryption for secure communication.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Cross-Platform Communication:&lt;/strong&gt; The platform supports audio/video calls and file sharing across devices.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Target Audience:&lt;/strong&gt; XChat is initially available to paid subscribers of X, with plans for wider availability in the future.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Based on Rust:&lt;/strong&gt; XChat is built using the Rust programming language, which prioritizes speed and security.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Future Plans:&lt;/strong&gt; XChat could potentially integrate AI features, similar to WhatsApp&amp;#39;s Grok AI.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Beta Availability:&lt;/strong&gt; XChat is currently in its beta phase and available to select users and developers.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Competition:&lt;/strong&gt; XChat aims to challenge the dominance of established platforms like WhatsApp, Telegram, and WeChat.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;XChat&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;एलन मस्क ने व्हाट्सएप, टेलीग्राम और वीचैट को प्रतिस्पर्धी के रूप में एक नया मैसेजिंग प्लेटफॉर्म, XChat लॉन्च किया है।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;सुरक्षा सुविधाएँ:&lt;/strong&gt; XChat सुरक्षित संचार के लिए बिटकॉइन-शैली एन्क्रिप्शन, गायब होने वाले संदेश और एंड-टू-एंड एन्क्रिप्शन प्रदान करता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;क्रॉस-प्लेटफ़ॉर्म संचार:&lt;/strong&gt; यह प्लेटफ़ॉर्म उपकरणों पर ऑडियो/वीडियो कॉल और फ़ाइल साझाकरण का समर्थन करता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;लक्षित दर्शक:&lt;/strong&gt; XChat शुरू में X के सशुल्क ग्राहकों के लिए उपलब्ध है, भविष्य में व्यापक उपलब्धता की योजना है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Rust पर आधारित:&lt;/strong&gt; XChat Rust प्रोग्रामिंग भाषा का उपयोग करके बनाया गया है, जो गति और सुरक्षा को प्राथमिकता देता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;भविष्य की योजनाएँ:&lt;/strong&gt; XChat संभावित रूप से व्हाट्सएप के Grok AI के समान AI सुविधाओं को एकीकृत कर सकता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;बीटा उपलब्धता:&lt;/strong&gt; XChat वर्तमान में अपने बीटा चरण में है और चुनिंदा उपयोगकर्ताओं और डेवलपर्स के लिए उपलब्ध है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;प्रतिस्पर्धा:&lt;/strong&gt; XChat का लक्ष्य व्हाट्सएप, टेलीग्राम और वीचैट जैसे स्थापित प्लेटफार्मों के प्रभुत्व को चुनौती देना है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;&quot;&gt;The correct answer is&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;Barley and gram&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul dir=&quot;ltr&quot; style=&quot;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Rabi crops are winter-planted crops that are harvested in the spring.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Rabi crops&lt;/span&gt;&amp;nbsp;are sown in winter from October to December and harvested in summer from April to June.&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Wheat, barley, gram, peas, and lentils are among them.&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;A warm climate is required for seed germination and a cold climate for the growth of crops.&lt;/li&gt;
&lt;/ul&gt;

&lt;div style=&quot;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/div&gt;

&lt;div style=&quot;&quot;&gt;
&lt;p dir=&quot;ltr&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Kharif crop :&lt;/span&gt;&lt;/p&gt;

&lt;ul dir=&quot;ltr&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Crops that are sown during the southwest monsoon season are called Kharif or monsoon crops.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;These crops are sown at the beginning of the season around the end of May to early June and are harvested post the monsoon rains beginning in October.&lt;/li&gt;
	&lt;li&gt;Rice, &lt;strong&gt;maize&lt;/strong&gt;, pulses such as urad, moong dal and millets are among the key kharif crops.&lt;/li&gt;
	&lt;li&gt;It requires a lot of water and hot weather to grow.&lt;/li&gt;
&lt;/ul&gt;

&lt;p dir=&quot;ltr&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Zaid Crop :&lt;/span&gt;&lt;/p&gt;

&lt;ul dir=&quot;ltr&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Sown and harvested: March-July (between Rabi and Kharif)&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;Important Zaid crops include: Seasonal fruits, vegetables, fodder crops etc.&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;<br><br>&lt;p&gt;सही उत्तर&amp;nbsp;&lt;u&gt;&lt;strong&gt;जौ और चना&lt;/strong&gt;&lt;/u&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;है।&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;रबी की फसलें सर्दियों में बोई जाने वाली फसलें हैं जो वसंत ऋतु में काटी जाती हैं।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;रबी की फ़सल&lt;/strong&gt; सर्दियों में अक्टूबर से दिसंबर तक बोई जाती है और गर्मियों में अप्रैल से जून तक काटी जाती है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;इनमें गेहूं, जौ, चना, मटर और मसूर शामिल हैं।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;बीजों के अंकुरण के लिए गर्म जलवायु और फसलों के विकास के लिए ठंडी जलवायु की आवश्यकता होती है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;खरीफ फसल :&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;दक्षिण-पश्चिम मानसून के मौसम में बोई जाने वाली फसलें खरीफ या मानसून की फसलें कहलाती हैं।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;ये फ़सलें मौसम की शुरुआत में मई के अंत से लेकर जून की शुरुआत तक बोई जाती हैं और अक्टूबर में शुरू होने वाली मानसून की बारिश के बाद काटी जाती हैं।&lt;/li&gt;
	&lt;li&gt;चावल, &lt;strong&gt;मक्का&lt;/strong&gt;, दालें जैसे उड़द, मूंग दाल और बाजरा प्रमुख खरीफ फसलों में से हैं।&lt;/li&gt;
	&lt;li&gt;इसे बढ़ने के लिए बहुत अधिक पानी और गर्म मौसम की आवश्यकता होती है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;जायद फसल :&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;बुवाई&amp;nbsp;और कटाई : मार्च-जुलाई (रबी और खरीफ के बीच)&lt;span style=&quot;&quot;&gt;।&lt;/span&gt;&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;महत्वपूर्ण जायद फसलों में&amp;nbsp;मौसमी फल, सब्जियाँ, चारा फसलें आदि शामिल हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is option 3 i.e.,&amp;nbsp;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Article 37.&lt;/span&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Article 37&lt;/strong&gt;&lt;/u&gt;&amp;nbsp;of the Indian Constitution makes it clear that Directive Principles are non-justiciable.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;According to 37 &lt;/strong&gt;-&amp;nbsp;The provisions contained in this Part(III) shall not be enforceable by any court, but the principles therein laid down are nevertheless fundamental in the governance of the country and it shall be the duty of the State to apply these principles in making laws.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Article 36&lt;/strong&gt; defines the State.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Article 38(1)&lt;/strong&gt;&amp;nbsp;states that the State shall strive to promote the welfare of the people by securing and protecting as effectively as it may a social order in which justice, social, economic and political, shall inform all the institutions of the national life.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर विकल्प 3 है, अर्थात &lt;u&gt;&lt;strong&gt;अनुच्छेद 37&lt;/strong&gt;&lt;/u&gt;।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;भारतीय संविधान का &lt;u&gt;&lt;strong&gt;अनुच्छेद 37&lt;/strong&gt;&lt;/u&gt; यह स्पष्ट करता है कि निर्देशक सिद्धांत गैर-न्यायसंगत हैं।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;37 के अनुसार&lt;/strong&gt; - इस भाग (III) में निहित उपबंध&amp;nbsp;किसी भी न्यायालय द्वारा प्रवर्तनीय&amp;nbsp;नहीं होंगें&amp;nbsp;किंतु फिर भी इनमें अधिकथित तत्त्व देश के शासन में मूलभूत हैं और विधि बनाने में इन तत्त्वों को लागू करना राज्य का कर्तव्य होगा।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;अनुच्छेद 36&lt;/strong&gt; राज्य की परिभाषा का वर्णन करता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;अनुच्छेद 38(1)&lt;/strong&gt; में कहा गया है कि राज्य लोक कल्याण की अभिवृद्धि करने और उनकी रक्षा करने का प्रयास करेगा क्योंकि यह एक सामाजिक व्यवस्था है जिसमें न्याय, सामाजिक, आर्थिक और राजनीतिक रूप से राष्ट्रीय जीवन के सभी संस्थानों को अनुप्राणित&amp;nbsp;किया जाएगा।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Jaipur and Alwar&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Koftgiri work&lt;/strong&gt;-

	&lt;ul&gt;
		&lt;li&gt;This art came from &lt;strong&gt;Damshik in Punjab&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;In Rajasthan, it came through the state of Gujarat.&lt;/li&gt;
		&lt;li&gt;The inlay on steel objects with thin wires of gold and brass is called &lt;strong&gt;koftagiri&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;&lt;u&gt;&lt;strong&gt;Jaipur and Alwar districts of Rajasthan are famous for this art&lt;/strong&gt;&lt;/u&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Tahnisha:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;Goldwork in brass.&lt;/li&gt;
		&lt;li&gt;Main Center - Alwar, Jaipur&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Tarkashi:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;Jewellery is made from thin wires of silver.&lt;/li&gt;
		&lt;li&gt;Main Center - Nathdwara (Rajsamand)&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्&amp;zwj;तर &lt;u&gt;&lt;strong&gt;जयपुर और अलवर&lt;/strong&gt;&lt;/u&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;कोफ्तगिरी कार्य-&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;यह कला &lt;strong&gt;पंजाब के दमिश्क&amp;nbsp;&lt;/strong&gt;से आयी&amp;nbsp;थी।&lt;/li&gt;
		&lt;li&gt;राजस्थान में, यह गुजरात राज्य के माध्यम से आयी&amp;nbsp;थी।&lt;/li&gt;
		&lt;li&gt;सोने और पीतल के पतले तारों से स्टील की वस्तुओं पर जड़ना &lt;strong&gt;कोफ्तगिरी&lt;/strong&gt; कहा जाता है।&lt;/li&gt;
		&lt;li&gt;&lt;u&gt;&lt;strong&gt;राजस्थान के जयपुर और अलवर जिले इस कला के लिए प्रसिद्ध हैं।&lt;/strong&gt;&lt;/u&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;तहनिशा:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;पीतल में सोने का काम।&lt;/li&gt;
		&lt;li&gt;मुख्य केंद्र - अलवर, जयपुर&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;तारकाशी:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;चांदी के पतले तारों से आभूषण बनाए जाते हैं।&lt;/li&gt;
		&lt;li&gt;मुख्य केंद्र - नाथद्वारा (राजसमंद)&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Chief Justice&lt;/strong&gt;.&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&amp;nbsp;&lt;strong&gt;Judicial Administration under Gupta&amp;#39;s period&lt;/strong&gt;:

	&lt;ul&gt;
		&lt;li&gt;The judicial system was far &lt;strong&gt;more developed under the Gupta rulers &lt;/strong&gt;than in earlier times.&lt;/li&gt;
		&lt;li&gt;For the first time, &lt;strong&gt;civil and criminal laws &lt;/strong&gt;were &lt;strong&gt;clearly demarcated&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;Theft and adultery&lt;/strong&gt; were subjects treated under&lt;strong&gt; criminal law&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;Disputes regarding various types of&lt;strong&gt; property formed&lt;/strong&gt; the&lt;strong&gt; body of civil law&lt;/strong&gt;. Elaborate laws were laid down about inheritance.&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;Laws&lt;/strong&gt; were based on the &lt;strong&gt;varna hierarchy.&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;The &lt;strong&gt;supreme judicial power&lt;/strong&gt; rested with the&amp;nbsp;&lt;strong&gt;king&lt;/strong&gt; and he tried cases with the help of the &lt;strong&gt;brahmana priests&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;There was the office of &lt;u&gt;Mahadandanayaka,&lt;/u&gt; who probably functioned as chief justice.&amp;nbsp;Hence, option 3 is correct.&amp;nbsp;&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;मुख्य न्यायाधीश&lt;/strong&gt; &lt;/u&gt;है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;गुप्त काल में न्यायिक प्रशासन&lt;/strong&gt;:

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;गुप्त शासकों के अधीन न्यायिक प्रणाली पहले के समय की तुलना में कहीं अधिक विकसित&lt;/strong&gt; थी।&lt;/li&gt;
		&lt;li&gt;पहली बार &lt;strong&gt;दीवानी और फौजदारी कानूनों&lt;/strong&gt; का &lt;strong&gt;स्पष्ट रूप से सीमांकन&lt;/strong&gt; किया गया।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;चोरी और व्यभिचार&lt;/strong&gt; &lt;strong&gt;आपराधिक कानून&lt;/strong&gt; के तहत व्यवहार किए जाने वाले विषय थे।&lt;/li&gt;
		&lt;li&gt;विभिन्न प्रकार की &lt;strong&gt;संपत्ति&lt;/strong&gt; से संबंधित विवादों &lt;strong&gt;ने नागरिक कानून का&lt;/strong&gt; गठन किया। विरासत के बारे में विस्तृत कानून बनाए गए थे।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;कानून&lt;/strong&gt; &lt;strong&gt;वर्ण पदानुक्रम पर आधारित थे।&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;सर्वोच्च न्यायिक शक्ति&lt;/strong&gt; &lt;strong&gt;राजा&lt;/strong&gt; के पास थी और उसने &lt;strong&gt;ब्राह्मण पुजारियों&lt;/strong&gt; की मदद से मामलों की कोशिश की&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;&lt;u&gt;महादंडनायक का कार्यालय था,&lt;/u&gt; जो संभवत: मुख्य न्यायाधीश के रूप में कार्य करता था। अत: विकल्प 3 सही है।&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&lt;strong&gt;&amp;nbsp;&lt;span style=&quot;&quot;&gt;Open source operating system&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;Operating system:&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;It is a system software useful for managing hardware and software resources of the computer and providing common services for computer programs&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&amp;nbsp;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;LINUX:&amp;nbsp;&lt;/strong&gt;&lt;span style=&quot;color: rgb(77, 81, 86);  &quot;&gt;Linux belongs to&amp;nbsp;the family of open-source Unix-like operating systems based on the Linux kernel.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(32, 33, 36);   &quot;&gt;&amp;nbsp;Linux is beneficial for all types of server applications and is designed to support multithreading applications.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(32, 33, 36);   &quot;&gt;Hence t&lt;/span&gt;&lt;span style=&quot;&quot;&gt;he correct answer is&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;&amp;nbsp;Open source operating system.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;Java platform:&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;color: rgb(22, 22, 22);   &quot;&gt;The Java&amp;nbsp;platform is the environment for developing and managing Java applets and applications.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;Communication software:&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;color: rgb(77, 81, 86);  &quot;&gt;Communication software exchanges&amp;nbsp;files and messages in text, audio,&amp;nbsp;and video formats between different computers or users.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;System software:&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;A system software is a set of programs that manages and controls a computer&amp;#39;s hardware and applications.&lt;/span&gt;&lt;span style=&quot;color: rgb(77, 81, 86);  &quot;&gt;&amp;nbsp;Examples of system software include operating systems, search engines, and game engines.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;<br><br>&lt;p&gt;सही उत्तर&amp;nbsp;&lt;strong&gt;ओपन सोर्स ऑपरेटिंग सिस्टम&lt;/strong&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li len=&quot;363&quot;&gt;&lt;strong len=&quot;113&quot;&gt;ऑपरेटिंग सिस्टम:&lt;/strong&gt;&lt;span len=&quot;159&quot;&gt;&amp;nbsp;यह कंप्यूटर के हार्डवेयर और सॉफ्टवेयर संसाधनों के प्रबंधन और कंप्यूटर प्रोग्राम के लिए सामान्य सेवाएं प्रदान करने के लिए उपयोगी एक सिस्टम सॉफ्टवेयर है&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&amp;nbsp;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li len=&quot;319&quot;&gt;&lt;strong len=&quot;102&quot;&gt;लिनक्स:&amp;nbsp;&lt;/strong&gt;&lt;span len=&quot;112&quot;&gt;लिनक्स लिनक्स कर्नेल पर आधारित ओपन-सोर्स यूनिक्स जैसे ऑपरेटिंग सिस्टम के परिवार से संबंधित है।&lt;/span&gt;&lt;/li&gt;
	&lt;li len=&quot;232&quot;&gt;&lt;span len=&quot;128&quot;&gt;लिनक्स सभी प्रकार के सर्वर अनुप्रयोगों के लिए फायदेमंद है और इसे मल्टीथ्रेडिंग अनुप्रयोगों का समर्थन करने के लिए डिज़ाइन किया गया है।&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span len=&quot;128&quot;&gt;​&lt;/span&gt;अतःसही उत्तर&lt;strong&gt;&amp;nbsp;ओपन सोर्स ऑपरेटिंग सिस्टम&lt;/strong&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li len=&quot;331&quot;&gt;&lt;strong len=&quot;116&quot;&gt;जावा प्लेटफॉर्म:&amp;nbsp;&lt;/strong&gt;&lt;span len=&quot;110&quot;&gt;जावा प्लेटफॉर्म जावा एप्लेट और अनुप्रयोगों के विकास और प्रबंधन के लिए वातावरण है।&lt;/span&gt;&lt;/li&gt;
	&lt;li len=&quot;367&quot;&gt;&lt;strong len=&quot;119&quot;&gt;संचार सॉफ्टवेयर:&amp;nbsp;&lt;/strong&gt;&lt;span len=&quot;143&quot;&gt;संचार सॉफ्टवेयर विभिन्न कंप्यूटरों या उपयोगकर्ताओं के बीच पाठ, ऑडियो और वीडियो प्रारूपों में फ़ाइलों और संदेशों का आदान-प्रदान करता है।&lt;/span&gt;&lt;/li&gt;
	&lt;li len=&quot;456&quot;&gt;&lt;strong len=&quot;106&quot;&gt;सिस्टम सॉफ्टवेयर:&lt;/strong&gt;&lt;span len=&quot;259&quot;&gt;&amp;nbsp;एक सिस्टम सॉफ्टवेयर प्रोग्राम का एक सेट है जो कंप्यूटर के हार्डवेयर और अनुप्रयोगों का प्रबंधन और नियंत्रण करता है।&lt;/span&gt;&amp;nbsp;सिस्टम सॉफ़्टवेयर के उदाहरणों में ऑपरेटिंग सिस्टम, खोज इंजन और गेम इंजन शामिल हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;The Correct answer is&lt;u&gt;&lt;strong&gt;&amp;nbsp;​Swami Dayanand Saraswati.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Satyarth Prakash (The Light of Meaning of the Truth or&amp;nbsp;The Light of Truth) is written&amp;nbsp;by&amp;nbsp;Dayanand Saraswati&lt;/strong&gt;&lt;/u&gt;&amp;nbsp;in 1875.

	&lt;ul&gt;
		&lt;li&gt;It is considered one of his major scholarly works.&lt;/li&gt;
		&lt;li&gt;The book was originally written in Hindi and subsequently revised by Swami Dayanand Saraswati in 1882.&lt;/li&gt;
		&lt;li&gt;This book is now translated into more than 20 languages including&amp;nbsp;Sanskrit&amp;nbsp;and several foreign languages like English,&amp;nbsp;French,&amp;nbsp;German,&amp;nbsp;Swahili,&amp;nbsp;Arabic&amp;nbsp;and&amp;nbsp;Chinese.&lt;/li&gt;
		&lt;li&gt;The major portion of the book is dedicated to laying down the reformist advocacy of Swami Dayanand with the last three chapters making a case for the comparative study of different religious faiths.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot; &quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Dayananda Saraswati&amp;nbsp;&lt;/strong&gt;was an Indian philosopher, social leader and founder of the&amp;nbsp;Arya Samaj.

	&lt;ul&gt;
		&lt;li&gt;He was the first to give the call for&lt;strong&gt;&amp;nbsp;Swaraj&amp;nbsp;as &amp;quot;India for Indians&amp;quot; in 1876&lt;/strong&gt;, a call later taken up by&amp;nbsp;&lt;strong&gt;Lokmanya Tilak&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;Denouncing the&amp;nbsp;idolatry&amp;nbsp;and ritualistic worship prevalent in&amp;nbsp;India&amp;nbsp;at the time, he worked towards reviving&amp;nbsp;Vedic&amp;nbsp;ideologies.&lt;/li&gt;
		&lt;li&gt;The&amp;nbsp;philosopher&amp;nbsp;and&amp;nbsp;President of India,&amp;nbsp;&lt;strong&gt;S. Radhakrishnan&amp;nbsp;called him one of the &amp;quot;makers of Modern India&amp;quot;&lt;/strong&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर&lt;u&gt;&lt;strong&gt;&amp;nbsp;स्वामी दयानंद सरस्वती है&lt;/strong&gt;&lt;/u&gt;।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;सत्यार्थ प्रकाश (सत्य का प्रकाश या सत्य का प्रकाश) दयानंद सरस्वती द्वारा 1875 में लिखा गया है।&lt;/strong&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;यह उनके प्रमुख विद्वानों में से एक माना जाता है।&lt;/li&gt;
		&lt;li&gt;पुस्तक मूल रूप से हिंदी में लिखी गई थी और बाद में 1882 में स्वामी दयानंद सरस्वती द्वारा संशोधित की गई थी।&lt;/li&gt;
		&lt;li&gt;यह पुस्तक अब 20 से अधिक भाषाओं में अनुवादित है, जिसमें संस्कृत और कई विदेशी भाषाओं जैसे अंग्रेजी, फ्रेंच, जर्मन, स्वाहिली, अरबी और चीनी शामिल हैं।&lt;/li&gt;
		&lt;li&gt;पुस्तक का प्रमुख हिस्सा स्वामी दयानंद की सुधारवादी वकालत को अंतिम तीन अध्यायों के साथ समर्पित करने के लिए समर्पित है, जो विभिन्न धार्मिक विश्वासों के तुलनात्मक अध्ययन के लिए एक मामला बनाते हैं&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;दयानंद सरस्वती &lt;/strong&gt;एक भारतीय दार्शनिक, सामाजिक नेता और आर्य समाज के संस्थापक थे।

	&lt;ul&gt;
		&lt;li&gt;वह &lt;strong&gt;1876 में स्वराज को &amp;quot;भारतीयों के लिए भारत&amp;quot; के रूप में आह्वान&lt;/strong&gt;&lt;strong&gt; देने वाले पहले व्यक्ति थे, &lt;/strong&gt;जिसे बाद में लोकमान्य तिलक ने लिया था।&lt;/li&gt;
		&lt;li&gt;उस समय भारत में प्रचलित मूर्ति पूजा और कर्मकांड पूजा की घोषणा करते हुए उन्होंने वैदिक विचारधाराओं को पुनर्जीवित करने की दिशा में काम किया।&lt;/li&gt;
		&lt;li&gt;दार्शनिक और भारत के राष्ट्रपति &lt;strong&gt;एस.&amp;nbsp;राधाकृष्णन ने उन्हें &amp;quot;आधुनिक भारत के निर्माताओं&amp;quot; में से एक कहा।&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The shore temple at Mahabalipuram, notable for its rock-cut architecture, was built during the reign of&amp;nbsp;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;Narasimhavarman II (Rajasimha).&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(31, 31, 31);   white-space-collapse: preserve;&quot;&gt;The Shore Temple at Mahabalipuram is a complex of temples and shrines that overlooks the &lt;strong&gt;shore of the Bay of Bengal. &lt;/strong&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(31, 31, 31);   white-space-collapse: preserve;&quot;&gt;It is one of the &lt;strong&gt;oldest structural (versus rock-cut)&lt;/strong&gt; stone temples of Southern India. &lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(31, 31, 31);   white-space-collapse: preserve;&quot;&gt;It was built during the &lt;strong&gt;reign of Narasimhavarman II (Rajasimha),&lt;/strong&gt; the Pallava king who ruled from&lt;strong&gt; 690 to 722 CE.&lt;/strong&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(31, 31, 31);   white-space-collapse: preserve;&quot;&gt;The Shore Temple is notable for its rock-cut architecture. &lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(31, 31, 31);   white-space-collapse: preserve;&quot;&gt;The main shrine is carved out of a single block of granite, and the other two shrines are built on a platform that is also carved out of the rock. &lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(31, 31, 31);   white-space-collapse: preserve;&quot;&gt;The temple is decorated with intricate carvings of Hindu gods and goddesses, as well as scenes from mythology.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(31, 31, 31);   white-space-collapse: preserve;&quot;&gt;The &lt;strong&gt;Shore Temple is a UNESCO World Heritage Site&lt;/strong&gt;, and it is one of the most popular tourist destinations in India. &lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(31, 31, 31);   white-space-collapse: preserve;&quot;&gt;It is a stunning &lt;strong&gt;example of Dravidian architecture&lt;/strong&gt;, and it is a testament to the skill and artistry of the &lt;strong&gt;Pallava craftsmen&lt;/strong&gt; who built it.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(31, 31, 31);   white-space-collapse: preserve;&quot;&gt;Here are some additional facts about the Shore Temple:&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;​It is the &lt;strong&gt;earliest important structural temple&lt;/strong&gt; in South India.&lt;/li&gt;
		&lt;li data-sourcepos=&quot;10:1-10:71&quot;&gt;It is built with sculpted granite stones hauled from a nearby quarry.&lt;/li&gt;
		&lt;li data-sourcepos=&quot;11:1-11:100&quot;&gt;Its &lt;strong&gt;pyramidal structure is 60 feet (18 m)&lt;/strong&gt; high and sits on a &lt;strong&gt;50 feet (15 m)&lt;/strong&gt; square platform.&lt;/li&gt;
		&lt;li data-sourcepos=&quot;12:1-12:71&quot;&gt;There is a small temple in front which was the original porch.&lt;/li&gt;
		&lt;li data-sourcepos=&quot;13:1-13:160&quot;&gt;The temple is a combination of three shrines. The main shrine is dedicated to Shiva, as is the smaller second shrine. The third shrine is dedicated to Vishnu.&lt;/li&gt;
		&lt;li data-sourcepos=&quot;14:1-14:104&quot;&gt;The temple has been damaged by sea erosion over the centuries, but it has been restored several times.&lt;/li&gt;
		&lt;li data-sourcepos=&quot;15:1-15:101&quot;&gt;The Shore Temple is a popular tourist destination, and it is also a place of pilgrimage for Hindus.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p data-placeholder=&quot;Translation&quot; dir=&quot;ltr&quot; id=&quot;tw-target-text&quot;&gt;महाबलीपुरम का शोर मंदिर, जो अपनी चट्टानों को काटकर बनाई गई वास्तुकला के लिए उल्लेखनीय है, &lt;strong&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;नरसिंहवर्मन &lt;/span&gt;&lt;/strong&gt;&lt;strong&gt;द्वितीय (राजसिम्हा) &lt;/strong&gt;के शासनकाल के दौरान बनाया गया था।&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;span style=&quot;font-family: var(--bs-body-font-family); font-size: var(--bs-body-font-size); font-weight: var(--bs-body-font-weight); text-align: var(--bs-body-text-align);&quot;&gt; &lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul dir=&quot;ltr&quot;&gt;
	&lt;li data-placeholder=&quot;Translation&quot;&gt;महाबलीपुरम का शोर मंदिर, मंदिरों और तीर्थस्थलों का एक परिसर है जो &lt;strong&gt;बंगाल की खाड़ी के तट पर दिखता है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li data-placeholder=&quot;Translation&quot;&gt;यह दक्षिणी भारत के &lt;strong&gt;सबसे पुराने संरचनात्मक (रॉक-कट) पत्थर&lt;/strong&gt; के मंदिरों में से एक है।&lt;/li&gt;
	&lt;li data-placeholder=&quot;Translation&quot;&gt;इसका निर्माण पल्लव &lt;strong&gt;राजा नरसिंहवर्मन द्वितीय (राजसिम्हा) &lt;/strong&gt;के शासनकाल के दौरान किया गया था, जिन्होंने&lt;strong&gt; 690 से 722 ईस्वी &lt;/strong&gt;तक शासन किया था।&lt;/li&gt;
	&lt;li data-placeholder=&quot;Translation&quot;&gt;शोर मंदिर अपनी चट्टानों को काटकर बनाई गई वास्तुकला के लिए उल्लेखनीय है।&lt;/li&gt;
	&lt;li data-placeholder=&quot;Translation&quot;&gt;मुख्य मंदिर ग्रेनाइट के एक ही खंड से बना है, और अन्य दो मंदिर एक चबूतरे पर बने हैं जो चट्टान से बना है।&lt;/li&gt;
	&lt;li data-placeholder=&quot;Translation&quot;&gt;मंदिर को हिंदू देवी-देवताओं की जटिल नक्काशी के साथ-साथ पौराणिक कथाओं के दृश्यों से सजाया गया है।&lt;/li&gt;
	&lt;li data-placeholder=&quot;Translation&quot;&gt;&lt;strong&gt;शोर &lt;/strong&gt;&lt;strong&gt;मंदिर एक यूनेस्को विश्व धरोहर स्थल है&lt;/strong&gt;, और यह भारत में सबसे लोकप्रिय पर्यटन स्थलों में से एक है।&lt;/li&gt;
	&lt;li data-placeholder=&quot;Translation&quot;&gt;यह &lt;strong&gt;द्रविड़ वास्तुकला &lt;/strong&gt;का एक आश्चर्यजनक &lt;strong&gt;उदाहरण&lt;/strong&gt; है, और यह इसे बनाने वाले &lt;strong&gt;पल्लव कारीगरों&lt;/strong&gt; के कौशल और कलात्मकता का प्रमाण है।&lt;/li&gt;
	&lt;li data-placeholder=&quot;Translation&quot;&gt;यहाँ &lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;तटवर्ती &lt;/span&gt;मंदिर के बारे में कुछ अतिरिक्त तथ्य दिए गए हैं:
	&lt;ul&gt;
		&lt;li data-placeholder=&quot;Translation&quot;&gt;​यह दक्षिण भारत का सबसे &lt;strong&gt;पहला महत्वपूर्ण संरचनात्मक मंदिर&lt;/strong&gt; है।&lt;/li&gt;
		&lt;li data-placeholder=&quot;Translation&quot;&gt;इसे पास की खदान से लाए गए तराशे गए ग्रेनाइट पत्थरों से बनाया गया है।&lt;/li&gt;
		&lt;li data-placeholder=&quot;Translation&quot;&gt;इसकी&lt;strong&gt; पिरामिडनुमा संरचना 60 फीट (18 मीटर) ऊँची है और 50 फीट (15 मीटर)&lt;/strong&gt; के वर्गाकार चबूतरे पर स्थित है।&lt;/li&gt;
		&lt;li data-placeholder=&quot;Translation&quot;&gt;सामने एक छोटा सा मंदिर है जो मूल बरामदा था।&lt;/li&gt;
		&lt;li data-placeholder=&quot;Translation&quot;&gt;यह मंदिर तीन तीर्थों का संयोजन है। इसमें &lt;span style=&quot;color: rgb(32, 33, 36);  &quot;&gt;बीच में भगवान विष्णु का मंदिर है जिसके दोनों तरफ से शिव मंदिर हैं।&lt;/span&gt;&lt;/li&gt;
		&lt;li data-placeholder=&quot;Translation&quot;&gt;मंदिर सदियों से समुद्री कटाव से क्षतिग्रस्त हो गया है, लेकिन इसे कई बार पुनर्निर्मित किया गया है।&lt;/li&gt;
		&lt;li data-placeholder=&quot;Translation&quot; id=&quot;tw-target-text&quot;&gt;तटीय मंदिर एक लोकप्रिय पर्यटन स्थल है, और यह हिंदुओं का तीर्थ स्थान भी है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Louis H. Sullivan.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Skyscraper Day is celebrated every year on September 3, marking the birth anniversary of Louis H. Sullivan, known as the &amp;ldquo;father of skyscrapers&amp;rdquo;.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Sullivan&amp;rsquo;s principle &amp;ldquo;form follows function&amp;rdquo; laid the foundation for modern skyscraper architecture.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Skyscraper Day is observed annually on September 3.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Louis H. Sullivan is celebrated as the &amp;ldquo;father of skyscrapers&amp;rdquo;.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;He promoted the architectural concept &amp;ldquo;form follows function&amp;rdquo;.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;The day honors engineering innovation, urban efficiency, and architectural creativity.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(0, 0, 0); &quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Frank Lloyd Wright&lt;/strong&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;Renowned American architect, considered Sullivan&amp;rsquo;s prot&amp;eacute;g&amp;eacute;, known for organic architecture and designs like Fallingwater.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Le Corbusier&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;Swiss-French architect, pioneer of modernist architecture; designed Chandigarh&amp;rsquo;s master plan in India.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Ludwig Mies van der Rohe&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;German-American architect, famous for minimalist style and modernist designs like the Barcelona Pavilion.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Significance of Skyscrapers&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;Symbolize progress, urban efficiency, and national pride.&lt;/li&gt;
		&lt;li&gt;Define modern city skylines and boost tourism.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;लुईस एच. सुलिवन&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;गगनचुंबी इमारत दिवस प्रत्येक वर्ष 3 सितंबर को मनाया जाता है, जो लुईस एच. सुलिवन की जयंती है, जिन्हें &amp;ldquo;गगनचुंबी इमारतों का जनक&amp;rdquo; के रूप में जाना जाता है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;सुलिवन के सिद्धांत &amp;ldquo;रूप कार्य का अनुसरण करता है (form follows function)&amp;rdquo; ने आधुनिक गगनचुंबी इमारत वास्तुकला की नींव रखी।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;गगनचुंबी इमारत दिवस प्रतिवर्ष 3 सितंबर को मनाया जाता है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;लुईस एच. सुलिवन को &amp;ldquo;गगनचुंबी इमारतों का जनक&amp;rdquo; के रूप में मनाया जाता है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;उन्होंने वास्तुशिल्प अवधारणा &amp;ldquo;रूप कार्य का अनुसरण करता है&amp;rdquo; को बढ़ावा दिया।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;यह दिन इंजीनियरिंग नवाचार, शहरी दक्षता और वास्तुशिल्प रचनात्मकता का सम्मान करता है।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(0, 0, 0); &quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;फ्रैंक लॉयड राइट&lt;/strong&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;प्रसिद्ध अमेरिकी वास्तुकार, सुलिवन के संरक्षक माने जाते हैं, जैविक वास्तुकला और फॉलिंगवाटर जैसे डिजाइनों के लिए जाने जाते हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;ले कॉर्बुसियर&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;स्विस-फ्रांसीसी वास्तुकार, आधुनिक वास्तुकला के अग्रदूत; भारत में चंडीगढ़ की मास्टर प्लान तैयार की है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;लुडविग मिस वैन डेर रोहे&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;जर्मन-अमेरिकी वास्तुकार, न्यूनतम शैली और बार्सिलोना पैवेलियन जैसे आधुनिक डिजाइनों के लिए प्रसिद्ध है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;गगनचुंबी इमारतों का महत्व&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;प्रगति, शहरी दक्षता और राष्ट्रीय गौरव का प्रतीक हैं।&lt;/li&gt;
		&lt;li&gt;आधुनिक शहर के क्षितिज को परिभाषित करते हैं और पर्यटन को बढ़ावा देते हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Koppen Classification&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The &lt;strong&gt;Koppen Classification&lt;/strong&gt; is the most widely used climate classification system globally. It was developed by the German climatologist &lt;strong&gt;Wladimir K&amp;ouml;ppen&lt;/strong&gt; in &lt;strong&gt;1884&lt;/strong&gt; and has undergone several revisions since.&lt;/li&gt;
	&lt;li&gt;The system categorizes climates into &lt;strong&gt;five major groups&lt;/strong&gt;, based on &lt;strong&gt;average temperature&lt;/strong&gt; and &lt;strong&gt;precipitation patterns&lt;/strong&gt;. These groups are further subdivided into smaller categories.&lt;/li&gt;
	&lt;li&gt;The &lt;strong&gt;Koppen Classification&lt;/strong&gt; is valued for its simplicity and ability to effectively correlate vegetation types with climatic conditions, making it extensively used in fields such as &lt;strong&gt;geography, ecology, and agricultural studies&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;The five major climate groups in the system are: &lt;strong&gt;Tropical (A)&lt;/strong&gt;, &lt;strong&gt;Dry (B)&lt;/strong&gt;, &lt;strong&gt;Temperate (C)&lt;/strong&gt;, &lt;strong&gt;Continental (D)&lt;/strong&gt;, and &lt;strong&gt;Polar (E)&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;This classification is based on monthly and annual averages of temperature and precipitation, making it a versatile tool for analyzing global climatic patterns.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Trewartha Classification:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;The &lt;strong&gt;Trewartha Classification&lt;/strong&gt; is a modified version of the K&amp;ouml;ppen system, introduced by &lt;strong&gt;Glenn Trewartha&lt;/strong&gt; in the &lt;strong&gt;1930s&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;It focuses on better distinguishing between subtropical and temperate climates, addressing criticisms of K&amp;ouml;ppen&amp;#39;s original system.&lt;/li&gt;
		&lt;li&gt;Though useful, it is less widely adopted compared to the K&amp;ouml;ppen system.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Strahler Classification:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;Developed by &lt;strong&gt;Arthur Strahler&lt;/strong&gt;, this classification is based on the concept of air masses and their movements.&lt;/li&gt;
		&lt;li&gt;It integrates physical geography principles to define climate zones.&lt;/li&gt;
		&lt;li&gt;While insightful, it is primarily used in academic research rather than practical applications.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Thornthwaite Classification:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;Introduced by &lt;strong&gt;Charles Warren Thornthwaite&lt;/strong&gt; in &lt;strong&gt;1948&lt;/strong&gt;, this system emphasizes &lt;strong&gt;water balance and potential evapotranspiration&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;It is mainly applied in &lt;strong&gt;hydrology and agricultural studies&lt;/strong&gt;, as it provides a detailed understanding of soil moisture and water availability.&lt;/li&gt;
		&lt;li&gt;Despite its utility, it is not as universally applied as the K&amp;ouml;ppen system.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Applications of Koppen Classification:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;It is extensively used in &lt;strong&gt;environmental studies, agriculture, and urban planning&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;Ecologists use it to study &lt;strong&gt;biomes&lt;/strong&gt; and understand the distribution of vegetation globally.&lt;/li&gt;
		&lt;li&gt;It also assists in predicting climate change impacts and analyzing historical climatic trends.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Historical Development:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;The &lt;strong&gt;Koppen Classification&lt;/strong&gt; system was first introduced in &lt;strong&gt;1884&lt;/strong&gt; and revised in &lt;strong&gt;1918, 1936, and 1938&lt;/strong&gt; to incorporate better understanding of climatic data.&lt;/li&gt;
		&lt;li&gt;Its creator, &lt;strong&gt;Wladimir K&amp;ouml;ppen&lt;/strong&gt;, was a pioneer in integrating climate and vegetation patterns.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Global Acceptance:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;The system&amp;#39;s simplicity and effectiveness have led to its universal adoption, making it the standard for climate classification.&lt;/li&gt;
		&lt;li&gt;It is used by organizations such as the &lt;strong&gt;World Meteorological Organization (WMO)&lt;/strong&gt; and &lt;strong&gt;United Nations&lt;/strong&gt; for climate-related studies.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Scientific Basis:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;The classification is grounded in scientific principles of &lt;strong&gt;temperature and precipitation&lt;/strong&gt; averages, ensuring its reliability across different geographical regions.&lt;/li&gt;
		&lt;li&gt;Its subdivisions are particularly useful for detailed regional climate studies.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;कोपेन वर्गीकरण&lt;/strong&gt;&lt;/u&gt; है।&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;कोपेन वर्गीकरण&lt;/strong&gt; विश्व स्तर पर सबसे व्यापक रूप से उपयोग की जाने वाली जलवायु वर्गीकरण प्रणाली है। इसे जर्मन जलवायु विज्ञानी &lt;strong&gt;व्लादिमीर कोपेन&lt;/strong&gt; ने &lt;strong&gt;1884&lt;/strong&gt; में विकसित किया था और तब से इसमें कई संशोधन हुए हैं।&lt;/li&gt;
	&lt;li&gt;यह प्रणाली &lt;strong&gt;औसत तापमान&lt;/strong&gt; और &lt;strong&gt;वर्षा पैटर्न&lt;/strong&gt; के आधार पर जलवायु को &lt;strong&gt;पांच प्रमुख समूहों&lt;/strong&gt; में वर्गीकृत करती है। इन समूहों को आगे छोटे श्रेणियों में विभाजित किया गया है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;कोपेन वर्गीकरण&lt;/strong&gt; को इसकी सरलता और जलवायु परिस्थितियों के साथ वनस्पति प्रकारों को प्रभावी ढंग से सहसंबंधित करने की क्षमता के लिए महत्व दिया जाता है, जिससे यह &lt;strong&gt;भूगोल, पारिस्थितिकी और कृषि अध्ययन&lt;/strong&gt; जैसे क्षेत्रों में व्यापक रूप से उपयोग किया जाता है।&lt;/li&gt;
	&lt;li&gt;इस प्रणाली में पांच प्रमुख जलवायु समूह हैं: &lt;strong&gt;उष्णकटिबंधीय (A)&lt;/strong&gt;, &lt;strong&gt;शुष्क (B)&lt;/strong&gt;, &lt;strong&gt;समशीतोष्ण (C)&lt;/strong&gt;, &lt;strong&gt;महाद्वीपीय (D)&lt;/strong&gt;, और &lt;strong&gt;ध्रुवीय (E)&lt;/strong&gt;।&lt;/li&gt;
	&lt;li&gt;यह वर्गीकरण तापमान और वर्षा के मासिक और वार्षिक औसत पर आधारित है, जो इसे वैश्विक जलवायु पैटर्न का विश्लेषण करने के लिए एक बहुमुखी उपकरण बनाता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;ट्रेवर्था वर्गीकरण:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;ट्रेवर्था वर्गीकरण&lt;/strong&gt; कोपेन प्रणाली का एक संशोधित संस्करण है, जिसे &lt;strong&gt;ग्लेन ट्रेवर्था&lt;/strong&gt; ने &lt;strong&gt;1930 के दशक&lt;/strong&gt; में पेश किया था।&lt;/li&gt;
		&lt;li&gt;यह कोपेन की मूल प्रणाली की आलोचनाओं को संबोधित करते हुए, उपोष्णकटिबंधीय और समशीतोष्ण जलवायु के बीच बेहतर ढंग से अंतर करने पर केंद्रित है।&lt;/li&gt;
		&lt;li&gt;उपयोगी होने पर भी, इसे कोपेन प्रणाली की तुलना में कम व्यापक रूप से अपनाया गया है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;स्ट्राहलर वर्गीकरण:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;आर्थर स्ट्राहलर&lt;/strong&gt; द्वारा विकसित, यह वर्गीकरण वायु द्रव्यमान और उनकी गतिविधियों की अवधारणा पर आधारित है।&lt;/li&gt;
		&lt;li&gt;यह जलवायु क्षेत्रों को परिभाषित करने के लिए भौतिक भूगोल सिद्धांतों को एकीकृत करता है।&lt;/li&gt;
		&lt;li&gt;अंतर्दृष्टिपूर्ण होने के बावजूद, इसका उपयोग मुख्य रूप से व्यावहारिक अनुप्रयोगों के बजाय शैक्षणिक अनुसंधान में किया जाता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;थॉर्नथवेट वर्गीकरण:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;चार्ल्स वॉरेन थॉर्नथवेट&lt;/strong&gt; द्वारा &lt;strong&gt;1948&lt;/strong&gt; में पेश की गई, यह प्रणाली &lt;strong&gt;जल संतुलन और संभावित वाष्पीकरण&lt;/strong&gt; पर जोर देती है।&lt;/li&gt;
		&lt;li&gt;यह मुख्य रूप से &lt;strong&gt;जल विज्ञान और कृषि अध्ययन&lt;/strong&gt; में लागू होता है, क्योंकि यह मिट्टी की नमी और पानी की उपलब्धता की विस्तृत समझ प्रदान करता है।&lt;/li&gt;
		&lt;li&gt;अपनी उपयोगिता के बावजूद, यह कोपेन प्रणाली जितना सार्वभौमिक रूप से लागू नहीं होता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;कोपेन वर्गीकरण के अनुप्रयोग:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;यह &lt;strong&gt;पर्यावरण अध्ययन, कृषि और शहरी नियोजन&lt;/strong&gt; में व्यापक रूप से उपयोग किया जाता है।&lt;/li&gt;
		&lt;li&gt;पारिस्थितिकीविद &lt;strong&gt;बायोम&lt;/strong&gt; का अध्ययन करने और विश्व स्तर पर वनस्पति के वितरण को समझने के लिए इसका उपयोग करते हैं।&lt;/li&gt;
		&lt;li&gt;यह जलवायु परिवर्तन के प्रभावों की भविष्यवाणी करने और ऐतिहासिक जलवायु रुझानों का विश्लेषण करने में भी सहायता करता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;ऐतिहासिक विकास:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;कोपेन वर्गीकरण&lt;/strong&gt; प्रणाली पहली बार &lt;strong&gt;1884&lt;/strong&gt; में पेश की गई थी और जलवायु डेटा की बेहतर समझ को शामिल करने के लिए &lt;strong&gt;1918, 1936 और 1938&lt;/strong&gt; में संशोधित की गई थी।&lt;/li&gt;
		&lt;li&gt;इसके निर्माता, &lt;strong&gt;व्लादिमीर कोपेन&lt;/strong&gt;, जलवायु और वनस्पति पैटर्न को एकीकृत करने में अग्रणी थे।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;वैश्विक स्वीकृति:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;सिस्टम की सरलता और प्रभावशीलता ने इसे सार्वभौमिक रूप से अपनाने के लिए प्रेरित किया है, जिससे यह जलवायु वर्गीकरण के लिए मानक बन गया है।&lt;/li&gt;
		&lt;li&gt;इसका उपयोग &lt;strong&gt;विश्व मौसम विज्ञान संगठन (WMO)&lt;/strong&gt; और &lt;strong&gt;संयुक्त राष्ट्र&lt;/strong&gt; जैसे संगठनों द्वारा जलवायु संबंधी अध्ययनों के लिए किया जाता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;वैज्ञानिक आधार:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;वर्गीकरण &lt;strong&gt;तापमान और वर्षा&lt;/strong&gt; औसत के वैज्ञानिक सिद्धांतों पर आधारित है, जो विभिन्न भौगोलिक क्षेत्रों में इसकी विश्वसनीयता सुनिश्चित करता है।&lt;/li&gt;
		&lt;li&gt;इसके उपखंड विशेष रूप से विस्तृत क्षेत्रीय जलवायु अध्ययन के लिए उपयोगी हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Adult Franchise&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;u style=&quot;font-size: 21px; font-weight: bolder; font-family: var(--bs-body-font-family); text-align: var(--bs-body-text-align);&quot;&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The Preamble to the Indian Constitution does not explicitly mention &lt;strong&gt;Adult Franchise&lt;/strong&gt; as one of its components.&lt;/li&gt;
	&lt;li&gt;The key elements of the Preamble include &lt;strong&gt;Justice&lt;/strong&gt; (social, economic, and political), &lt;strong&gt;Equality&lt;/strong&gt; (of status and opportunity), &lt;strong&gt;Liberty&lt;/strong&gt; (of thought, expression, belief, faith, and worship), and &lt;strong&gt;Fraternity&lt;/strong&gt; (assuring the dignity of the individual and the unity and integrity of the Nation).&lt;/li&gt;
	&lt;li&gt;Adult franchise, which ensures voting rights to all citizens above the age of 18 irrespective of caste, religion, or gender, is provided under &lt;strong&gt;Article 326&lt;/strong&gt; of the Constitution and is a fundamental principle of the democratic process in India.&lt;/li&gt;
	&lt;li&gt;The Preamble serves as the guiding philosophy of the Constitution but does not include operational details like adult franchise.&lt;/li&gt;
	&lt;li&gt;Adult franchise forms part of the broader democratic framework enshrined in the Constitution but is not explicitly mentioned in the Preamble.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Preamble of the Indian Constitution:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;The Preamble reflects the essence and philosophy of the Indian Constitution.&lt;/li&gt;
		&lt;li&gt;It declares India to be a &lt;strong&gt;Sovereign, Socialist, Secular, Democratic Republic&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;The objectives stated in the Preamble include Justice, Liberty, Equality, and Fraternity.&lt;/li&gt;
		&lt;li&gt;The Preamble is considered a &lt;strong&gt;part of the Constitution&lt;/strong&gt; as per the landmark Supreme Court judgment in the Kesavananda Bharati case (1973).&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Adult Franchise:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;Adult franchise in India is guaranteed under &lt;strong&gt;Article 326&lt;/strong&gt; of the Constitution.&lt;/li&gt;
		&lt;li&gt;It provides voting rights to all citizens aged 18 and above, without discrimination.&lt;/li&gt;
		&lt;li&gt;It is a fundamental aspect of India&amp;#39;s democratic system, ensuring universal suffrage.&lt;/li&gt;
		&lt;li&gt;Adult franchise was introduced by the Constitution to eliminate barriers of caste, religion, gender, or wealth in electoral participation.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Justice, Equality, Liberty, and Fraternity:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;Justice:&lt;/strong&gt; Refers to social, economic, and political justice ensuring fair treatment for all.&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;Equality:&lt;/strong&gt; Ensures equality of status and opportunity for all citizens.&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;Liberty:&lt;/strong&gt; Protects freedoms of thought, expression, belief, faith, and worship.&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;Fraternity:&lt;/strong&gt; Promotes national unity and integrity while ensuring individual dignity.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Kesavananda Bharati Case (1973):&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;This landmark case upheld the Preamble as an integral part of the Constitution.&lt;/li&gt;
		&lt;li&gt;It established the doctrine of the &amp;quot;basic structure&amp;quot; of the Constitution.&lt;/li&gt;
		&lt;li&gt;As per the judgment, the Preamble&amp;#39;s principles cannot be amended or altered in a way that damages the Constitution&amp;#39;s fundamental framework.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;वयस्क मताधिकार&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-size:22px;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; style=&quot;color: rgb(33, 37, 41);&quot; width=&quot;26px&quot; /&gt;&lt;u style=&quot;color: rgb(33, 37, 41);  font-weight: bolder;&quot;&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;भारतीय संविधान की प्रस्तावना में &lt;strong&gt;वयस्क मताधिकार&lt;/strong&gt; को स्पष्ट रूप से इसके घटकों में से एक के रूप में उल्लेख नहीं किया गया है।&lt;/li&gt;
	&lt;li&gt;प्रस्तावना के मुख्य तत्वों में &lt;strong&gt;न्याय&lt;/strong&gt; (सामाजिक, आर्थिक और राजनीतिक), &lt;strong&gt;समानता&lt;/strong&gt; (स्थिति और अवसर की), &lt;strong&gt;स्वतंत्रता&lt;/strong&gt; (विचार, अभिव्यक्ति, विश्वास, आस्था और उपासना की), और &lt;strong&gt;बंधुत्व&lt;/strong&gt; (व्यक्ति की गरिमा और राष्ट्र की एकता और अखंडता का आश्वासन) शामिल हैं।&lt;/li&gt;
	&lt;li&gt;वयस्क मताधिकार, जो जाति, धर्म या लिंग की परवाह किए बिना 18 वर्ष से अधिक आयु के सभी नागरिकों को मतदान का अधिकार सुनिश्चित करता है, संविधान के &lt;strong&gt;अनुच्छेद 326&lt;/strong&gt; के तहत प्रदान किया गया है और भारत में लोकतांत्रिक प्रक्रिया का एक मौलिक सिद्धांत है।&lt;/li&gt;
	&lt;li&gt;प्रस्तावना संविधान के मार्गदर्शक दर्शन के रूप में कार्य करती है लेकिन इसमें वयस्क मताधिकार जैसे परिचालन विवरण शामिल नहीं हैं।&lt;/li&gt;
	&lt;li&gt;वयस्क मताधिकार संविधान में निहित व्यापक लोकतांत्रिक ढांचे का हिस्सा है लेकिन प्रस्तावना में स्पष्ट रूप से इसका उल्लेख नहीं किया गया है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;भारतीय संविधान की प्रस्तावना:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;प्रस्तावना भारतीय संविधान के सार और दर्शन को दर्शाती है।&lt;/li&gt;
		&lt;li&gt;यह भारत को एक &lt;strong&gt;संप्रभु, समाजवादी, धर्मनिरपेक्ष, लोकतांत्रिक गणराज्य&lt;/strong&gt; घोषित करता है।&lt;/li&gt;
		&lt;li&gt;प्रस्तावना में बताए गए उद्देश्यों में न्याय, स्वतंत्रता, समानता और बंधुत्व शामिल हैं।&lt;/li&gt;
		&lt;li&gt;केशवानंद भारती मामले (1973) में उच्चतम न्यायालय के ऐतिहासिक फैसले के अनुसार प्रस्तावना को &lt;strong&gt;संविधान का हिस्सा&lt;/strong&gt; माना जाता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;वयस्क मताधिकार:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;भारत में वयस्क मताधिकार संविधान के &lt;strong&gt;अनुच्छेद 326&lt;/strong&gt; के तहत गारंटीकृत है।&lt;/li&gt;
		&lt;li&gt;यह भेदभाव के बिना, 18 वर्ष और उससे अधिक आयु के सभी नागरिकों को मतदान का अधिकार प्रदान करता है।&lt;/li&gt;
		&lt;li&gt;यह भारत की लोकतांत्रिक व्यवस्था का एक मौलिक पहलू है, जो सार्वभौमिक मताधिकार सुनिश्चित करता है।&lt;/li&gt;
		&lt;li&gt;चुनावी भागीदारी में जाति, धर्म, लिंग या धन के अवरोधों को समाप्त करने के लिए संविधान द्वारा वयस्क मताधिकार शुरू किया गया था।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;न्याय, समानता, स्वतंत्रता और बंधुत्व:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;न्याय:&lt;/strong&gt; सभी के लिए निष्पक्ष व्यवहार सुनिश्चित करने वाले सामाजिक, आर्थिक और राजनीतिक न्याय को संदर्भित करता है।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;समानता:&lt;/strong&gt; सभी नागरिकों के लिए स्थिति और अवसर की समानता सुनिश्चित करता है।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;स्वतंत्रता:&lt;/strong&gt; विचार, अभिव्यक्ति, विश्वास, आस्था और उपासना की स्वतंत्रता की रक्षा करता है।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;बंधुत्व:&lt;/strong&gt; व्यक्तिगत गरिमा सुनिश्चित करते हुए राष्ट्रीय एकता और अखंडता को बढ़ावा देता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;केशवानंद भारती मामला (1973):&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;इस ऐतिहासिक मामले ने प्रस्तावना को संविधान के अभिन्न अंग के रूप में बरकरार रखा।&lt;/li&gt;
		&lt;li&gt;इसने संविधान के &amp;quot;मूल ढांचे&amp;quot; के सिद्धांत को स्थापित किया।&lt;/li&gt;
		&lt;li&gt;निर्णय के अनुसार, प्रस्तावना के सिद्धांतों को इस तरह से संशोधित या परिवर्तित नहीं किया जा सकता है जिससे संविधान के मौलिक ढांचे को नुकसान पहुंचे।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;England&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;u style=&quot;font-size: 21px; font-weight: bolder; font-family: var(--bs-body-font-family); text-align: var(--bs-body-text-align);&quot;&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The sandwich was popularized in &lt;strong&gt;England&lt;/strong&gt; by John Montagu, the 4th Earl of Sandwich, in the 18th century.&lt;/li&gt;
	&lt;li&gt;The Earl reportedly asked for meat to be placed between slices of bread so he could eat while continuing to play cards, which led to the creation of the sandwich.&lt;/li&gt;
	&lt;li&gt;The term &amp;quot;sandwich&amp;quot; was named after John Montagu&amp;#39;s title, the Earl of Sandwich.&lt;/li&gt;
	&lt;li&gt;Sandwiches became a convenient and portable food option and eventually gained widespread popularity across Europe and beyond.&lt;/li&gt;
	&lt;li&gt;Today, sandwiches are a versatile global staple, with countless variations found in different cuisines worldwide.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Origin of the Name:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;The name &amp;quot;sandwich&amp;quot; originates from John Montagu, 4th Earl of Sandwich, who lived in the 1700s in England.&lt;/li&gt;
		&lt;li&gt;It is believed that the Earl&amp;#39;s culinary invention was born out of practicality to avoid interrupting his gambling activities.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Types of Sandwiches:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;Sandwiches vary globally, including popular types like club sandwiches, paninis, subs, and wraps.&lt;/li&gt;
		&lt;li&gt;National variations include the B&amp;aacute;nh m&amp;igrave; in Vietnam, Shawarma wraps in the Middle East, and Croque Monsieur in France.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Health and Nutrition:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;Sandwiches can be made healthy by incorporating whole-grain bread, lean proteins, and fresh vegetables.&lt;/li&gt;
		&lt;li&gt;They also offer a flexible option for dietary preferences, including vegetarian and vegan alternatives.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Economic and Social Impact:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;Sandwiches are a significant part of the global fast-food industry, contributing to economic activities worldwide.&lt;/li&gt;
		&lt;li&gt;Their portability and ease of preparation make them a popular choice for working professionals and students.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;इंग्लैंड&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-size:22px;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; style=&quot;color: rgb(33, 37, 41);&quot; width=&quot;26px&quot; /&gt;&lt;u style=&quot;color: rgb(33, 37, 41);  font-weight: bolder;&quot;&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;18वीं शताब्दी में &lt;strong&gt;इंग्लैंड&lt;/strong&gt; में जॉन मोंटेगू, सैंडविच के चौथे अर्ल द्वारा सैंडविच को लोकप्रिय बनाया गया था।&lt;/li&gt;
	&lt;li&gt;कहा जाता है कि अर्ल ने कार्ड खेलते रहने के दौरान खाने के लिए ब्रेड के स्लाइस के बीच मांस रखने के लिए कहा था, जिससे सैंडविच का निर्माण हुआ।&lt;/li&gt;
	&lt;li&gt;&amp;quot;सैंडविच&amp;quot; शब्द का नाम जॉन मोंटेगू के खिताब, अर्ल ऑफ़ सैंडविच के नाम पर रखा गया था।&lt;/li&gt;
	&lt;li&gt;सैंडविच एक सुविधाजनक और पोर्टेबल खाद्य विकल्प बन गया और अंततः पूरे यूरोप और उसके बाहर व्यापक लोकप्रियता प्राप्त की।&lt;/li&gt;
	&lt;li&gt;आज, सैंडविच एक बहुमुखी वैश्विक मुख्य भोजन है, जिसमें दुनिया भर के विभिन्न व्यंजनों में अनगिनत रूप हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;नाम की उत्पत्ति:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;&amp;quot;सैंडविच&amp;quot; नाम इंग्लैंड में 1700 के दशक में रहने वाले जॉन मोंटेगू, सैंडविच के चौथे अर्ल से उत्पन्न हुआ है।&lt;/li&gt;
		&lt;li&gt;यह माना जाता है कि अर्ल का पाक आविष्कार उनकी जुआ गतिविधियों को बाधित करने से बचने की व्यावहारिकता से पैदा हुआ था।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;सैंडविच के प्रकार:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;सैंडविच विश्व स्तर पर भिन्न होते हैं, जिसमें क्लब सैंडविच, पैनिनि, सब और रैप जैसे लोकप्रिय प्रकार शामिल हैं।&lt;/li&gt;
		&lt;li&gt;राष्ट्रीय रूपों में वियतनाम में बान मि, मध्य पूर्व में शावर्मा रैप और फ्रांस में क्रोक मेसियर शामिल हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;स्वास्थ्य और पोषण:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;पूरे अनाज की ब्रेड, दुबले प्रोटीन और ताजी सब्जियों को शामिल करके सैंडविच को स्वस्थ बनाया जा सकता है।&lt;/li&gt;
		&lt;li&gt;वे आहार संबंधी प्राथमिकताओं के लिए एक लचीला विकल्प भी प्रदान करते हैं, जिसमें शाकाहारी और शाकाहारी विकल्प शामिल हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;आर्थिक और सामाजिक प्रभाव:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;सैंडविच वैश्विक फास्ट-फूड उद्योग का एक महत्वपूर्ण हिस्सा हैं, जो दुनिया भर में आर्थिक गतिविधियों में योगदान करते हैं।&lt;/li&gt;
		&lt;li&gt;उनकी पोर्टेबिलिटी और तैयारी में आसानी उन्हें कामकाजी पेशेवरों और छात्रों के लिए एक लोकप्रिय विकल्प बनाती है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;color: (33, 37, 41);&quot;&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;₹100 crore&lt;/strong&gt;&lt;/u&gt;.&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;NABARD:&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;NABARD&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;came into existence on&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;12 July 1982&lt;/span&gt;&amp;nbsp;by transferring the agricultural credit functions of RBI and refinance functions of the then Agricultural Refinance and Development Corporation (ARDC).&lt;/li&gt;
	&lt;li&gt;Set up with an initial capital of Rs.100 crore, its&amp;rsquo; paid-up capital stood at Rs.14,080 crore as of 31 March 2020.&lt;/li&gt;
	&lt;li&gt;Initially, it is owned by the Government of India and RBI.&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;NABARD today is fully owned by the Government of India&lt;/span&gt;.&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Vision&amp;nbsp;&lt;/span&gt;-&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;nbsp;&lt;/span&gt;Development Bank of the Nation for Fostering Rural Prosperity.&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Mission&lt;/span&gt;&amp;nbsp;-&amp;nbsp;Promote sustainable and equitable agriculture and rural development through participative financial and non-financial interventions, innovations, technology, and institutional development for securing prosperity.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color: (33, 37, 41);&quot;&gt;
	&lt;li&gt;The Reserve Bank of India (&lt;span style=&quot;font-weight: bolder;&quot;&gt;RBI&lt;/span&gt;) at the insistence of the Government of India, constituted a Committee to Review the Arrangements For Institutional Credit for Agriculture and Rural Development (&lt;span style=&quot;font-weight: bolder;&quot;&gt;CRAFICARD&lt;/span&gt;) to look into these very critical aspects.&lt;/li&gt;
	&lt;li&gt;The Committee was formed on&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;30 March 1979&lt;/span&gt;, under the&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;nbsp;Chairmanship of Shri B. Sivaraman&lt;/span&gt;, a former member of Planning Commission, Government of India.&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Committee&amp;rsquo;s interim report&lt;/span&gt;, submitted on 28 November 1979, outlined the&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;need for a new organizational device for providing undivided attention, forceful direction, and pointed focus to credit-related issues linked with rural development&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;Its recommendation was the formation of a unique development financial institution that would address these aspirations and the formation of the&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;National Bank for Agriculture and Rural Development (NABARD)&lt;/span&gt;&amp;nbsp;was approved by the Parliament through Act 61 of 1981.&lt;/li&gt;
&lt;/ul&gt;<br><br><p style="color: rgb(33, 37, 41);">সঠিক উত্তর&nbsp;<u><strong><span style="color: rgb(33, 37, 41);">100&nbsp;</span><span style="color: rgb(33, 37, 41);">কোটি টাকা</span></strong></u></p>

<p style="color: rgb(33, 37, 41);"><span style="display: flex;gap: 6px;align-items: center;"><img height="26px" src="//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png" width="26px" /><strong><span style="vertical-align: middle;font-size: 21px;"><u>Key Points</u></span></strong></span></p>

<p><span style="font-weight: bolder;">NABARD:</span></p>

<ul>
	<li>NABARD <strong>12ই জুলাই 1982-এ</strong> RBI-এর কৃষি ঋণ কার্যাবলী এবং তৎকালীন কৃষি পুনঃঅর্থায়ন ও উন্নয়ন কর্পোরেশন (ARDC)-এর পুনঃঅর্থায়ন কার্যাবলী হস্তান্তরের মাধ্যমে <strong>অস্তিত্ব লাভ করে।</strong></li>
	<li>100 কোটি টাকার প্রাথমিক মূলধনের সাথে সেট আপ করা হয়েছে, 31শে মার্চ 2020 পর্যন্ত এর পরিশোধিত মূলধন দাঁড়িয়েছে 14,080 কোটি টাকা।</li>
	<li>প্রাথমিকভাবে, এটি ভারত সরকার এবং আরবিআইয়ের মালিকানাধীন।</li>
	<li><strong>NABARD আজ সম্পূর্ণরূপে ভারত সরকারের মালিকানাধীন।</strong></li>
	<li><strong>ভাবনা - </strong>গ্রামীণ সমৃদ্ধি বৃদ্ধির জন্য জাতির উন্নয়ন <span style="color: rgb(33, 37, 41);">ব্যাঙ্ক</span>।</li>
	<li><strong><span style="color: rgb(33, 37, 41);">উদ্দেশ্য়</span> - </strong>অংশীদারিত্বমূলক আর্থিক এবং অ-আর্থিক হস্তক্ষেপ, উদ্ভাবন, প্রযুক্তি এবং সমৃদ্ধির জন্য প্রাতিষ্ঠানিক উন্নয়নের মাধ্যমে টেকসই এবং ন্যায়সঙ্গত কৃষি এবং গ্রামীণ উন্নয়নের প্রচার।</li>
</ul>

<p><span style="display: flex;gap: 6px;align-items: center;"><img height="26px" src="//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png" width="26px" /><strong><span style="vertical-align: middle;font-size: 21px;"><u>Additional Information</u></span></strong></span></p>

<ul>
	<li>ভারতীয় রিজার্ভ ব্যাঙ্ক (<strong>RBI</strong>) ভারত সরকারের পীড়াপীড়িতে, এই অত্যন্ত গুরুত্বপূর্ণ দিকগুলি দেখার জন্য কৃষি ও গ্রামীণ উন্নয়নের জন্য প্রাতিষ্ঠানিক ঋণের ব্যবস্থা পর্যালোচনা করার জন্য কমিটি (<strong>CRAFICARD</strong>) গঠন করেছে।</li>
	<li>কমিটিটি <strong>30শে মার্চ 1979</strong> তারিখে ভারত সরকারের পরিকল্পনা কমিশনের প্রাক্তন সদস্য <strong>শ্রী বি. শিবরামনের সভাপতিত্বে</strong> গঠিত হয়েছিল।</li>
	<li><span style="color: rgb(33, 37, 41);">28শে নভেম্বর 1979-এ জমা দেওয়া,&nbsp;</span><strong>কমিটির অন্তর্বর্তী প্রতিবেদন,</strong>&nbsp;<strong>অবিভক্ত মনোযোগ প্রদানের জন্য একটি নতুন সাংগঠনিক ডিভাইসের প্রয়োজনীয়তার রূপরেখা, জোরপূর্বক দিকনির্দেশনা এবং গ্রামীণ উন্নয়নের সাথে যুক্ত ক্রেডিট-সম্পর্কিত বিষয়গুলিতে ফোকাস করা।</strong></li>
	<li>এর সুপারিশ ছিল একটি অনন্য উন্নয়ন আর্থিক প্রতিষ্ঠান গঠন করা যা এই আকাঙ্খাগুলিকে সমাধান করবে এবং <strong>ন্যাশনাল <span style="color: rgb(33, 37, 41);">ব্যাঙ্ক</span> ফর এগ্রিকালচার অ্যান্ড রুরাল ডেভেলপমেন্ট (NABARD)</strong> গঠন 1981 সালের আইন 61 এর মাধ্যমে সংসদ দ্বারা অনুমোদিত হয়েছিল।</li>
</ul>

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Air Marshal Nagesh Kapoor.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Air Marshal Nagesh Kapoor SYSM PVSM AVSM VM assumed charge as the Vice Chief of the Air Staff of the Indian Air Force on 01 January 2026.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Air Marshal Nagesh Kapoor is an experienced fighter pilot with over 3,400 hours of flying experience.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;He was commissioned into the Indian Air Force in the fighter stream on 06 December 1986.&lt;/li&gt;
	&lt;li&gt;He has served as AOC-in-C Training Command and AOC-in-C South Western Air Command.&lt;/li&gt;
	&lt;li&gt;He played a key role in the induction of the PC-7 Mk II aircraft at the Air Force Academy.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Career Highlights&lt;/span&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;Alumnus of the National Defence Academy, Defence Services Staff College and National Defence College.&lt;/li&gt;
		&lt;li&gt;Flown all variants of MiG-21 and MiG-29 fighter aircraft.&lt;/li&gt;
		&lt;li&gt;Served as Defence Attach&amp;eacute; to Pakistan.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Key Appointments&lt;/span&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;Assistant Chief of Air Staff (Operations &amp;ndash; Strategy) at Air Headquarters.&lt;/li&gt;
		&lt;li&gt;Air Defence Commander at South Western Air Command.&lt;/li&gt;
		&lt;li&gt;Air Officer-in-Charge Personnel at Air Headquarters.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Awards and Decorations&lt;/span&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;Vayu Sena Medal (2008).&lt;/li&gt;
		&lt;li&gt;Ati Vishisht Seva Medal (2022).&lt;/li&gt;
		&lt;li&gt;Param Vishisht Seva Medal and Sarvottam Yudh Seva Medal (2025).&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;एयर मार्शल नागेश कपूर&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;समाचार में&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;एयर मार्शल नागेश कपूर एसवाईएसएम पीवीएसएम एवीएसएम वीएम ने 01 जनवरी 2026 को भारतीय वायु सेना के उप प्रमुख के रूप में पदभार ग्रहण किया।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;मुख्य बिंदु&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;एयर मार्शल नागेश कपूर 3,400 घंटे से अधिक के उड़ान अनुभव के साथ एक अनुभवी लड़ाकू पायलट हैं।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;उन्हें 06 दिसंबर 1986 को भारतीय वायु सेना की लड़ाकू धारा में कमीशन किया गया था।&lt;/li&gt;
	&lt;li&gt;उन्होंने एओसी-इन-सी ट्रेनिंग कमांड और एओसी-इन-सी दक्षिण पश्चिमी वायु कमान के रूप में कार्य किया है।&lt;/li&gt;
	&lt;li&gt;उन्होंने वायु सेना अकादमी में पीसी-7 एमके II विमान के शामिल होने में महत्वपूर्ण भूमिका निभाई।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;अतिरिक्त जानकारी&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;कैरियर की मुख्य बातें&lt;/span&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;राष्ट्रीय रक्षा अकादमी, रक्षा सेवा स्टाफ कॉलेज और राष्ट्रीय रक्षा कॉलेज के पूर्व छात्र।&lt;/li&gt;
		&lt;li&gt;मिग-21 और मिग-29 लड़ाकू विमानों के सभी रूपों को उड़ाया।&lt;/li&gt;
		&lt;li&gt;पाकिस्तान में रक्षा अताशे के रूप में कार्य किया।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;प्रमुख नियुक्तियाँ&lt;/span&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;वायु मुख्यालय में सहायक वायु सेना प्रमुख (संचालन - रणनीति)।&lt;/li&gt;
		&lt;li&gt;दक्षिण पश्चिमी वायु कमान में वायु रक्षा कमांडर।&lt;/li&gt;
		&lt;li&gt;वायु मुख्यालय में वायु अधिकारी-प्रभारी कार्मिक।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;पुरस्कार और सजावट&lt;/span&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;वायु सेना पदक (2008)।&lt;/li&gt;
		&lt;li&gt;अति विशिष्ट सेवा पदक (2022)।&lt;/li&gt;
		&lt;li&gt;परम विशिष्ट सेवा पदक और सर्वोत्तम युद्ध सेवा पदक (2025)।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/confusion-points-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Confusion Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;color: rgb(36, 39, 41);&quot;&gt;***Note: Based on the official answer key provided by NTA, both Option 3 and 4, Application software and editor, are correct&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Compilers:&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;A compiler&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;is a program that translates a source program written in some high-level programming language&amp;nbsp;into machine code for some computer architecture.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;The generated machine code can be later executed many times against different data each time.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;It writes the text into a format that the CPU can understand&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;This is a kind of system software&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/21/03/F1_Lalita%20V_20-2-2021_Swati_D5.png&quot; style=&quot;width: 370px; height: 135px;&quot; /&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Operating system:&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;An operating system is a&amp;nbsp; system software&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;It is an interface between the computer, user, and the hardware&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(0, 0, 0); text-align: justify;&quot;&gt;It performs all the basic tasks like file management, memory management, process management, handling input and output, and controlling peripheral devices such as disk drives and printers&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(0, 0, 0); text-align: justify;&quot;&gt;Some of the examples of operating systems are Windows, Linux, VMS, etc.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(0, 0, 0); text-align: justify;&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/21/03/F1_Lalita%20V_20-2-2021_Swati_D6.png&quot; style=&quot;width: 350px; height: 293px;&quot; /&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(0, 0, 0); text-align: justify;&quot;&gt;&lt;strong&gt;Application software&lt;/strong&gt;:&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(0, 0, 0); text-align: justify;&quot;&gt;This software is used by the user to perform a specific task&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;It is also known as the end-user program&lt;/li&gt;
	&lt;li&gt;Application software programs are&amp;nbsp;&lt;span style=&quot;color: rgb(0, 0, 0);  &quot;&gt;developed to assist you with a particular process that may be related to creativity, productivity, or better communication.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(0, 0, 0);  &quot;&gt;It is a non-essential software.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(17, 21, 22);  &quot;&gt;Application software runs as and when the user requests it.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(0, 0, 0);  &quot;&gt;Some of the examples of application software are, google chrome, internet explorer, VLC media, etc.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(0, 0, 0); text-align: justify;&quot;&gt;Editor:&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Enable user to create and edit text files&lt;/li&gt;
	&lt;li&gt;These are provided with operating system and software development packages&lt;/li&gt;
	&lt;li&gt;For example, Notepad, Textedit&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;Hint Point:&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The system software is used to operate computer hardware&lt;/li&gt;
	&lt;li&gt;It is an&amp;nbsp;&lt;span style=&quot;color: rgb(36, 39, 41);  &quot;&gt;interface between Application Software and hardware of the computer.&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(36, 39, 41);  &quot;&gt;The System Software is designed to manage the system resources and it also provides a platform for Application Software to run.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/confusion-points-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Confusion Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(36, 39, 41);  &quot;&gt;***Note: Based on the official answer key provided by NTA, both Option 3 and 4, Application software and editor, are correct&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;<br><br>&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/confusion-points-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Confusion Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700; &quot;&gt;***नोट: एनटीए द्वारा प्रदान की गई आधिकारिक उत्तर कुंजी के आधार पर, विकल्प 3 और 4, एप्लिकेशन सॉफ्टवेयर और एडिटर दोनों सही हैं।&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;कंपाइलर:&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;एक कंपाइलर एक प्रोग्राम है जो कुछ कंप्यूटर आर्किटेक्चर के लिए मशीन कोड में कुछ उच्च-स्तरीय प्रोग्रामिंग भाषा में लिखे गए स्रोत प्रोग्राम का अनुवाद करता है।&lt;/li&gt;
	&lt;li&gt;उत्पन्न मशीन कोड को बाद में हर बार अलग-अलग डेटा के खिलाफ कई बार निष्पादित किया जा सकता है।&lt;/li&gt;
	&lt;li&gt;यह पाठ को एक प्रारूप में लिखता है जिसे सी.पी.यू.&amp;nbsp;समझ सकता है&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;यह एक प्रकार का सिस्टम सॉफ्टवेयर है&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/21/03/F1_Lalita%20V_20-2-2021_Swati_D5.png&quot; style=&quot;width: 370px; height: 135px;&quot; /&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;ऑपरेटिंग सिस्टम:&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;एक ऑपरेटिंग सिस्टम एक सिस्टम सॉफ्टवेयर है।&amp;nbsp;&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;यह कंप्यूटर, उपयोगकर्ता और हार्डवेयर के बीच का एक इंटरफेस है।&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;यह फ़ाइल प्रबंधन, मेमोरी प्रबंधन, प्रक्रिया प्रबंधन, इनपुट और आउटपुट का संचालन&amp;nbsp;और परिधीय उपकरणों को नियंत्रित करना जैसे कि डिस्क ड्राइव और प्रिंटर जैसे सभी बुनियादी कार्यों को करता है।&lt;/li&gt;
	&lt;li&gt;ऑपरेटिंग सिस्टम के कुछ उदाहरण विंडोज, लिनक्स, वीएमएस आदि हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/21/03/F1_Lalita%20V_20-2-2021_Swati_D6.png&quot; style=&quot;color: rgb(0, 0, 0); text-align: justify; width: 350px; height: 293px;&quot; /&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(0, 0, 0); text-align: justify;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;एप्लीकेशन&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सॉफ्टवेयर&lt;/span&gt;&lt;span style=&quot;color: rgb(0, 0, 0); text-align: justify;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt; &lt;/span&gt;:&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;इस सॉफ्टवेयर का उपयोग उपयोगकर्ता द्वारा किसी विशिष्ट कार्य को करने के लिए किया जाता है।&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;इसे एंड-यूज़र प्रोग्राम के रूप में भी जाना जाता है।&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;एप्लिकेशन सॉफ़्टवेयर प्रोग्राम एक विशेष प्रक्रिया के साथ आपकी सहायता करने के लिए विकसित किए जाते हैं जो रचनात्मकता, उत्पादकता या बेहतर संचार से संबंधित हो सकते हैं।&lt;/li&gt;
	&lt;li&gt;यह एक अनावश्यक&amp;nbsp;सॉफ्टवेयर है।&lt;/li&gt;
	&lt;li&gt;एप्लिकेशन सॉफ़्टवेयर तब चलता है जब उपयोगकर्ता इसका अनुरोध करता है।&lt;/li&gt;
	&lt;li&gt;एप्लीकेशन सॉफ्टवेयर के कुछ उदाहरण, गुगल क्रोम, इंटरनेट एक्सप्लोरर, वी.एल.सी. मीडिया, आदि है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;color: rgb(0, 0, 0); text-align: justify;&quot;&gt;एडिटर:&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;लिखित फ़ाइलों को बनाने और संपादित करने के लिए उपयोगकर्ता को सक्षम करें&lt;/li&gt;
	&lt;li&gt;ये ऑपरेटिंग सिस्टम और सॉफ्टवेयर डेवलपमेंट पैकेज के साथ दिए गए हैं&lt;br /&gt;
	उदाहरण के लिए, नोटपैड, टेक्स्टडिट&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;संकेत बिंदु&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;:&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;कंप्यूटर हार्डवेयर को संचालित करने के लिए सिस्टम सॉफ्टवेयर का उपयोग किया जाता है&lt;/li&gt;
	&lt;li&gt;यह एप्लीकेशन&amp;nbsp;सॉफ़्टवेयर और कंप्यूटर के हार्डवेयर के बीच का इंटरफ़ेस है।&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;सिस्टम सॉफ्टवेयर सिस्टम संसाधनों के प्रबंधन के लिए बनाया गया है और यह एप्लिकेशन सॉफ्टवेयर को चलाने के लिए एक मंच भी प्रदान करता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&amp;lsquo;The Jataka&amp;rsquo;, related to Buddhism, refers to &lt;strong&gt;&lt;u&gt;stories of Buddha&amp;rsquo;s Birth.&lt;/u&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Jataka in Pali and Sanskrit means &lt;strong&gt;Birth&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;A Buddhist scholar, &lt;strong&gt;Buddhagosa&lt;/strong&gt; is said to have gathered about 550 Jataka stories.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;Note:&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Buddhism&lt;/span&gt;&amp;nbsp;is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;World&amp;#39;s fourth-largest religion&lt;/span&gt;&amp;nbsp;and its followers are known as&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Buddhists.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;Buddhist traditions have the goal of&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;overcoming worldly suffering&lt;/span&gt;&amp;nbsp;and the attainment of&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Nirvana(Enlightenment).&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;The Buddhist religion is attributed to the teachings of&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Gautama Buddha.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;बौद्ध धर्म से संबंधित &amp;#39;जातक&amp;rsquo;, &lt;u&gt;&lt;strong&gt;बुद्ध के जन्म की कहानियों&lt;/strong&gt;&lt;/u&gt; को संदर्भित करता है।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;पाली और संस्कृत में जातक का अर्थ है &lt;strong&gt;जन्म&lt;/strong&gt;।&lt;/li&gt;
	&lt;li&gt;एक बौद्ध विद्वान, &lt;strong&gt;बुद्धगोसा&lt;/strong&gt; के बारे में कहा जाता है कि उन्होंने लगभग 550 जातक कहानियों को एकत्रित किया था।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;u&gt;ध्यान दें:&lt;/u&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;बौद्ध धर्म&amp;nbsp;दुनिया का चौथा सबसे बड़ा धर्म है&amp;nbsp;&lt;/span&gt;और इसके अनुयायियों को&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;बौद्ध&amp;nbsp;&lt;/span&gt;के रूप में जाना जाता है।&lt;/li&gt;
	&lt;li&gt;बौद्ध परंपराओं&amp;nbsp;का लक्ष्य&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;पीड़ा पर काबू पाना&amp;nbsp;&lt;/span&gt;और&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;निर्वाना&amp;nbsp;(आत्मज्ञान) को प्राप्त&amp;nbsp;करना&amp;nbsp;&lt;/span&gt;है।&lt;/li&gt;
	&lt;li&gt;बौद्ध धर्म के लिए&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;गौतम बुद्ध&amp;nbsp;&lt;/span&gt;की शिक्षाएँ&amp;nbsp;जिम्मेदार हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;&lt;span style=&quot;color: (33, 37, 41);&quot;&gt;B Srinivasan&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;color: (33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;B Srinivasan has been appointed as the Director General of the National Security Guard (NSG).&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;Srinivasan is a 1992 batch Indian Police Service (IPS) officer from the Bihar cadre.&lt;/li&gt;
	&lt;li&gt;His appointment will be effective from the date of joining up to August 31, 2027.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;He succeeds Nalin Prabhat, &lt;/strong&gt;who has been deputed as Jammu and Kashmir&amp;#39;s Special Director General of Police.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Nalin Prabhat:&lt;/strong&gt; The previous Director General of NSG, who was transferred to a new role as Special Director General of Police for Jammu and Kashmir. His tenure at NSG was curtailed, and he was moved to the AGMUT cadre.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;NSG (National Security Guard):&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;A specialized counter-terrorism unit under the Ministry of Home Affairs.&lt;/li&gt;
		&lt;li&gt;The National Security Guard, commonly known as Black Cats, is a counter-terrorism unit of India.&lt;/li&gt;
		&lt;li&gt;It was founded on 16 October 1984, following Operation Blue Star against Sikh militants, to combat terrorist activities and protect states against internal disturbances.&lt;/li&gt;
		&lt;li&gt;Founded: 22 September 1986.&lt;/li&gt;
		&lt;li&gt;Motto: सर्वत्र सर्वोत्तम सुरक्षा / Omnipresent best security.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Inter-cadre Deputation:&lt;/strong&gt; Refers to the process where an IPS officer is transferred from one cadre to another for a specified period. Nalin Prabhat was transferred to the AGMUT cadre as part of this process.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;//cdn.testbook.com/images/production/quesImages/qImage6735fd8f1f351d82ba1bc620.png&quot; style=&quot;height: 282px; width: 350px;&quot; /&gt;&lt;/p&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;&lt;span style=&quot;color: (33, 37, 41);&quot;&gt;बी श्रीनिवासन&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt; है&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;color: (33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;u style=&quot;font-family: var(--bs-body-font-family); font-size: var(--bs-body-font-size); text-align: var(--bs-body-text-align);&quot;&gt;&lt;span style=&quot;font-size:24px;&quot;&gt;Key Points&lt;/span&gt;&lt;/u&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;बी श्रीनिवासन को राष्ट्रीय सुरक्षा गार्ड (NSG) का महानिदेशक नियुक्त किया गया है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;श्रीनिवासन बिहार कैडर के 1992 बैच के भारतीय पुलिस सेवा (IPS) अधिकारी हैं।&lt;/li&gt;
	&lt;li&gt;उनकी नियुक्ति 31 अगस्त, 2027 तक, कार्यभार ग्रहण करने की तिथि से प्रभावी होगी।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;वे नलिन प्रभात का स्थान लेंगे,&lt;/strong&gt; जिन्हें जम्मू और कश्मीर का विशेष पुलिस महानिदेशक नियुक्त किया गया है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;u style=&quot;font-family: var(--bs-body-font-family); font-size: var(--bs-body-font-size); text-align: var(--bs-body-text-align); font-weight: 700;&quot;&gt;&lt;span style=&quot;font-size:26px;&quot;&gt;Additional Information&lt;/span&gt;&lt;/u&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;नलिन प्रभात:&lt;/strong&gt; NSG के पूर्व महानिदेशक, जिन्हें जम्मू और कश्मीर के लिए विशेष पुलिस महानिदेशक की नई भूमिका में स्थानांतरित किया गया था। NSG में उनका कार्यकाल कम कर दिया गया था, और उन्हें AGMUT कैडर में स्थानांतरित कर दिया गया था।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;NSG (राष्ट्रीय सुरक्षा गार्ड):&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;गृह मंत्रालय के अधीन एक विशेष आतंकवाद विरोधी इकाई।&lt;/li&gt;
		&lt;li&gt;राष्ट्रीय सुरक्षा गार्ड, जिसे आमतौर पर ब्लैक कैट्स के रूप में जाना जाता है, भारत की एक काउंटर-आतंकवाद इकाई है।&lt;/li&gt;
		&lt;li&gt;यह 16 अक्टूबर 1984 को, सिख उग्रवादी के खिलाफ ऑपरेशन ब्लू स्टार के बाद, आतंकवादी गतिविधियों का मुकाबला करने और आंतरिक अशांति से राज्यों की रक्षा के लिए स्थापित किया गया था।&lt;/li&gt;
		&lt;li&gt;स्थापना: 22 सितंबर 1986।&lt;/li&gt;
		&lt;li&gt;सूत्र: सर्वत्र सर्वोत्तम सुरक्षा / सर्वव्यापी सर्वोत्तम सुरक्षा।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;अंतर-कैडर प्रतिनियुक्ति:&lt;/strong&gt; एक IPS अधिकारी को एक निश्चित अवधि के लिए एक कैडर से दूसरे कैडर में स्थानांतरित करने की प्रक्रिया को संदर्भित करता है। नलिन प्रभात को इस प्रक्रिया के तहत AGMUT कैडर में स्थानांतरित किया गया था।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;//cdn.testbook.com/images/production/quesImages/qImage6735fd8f1f351d82ba1bc620.png&quot; style=&quot;color: rgb(33, 37, 41); height: 282px; width: 350px;&quot; /&gt;&lt;/p&gt;

&lt;p&gt;An &lt;strong&gt;intelligent sharing of power among a legislature, executive and judiciary&lt;/strong&gt; are very important to the design of democracy. Most common arrangements that we have or will come across.&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Power is shared among different organs of the government&lt;/strong&gt;, such as the &lt;strong&gt;legislature, executive, and judiciary&lt;/strong&gt;. This is called horizontal distribution of power because it allows different organs of the government placed at the same level to exercise different powers.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Power can be shared among governments at different levels&lt;/strong&gt; &amp;ndash; a general government for the entire country and governments at the provincial or regional level. The division of higher and lower levels of government is called the vertical division of power.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Power may also be shared among different social groups&lt;/strong&gt;, such as the religious and linguistic groups. &amp;lsquo;Community government&amp;rsquo; is a good example of this arrangement.&lt;/li&gt;
	&lt;li&gt;The power-sharing arrangement can also be seen in the way political parties, pressure groups and movements control or influence those in power.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Thus, it is clear that&amp;nbsp;&lt;strong&gt;Intelligent sharing of power is done among&amp;nbsp;Legislature, Executive and Judiciary.&lt;/strong&gt;&lt;/p&gt;<br><br>&lt;p&gt;&lt;strong&gt;एक विधायिका, कार्यपालिका और न्यायपालिका के बीच सत्ता का एक बुद्धिमान बंटवारा&lt;/strong&gt; लोकतंत्र की रूपरेखा के लिए बहुत महत्वपूर्ण होता है। अधिकांश सामान्य व्यवस्थाएं जो हमारे पास हैं या जो सामने आएंगी।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;सरकार के विभिन्न अंगों, जैसे विधायिका, कार्यपालिका और न्यायपालिका के बीच सत्ता साझा की जाती है।&lt;/strong&gt; इसे सत्ता का क्षैतिज वितरण कहा जाता है क्योंकि यह समान स्तर पर स्थित सरकार के विभिन्न अंगों को विभिन्न शक्तियों का प्रयोग करने की अनुमति देता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;सत्ता विभिन्न स्तरों पर सरकारों के बीच साझा की जा सकती है&lt;/strong&gt; - पूरे देश के लिए एक सामान्य सरकार और प्रांतीय या क्षेत्रीय स्तर पर सरकारें। सरकार के उच्च और निम्न स्तरों के विभाजन को सत्ता का ऊर्ध्वाधर विभाजन कहा जाता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;सत्ता को विभिन्न सामाजिक समूहों, जैसे कि धार्मिक और भाषाई समूहों के बीच भी साझा किया जा सकता है। &lt;/strong&gt;&amp;#39;सामुदायिक सरकार&amp;#39; इस व्यवस्था का एक अच्छा उदाहरण है।&lt;/li&gt;
	&lt;li&gt;सत्ता के बंटवारे की व्यवस्था को राजनीतिक दलों, दबाव समूहों और आंदोलनों द्वारा सत्ता में बैठे लोगों को नियंत्रित या प्रभावित करने के तरीके से भी देखा जा सकता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;इस प्रकार, यह स्पष्ट है कि&lt;strong&gt; विधायिका, कार्यपालिका और न्यायपालिका के बीच सत्ता का बुद्धिमान बंटवारा किया जाता है।&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Matanomadh, Kutch, Gujarat.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Researchers confirm the presence of jarosite in Matanomadh village of Kutch, Gujarat, similar to the discovery made on Mars.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Jarosite is a yellow mineral formed when oxygen, iron, sulphur, and potassium-rich minerals react with water, typically under volcanic conditions.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;This discovery is believed to serve as a potential field analogue for ISRO&amp;#39;s upcoming Mangalyaan-2 mission.&lt;/li&gt;
	&lt;li&gt;It was first detected on Mars by NASA&amp;rsquo;s Opportunity rover in 2004, providing evidence for the presence of water on the planet.&lt;/li&gt;
	&lt;li&gt;The jarosite in Matanomadh, dated to about 55 million years ago, closely resembles Martian geology.&lt;/li&gt;
	&lt;li&gt;Jarosite deposits have also been found in other global locations such as Mexico, Canada, Japan, Spain, and Utah, US.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Matanomadh&lt;/span&gt;&lt;/u&gt; is a village in Kutch, Gujarat, where jarosite deposits were recently discovered.&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;ISRO&amp;rsquo;s Mangalyaan-2&lt;/span&gt;&lt;/u&gt; is the upcoming Mars orbiter mission that may benefit from the findings in Matanomadh.&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;NASA&amp;rsquo;s Opportunity rover&lt;/span&gt;&lt;/u&gt; was responsible for discovering jarosite on Mars, a significant finding for the search for water.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;माता नो मढ, कच्छ, गुजरात है।&lt;/strong&gt;&lt;/u&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;span style=&quot;font-weight: 400;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;शोधकर्ताओं ने गुजरात के कच्छ के माता नो मढ गाँव में जैरोसाइट की उपस्थिति की पुष्टि की है, जो मंगल ग्रह पर की गई खोज के समान है।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;जैरोसाइट एक पीला खनिज है जो तब बनता है जब ऑक्सीजन, आयरन, सल्फर और पोटेशियम युक्त खनिज जल के साथ प्रतिक्रिया करते हैं, आमतौर पर ज्वालामुखी परिस्थितियों में।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;यह खोज ISRO के आगामी मंगलयान-2 मिशन के लिए एक संभावित क्षेत्रीय एनालॉग के रूप में काम करने के लिए मानी जाती है।&lt;/li&gt;
	&lt;li&gt;इसे पहली बार 2004 में NASA के अपॉर्च्युनिटी रोवर द्वारा मंगल ग्रह पर खोजा गया था, जिससे ग्रह पर जल की उपस्थिति का प्रमाण मिला।&lt;/li&gt;
	&lt;li&gt;माता नो मढ में जैरोसाइट, लगभग 55 मिलियन वर्ष पहले का है, जो मंगल ग्रह के भूविज्ञान से मिलता-जुलता है।&lt;/li&gt;
	&lt;li&gt;जैरोसाइट जमा अन्य वैश्विक स्थानों जैसे मेक्सिको, कनाडा, जापान, स्पेन और यूटा, अमेरिका में भी पाए गए हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;माता नो मढ&lt;/span&gt;&lt;/u&gt; कच्छ, गुजरात में एक गाँव है, जहाँ हाल ही में जैरोसाइट जमा की खोज की गई थी।&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;ISRO का मंगलयान-2&lt;/span&gt;&lt;/u&gt; आगामी मंगल परिक्रमा मिशन है जो माता नो मढ में निष्कर्षों से लाभान्वित हो सकता है।&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;NASA का अपॉर्च्युनिटी रोवर&lt;/span&gt;&lt;/u&gt; मंगल ग्रह पर जैरोसाइट की खोज के लिए जिम्मेदार था, जो जल की खोज के लिए एक महत्वपूर्ण खोज है।&lt;/li&gt;
&lt;/ul&gt;

&lt;ul&gt;
	&lt;li&gt;The Judges of the district court are&amp;nbsp;appointed by the &lt;u&gt;&lt;strong&gt;Governor&lt;/strong&gt;&lt;/u&gt;.&lt;/li&gt;
	&lt;li&gt;Under Article 233&amp;nbsp;A of the Indian constitution,&amp;nbsp;district judges&amp;nbsp;in any State shall be made by the Governor of the State in consultation with the High&amp;nbsp;Court&amp;nbsp;exercising jurisdiction in relation to such State.&lt;/li&gt;
	&lt;li&gt;
	&lt;p&gt;A person not&amp;nbsp;in the service of the State or the Union shall only be eligible to be appointed a district judge if he has been for not less than seven years an advocate or a pleader and is recommended by the High Court for the appointment.&lt;/p&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;ul&gt;
	&lt;li&gt;जिला न्यायालय के न्यायाधीश &lt;u&gt;&lt;strong&gt;राज्यपाल&lt;/strong&gt;&lt;/u&gt; द्वारा नियुक्त किए जाते हैं।&lt;/li&gt;
	&lt;li&gt;भारतीय संविधान के अनुच्छेद 233 A के तहत, किसी भी राज्य में जिला न्यायाधीश राज्य के राज्यपाल द्वारा उच्च न्यायालय के परामर्श से ऐसे राज्य के संबंध में क्षेत्राधिकार का प्रयोग करेंगे।&lt;/li&gt;
	&lt;li&gt;एक व्यक्ति जो राज्य या संघ की सेवा में नहीं है, केवल एक जिला न्यायाधीश नियुक्त होने के योग्य होगा, यदि वह कम से कम सात वर्ष से एक वकील या एक अधिवक्ता है और नियुक्ति के लिए उच्च न्यायालय द्वारा सिफारिश की गई है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is Option &lt;strong&gt;1&lt;/strong&gt; i.e.&amp;nbsp;&lt;u&gt;&lt;strong&gt;42nd amendment.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;Explanation:&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The feature of &lt;strong&gt;fundamental duties &lt;/strong&gt;was borrowed from the &lt;strong&gt;constitution of the USSR (Now Russia).&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;Fundamental duties are incorporated in the constitution by the &lt;strong&gt;42nd amendment 1976. &lt;/strong&gt;F.D was added in &lt;strong&gt;Part IV-A, article 51A &lt;/strong&gt;of the constitution.&lt;/li&gt;
	&lt;li&gt;Fundamental duties were added to the recommendation of the &lt;strong&gt;Swaran Singh committee in 1976.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;There were originally ten fundamental duties in the constitution,&lt;strong&gt; later 11th fundamental duty was added by the 86th constitutional amendment 2002&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;The 11th fundamental duty was related to free elementary &lt;strong&gt;education to children&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;List of 11 fundamental duties:&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;To abide by the constitution and respect its&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;ideals and institutions, the National flag and the National anthem.&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;To cherish and follow noble ideas that inspired the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;national struggle.&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;To protect the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;sovereignty, unity, and Integrity of India.&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;To defend the country and render national service when called&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;upon to do so.&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;To promote&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;harmony and the spirit of common brotherhood&lt;/span&gt;&amp;nbsp;amongst all the people of India transcending religious, linguistic, and regional or sectional diversities; to renounce practices derogatory to the dignity of women.&lt;/li&gt;
		&lt;li&gt;To value and preserve the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;rich heritage of our composite culture.&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;To protect and improve&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;the natural environment&lt;/span&gt;&amp;nbsp;including forests, lakes, rivers, wildlife and to have compassion for living creatures.&lt;/li&gt;
		&lt;li&gt;To develop the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;scientific temper, humanism, and the spirit of inquiry and reform.&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;To safeguard&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;public property and to abjure violence.&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;To strive towards excellence in all&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;spheres of individual and collective activity&lt;/span&gt;&amp;nbsp;so that the nation constantly rises to higher levels of endeavor and achievement.&lt;/li&gt;
		&lt;li&gt;
		&lt;p&gt;Who is a parent or guardian, to provide opportunities for&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;education to his child, or as the case may be&lt;/span&gt;, ward between the age of &lt;strong&gt;six to fourteen years.&lt;/strong&gt;&lt;span id=&quot;cke_bm_3659E&quot; style=&quot;display: none;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span id=&quot;cke_bm_3651E&quot; style=&quot;display: none;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span id=&quot;cke_bm_3643E&quot; style=&quot;display: none;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span id=&quot;cke_bm_3635E&quot; style=&quot;display: none;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span id=&quot;cke_bm_3627E&quot; style=&quot;display: none;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span id=&quot;cke_bm_3311E&quot; style=&quot;display: none;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;
		&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर विकल्प &lt;strong&gt;1&lt;/strong&gt; यानी &lt;u&gt;&lt;strong&gt;42वां संशोधन है।&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;व्याख्या:&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;मौलिक कर्तव्यों&lt;/strong&gt; की विशेषता &lt;strong&gt;यूएसएसआर (अब रूस)&lt;/strong&gt; के संविधान से उधार ली गई थी।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;मौलिक कर्तव्यों को 42वें संशोधन 1976&lt;/strong&gt; द्वारा संविधान में शामिल किया गया है &lt;strong&gt;। FD को संविधान के भाग IV-A, अनुच्छेद 51A&lt;/strong&gt; में जोड़ा गया था।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;मौलिक कर्तव्यों को 1976 में स्वर्ण सिंह समिति&lt;/strong&gt; की सिफारिश में जोड़ा गया था।&lt;/li&gt;
	&lt;li&gt;संविधान में मूल रूप से दस मौलिक कर्तव्य थे, &lt;strong&gt;बाद में 86वें संविधान संशोधन 2002 द्वारा 11वें मौलिक कर्तव्य को जोड़ा गया&lt;/strong&gt; ।&lt;/li&gt;
	&lt;li&gt;11वां मौलिक कर्तव्य &lt;strong&gt;बच्चों को निःशुल्क प्रारंभिक शिक्षा से संबंधित था&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;11 मौलिक कर्तव्यों की सूची:&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;संविधान का पालन करना और उसके &lt;span style=&quot;font-weight: 700;&quot;&gt;आदर्शों और संस्थानों, राष्ट्रीय ध्वज और राष्ट्रगान का सम्मान करना।&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;राष्ट्रीय संघर्ष को&lt;/span&gt; प्रेरित करने वाले महान विचारों को संजोना और उनका पालन करना।&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;भारत की संप्रभुता, एकता और अखंडता की&lt;/span&gt; रक्षा के लिए।&lt;/li&gt;
		&lt;li&gt;देश की रक्षा करने के लिए और ऐसा करने के लिए बुलाए जाने &lt;span style=&quot;font-weight: 700;&quot;&gt;पर राष्ट्रीय सेवा प्रदान करना।&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;भारत के सभी लोगों के बीच धार्मिक, भाषाई, और क्षेत्रीय या अनुभागीय विविधताओं से परे &lt;span style=&quot;font-weight: 700;&quot;&gt;सद्भाव और समान भाईचारे की भावना&lt;/span&gt; को बढ़ावा देना; महिलाओं के सम्मान के लिए अपमानजनक प्रथाओं का त्याग करना।&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;हमारी मिली-जुली संस्कृति&lt;/span&gt; की समृद्ध विरासत को महत्व देना और उसका संरक्षण करना।&lt;/li&gt;
		&lt;li&gt;वनों, झीलों, नदियों, वन्य जीवन सहित &lt;span style=&quot;font-weight: 700;&quot;&gt;प्राकृतिक पर्यावरण की&lt;/span&gt; रक्षा और सुधार करना और जीवित प्राणियों के प्रति दया करना।&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;वैज्ञानिक सोच, मानवतावाद और जांच और सुधार की भावना का&lt;/span&gt; विकास करना।&lt;/li&gt;
		&lt;li&gt;सार्वजनिक संपत्ति की रक्षा करना &lt;span style=&quot;font-weight: 700;&quot;&gt;और हिंसा से दूर रहना।&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;व्यक्तिगत और सामूहिक गतिविधि के&lt;/span&gt; सभी क्षेत्रों में उत्कृष्टता की दिशा में प्रयास करना ताकि राष्ट्र निरंतर प्रयास और उपलब्धि के उच्च स्तर तक पहुंचे।&lt;/li&gt;
		&lt;li&gt;
		&lt;p&gt;जो माता-पिता या अभिभावक हैं, &lt;strong&gt;छह से चौदह वर्ष&lt;/strong&gt; की आयु के बीच &lt;span style=&quot;font-weight: 700;&quot;&gt;अपने बच्चे या वार्ड, जैसा भी मामला हो, को शिक्षा के अवसर प्रदान करने के लिए।&lt;/span&gt; &lt;span id=&quot;cke_bm_3659E&quot; style=&quot;display: none;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span id=&quot;cke_bm_3651E&quot; style=&quot;display: none;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span id=&quot;cke_bm_3643E&quot; style=&quot;display: none;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span id=&quot;cke_bm_3635E&quot; style=&quot;display: none;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span id=&quot;cke_bm_3627E&quot; style=&quot;display: none;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span id=&quot;cke_bm_3311E&quot; style=&quot;display: none;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;
		&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;Odisha.&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Dalkhai dance&lt;/span&gt;&amp;nbsp;of&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Odisha&lt;/span&gt;&amp;nbsp;is usually performed to please&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Goddess Durga&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;dance Dalkai&lt;/span&gt;&amp;nbsp;originates from the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Sambalpur&amp;nbsp;&lt;/span&gt;district of&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Odisha&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Dalkhai&amp;nbsp;&lt;/span&gt;is one of the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;most popular traditional&amp;nbsp;&lt;/span&gt;folk-dance forms of&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Adivasi&amp;rsquo;s of Sambalpur.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;It is commonly&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;performed&lt;/span&gt;&amp;nbsp;at&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;festivals&lt;/span&gt;&amp;nbsp;like&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Dashahra&lt;/span&gt;,&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Bhaijiuntia&lt;/span&gt;,&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Phagun Puni&lt;/span&gt;,&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Nuakhai&lt;/span&gt;, etc.&lt;/li&gt;
	&lt;li&gt;The main&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;theme&lt;/span&gt;&amp;nbsp;of this&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;dance&lt;/span&gt;&amp;nbsp;form is&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;Radha and Krishna&lt;/span&gt;,&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Ramayana,&lt;/span&gt;&amp;nbsp;and&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Mahabharata&lt;/span&gt;.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Other important&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;Dances of Odisha:&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;Odissi Dance.&lt;/li&gt;
		&lt;li&gt;Chhau Dance.&lt;/li&gt;
		&lt;li&gt;Chaiti Ghoda.&lt;/li&gt;
		&lt;li&gt;Danda Nata.&lt;/li&gt;
		&lt;li&gt;Medha Nacha.&lt;/li&gt;
		&lt;li&gt;Changu Dance.&lt;/li&gt;
		&lt;li&gt;Karma Dance.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;ओडिशा&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;ओडिशा &lt;/strong&gt;का&lt;strong&gt; दलखाई नृत्य&lt;/strong&gt; आमतौर पर &lt;strong&gt;देवी दुर्गा &lt;/strong&gt;को प्रसन्न करने के लिए किया जाता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;दलखाई&lt;/strong&gt;&lt;strong&gt; नृत्य&lt;/strong&gt; की उत्पत्ति &lt;strong&gt;ओडिशा&lt;/strong&gt; के &lt;strong&gt;संबलपुर&lt;/strong&gt; जिले से हुई है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;दलखाई&lt;/strong&gt; &lt;strong&gt;संबलपुर के आदिवासियों&lt;/strong&gt; के &lt;strong&gt;सबसे लोकप्रिय पारंपरिक&lt;/strong&gt; लोक-नृत्य रूपों में से एक है।&lt;/li&gt;
	&lt;li&gt;यह आमतौर पर &lt;strong&gt;दशहरा, भाईजिंटिया, फागुन पुनी, नुआखाई &lt;/strong&gt;आदि&lt;strong&gt; त्योहारों पर किया जाता है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;इस &lt;strong&gt;नृत्य रूप&lt;/strong&gt; का मुख्य &lt;strong&gt;विषय&lt;/strong&gt; &lt;strong&gt;राधा और कृष्ण, रामायण और महाभारत&lt;/strong&gt; है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;ओडिशा के अन्य महत्वपूर्ण नृत्य:&lt;/strong&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;ओडिसी नृत्य&lt;/li&gt;
		&lt;li&gt;छऊ नृत्य&lt;/li&gt;
		&lt;li&gt;चैती घोडा&lt;/li&gt;
		&lt;li&gt;डंडा नाटा&lt;/li&gt;
		&lt;li&gt;मेधा नाचा&lt;/li&gt;
		&lt;li&gt;चांगू नृत्य&lt;/li&gt;
		&lt;li&gt;कर्म नृत्य&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;Exosphere&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Exosphere&lt;/span&gt;&amp;nbsp;

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;The exosphere is the uppermost region of Earth&amp;#39;s atmosphere &lt;/strong&gt;as it gradually fades into the vacuum of space.&lt;/li&gt;
		&lt;li&gt;It starts at an altitude of about 500 km and goes out to about &lt;strong&gt;10,000 km.&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;most abundantly found gas in the exosphere is Hydrogen&lt;/span&gt;&amp;nbsp;with some Helium, Carbon dioxide, and Atomic Oxygen near its base.&lt;/li&gt;
		&lt;li&gt;The temperature gradually increases through the layer.&lt;/li&gt;
		&lt;li&gt;This layer coincides with space.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;​&lt;span style=&quot;font-weight: 700;&quot;&gt;The different layers of the atmosphere are listed below:&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Thermosphere&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;The thermosphere starts just above the mesosphere and extends to 600 km (372 miles) high.&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Aurora and satellites occur in this layer.&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Mesosphere&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;The mesosphere starts just above the stratosphere and extends to 85 km (53 miles) high.&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Meteors&amp;nbsp;&lt;/span&gt;burn up in this layer.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Stratosphere&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;The stratosphere starts just above the troposphere and extends to 50 km (31 miles) high.&lt;/li&gt;
		&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;ozone layer&lt;/span&gt;, which absorbs and scatters the solar ultraviolet radiation, is in this layer.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Ionosphere&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;The ionosphere is an abundant layer of&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;electrons and ionized atoms&amp;nbsp;&lt;/span&gt;and molecules that stretches from about 48 km.&lt;/li&gt;
		&lt;li&gt;The ionosphere is a critical link in the chain of Sun-Earth interactions.&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;This region is what makes radio communications possible.&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/20/01/F1_A.B_Madhu_09.01.20_D%201.png&quot; style=&quot;width: 350px; height: 309px;&quot; /&gt;&lt;/p&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;बहिर्मंडल&lt;/span&gt;&amp;nbsp;&lt;/u&gt;है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;प्रमुख बिंदु&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;बहिर्मंडल&lt;/span&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;बहिर्मंडल&lt;/span&gt;&lt;strong&gt; पृथ्वी के वायुमंडल का सबसे ऊपरी क्षेत्र है&lt;/strong&gt; क्योंकि यह धीरे-धीरे अंतरिक्ष के निर्वात में फीका पड़ जाता है।&lt;/li&gt;
		&lt;li&gt;यह लगभग 500 किमी की ऊंचाई से शुरू होता है और लगभग &lt;strong&gt;10,000 किमी तक जाता है।&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;बहिर्मंडल में सबसे प्रचुर मात्रा में पाई जाने वाली गैस हाइड्रोजन है&lt;/span&gt; जिसके आधार के पास कुछ हीलियम, कार्बन डाइऑक्साइड और परमाणु ऑक्सीजन है।&lt;/li&gt;
		&lt;li&gt;परत के माध्यम से तापमान धीरे-धीरे बढ़ता है।&lt;/li&gt;
		&lt;li&gt;यह परत अंतरिक्ष के साथ मिल जाती&amp;nbsp;है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;अतिरिक्त जानकारी&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;वातावरण की&amp;nbsp;विभिन्न परत&amp;nbsp;नीचे सूचीबद्ध हैं:&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;बाह्य वायुमंडल&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;बाह्य वायुमंडल, &lt;span style=&quot;color: rgb(77, 81, 86); &quot;&gt;मध्यमण्डल&lt;/span&gt; के ठीक ऊपर शुरू होता है और 600 किमी (372 मील) की ऊँचाई तक फैला होता है।&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;इस परत में अरोरा और उपग्रह पाए जाते हैं।&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;मध्यमंडल&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;मध्यमंडल, समताप मंडल के ठीक ऊपर शुरू होता है और 85 किमी (53 मील) की ऊँचाई तक फैला होता है।&lt;/li&gt;
		&lt;li&gt;इस परत में &lt;span style=&quot;font-weight: 700;&quot;&gt;उल्काएं जलती हैं।&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;समताप मंडल&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;समताप मंडल, क्षोभमंडल के ठीक ऊपर शुरू होता है और 50 किमी (31 मील) की ऊँचाई तक फैला होता है।&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;ओजोन परत&lt;/span&gt;, जो सौर पराबैंगनी विकिरण को अवशोषित और बिखेरती है, इसी परत में होती है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;आयनमंडल&amp;nbsp;&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;आयनमंडल इलेक्ट्रॉनों और आयनित परमाणुओं&lt;/span&gt; और अणुओं की एक प्रचुर परत है जो लगभग 48 किमी तक फैली&amp;nbsp;है।&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;आयनमंडल&amp;nbsp;&lt;/span&gt;सूर्य-पृथ्वी की अंतःक्रियाओं की श्रृंखला में एक महत्वपूर्ण कड़ी है।&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;यही वह क्षेत्र है जो रेडियो संचार को संभव बनाता है।&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;//cdn.testbook.com/images/production/quesImages/qImage66f685d8e368f587d6fdbcc3.png&quot; style=&quot;height: 572px; width: 350px;&quot; /&gt;&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;Cultural, Political, Technological&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The triple pressures of &lt;strong&gt;commercialization, modernization, and population&lt;/strong&gt; led to the requirement of land reforms in the country.&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;The land reforms promote a triple revolution-&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Cultural Revolution-&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;The roots of uneven distribution of land lied in the discrimination and caste-based social structure. The Land Reforms took excess land from Zamindars and distributed it to the landless low cast people who usually perform beggar and forced labor. Hence it emerged as a cultural revolution.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Political Revolution-&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;It emerged as Political Revolution because in many states like Orissa and Bengal, the Land Reform became a major subject matter of election and soon it spread in other states also.&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Technological Revolution-&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;Land Reform promotes the Technological Revolution in agriculture because after Land Reforms the landless and forced labor now got land to work upon, now Zamindars and big farmers introduced tractors, thrashers, and other machines in farms to operate with minimum labor. Also, the green revolution further increased the income of farmers and the yield of crops. This further enhanced the technological revolution in small farmers also.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर&lt;u&gt;&lt;strong&gt; सांस्कृतिक, राजनीतिक, तकनीकी है।&lt;/strong&gt;&lt;/u&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;व्यावसायीकरण, आधुनिकीकरण और जनसंख्या&lt;/strong&gt; के तिहरे दबाव ने देश में भूमि सुधारों की आवश्यकता को जन्म दिया।&lt;/li&gt;
	&lt;li&gt;भूमि सुधार तिहरी क्रांति को बढ़ावा देते हैं-&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;सांस्कृतिक क्रांति-&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;भेदभाव और जाति आधारित सामाजिक संरचना में निहित भूमि के असमान वितरण की जड़ें। भूमि सुधार ने जमींदारों से अतिरिक्त भूमि ली और भूमिहीन निम्न जाति के लोगों को वितरित किया जो आमतौर पर भिखारी और जबरन श्रम करते हैं। इसलिए यह एक सांस्कृतिक क्रांति के रूप में उभरा।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;राजनीतिक क्रांति-&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;यह राजनीतिक क्रांति के रूप में उभरा क्योंकि उड़ीसा और बंगाल जैसे कई राज्यों में भूमि सुधार चुनाव का एक प्रमुख विषय बन गया है और जल्द ही यह अन्य राज्यों में भी फैल गया है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;तकनीकी क्रांति-&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;भूमि सुधार कृषि में तकनीकी क्रांति को बढ़ावा देता है क्योंकि भूमि सुधार के बाद भूमिहीन और मजबूर मजदूरों को अब काम करने के लिए जमीन मिल गई है, अब जमींदारों और बड़े किसानों ने न्यूनतम श्रम के साथ काम करने के लिए खेतों में ट्रैक्टर, थ्रेसर और अन्य मशीनें पेश कीं। साथ ही, हरित क्रांति ने किसानों की आय और फसलों की उपज में वृद्धि की। इसने छोटे किसानों में भी तकनीकी क्रांति को बढ़ाया है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;National Bank for Agriculture And Rural Development.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;National Bank for Agriculture And Rural Development&lt;/strong&gt;&lt;/u&gt; established in the year &lt;strong&gt;1982&lt;/strong&gt; on the recommendation of the Committee to Review Arrangements for Institutional Credit for Agriculture and Rural Development (CRAFICARD) committee headed by B. Sivaraman.&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;NABARD is an &lt;strong&gt;apex development bank&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;The major functions of NABARD include the promotion and development of agriculture and rural development through credit support.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;NABARD&lt;/strong&gt; is the &lt;strong&gt;supervisory&amp;nbsp;authority over RRBs&lt;/strong&gt; (Regional Rural Banks), &lt;strong&gt;Cooperative banks&lt;/strong&gt; and &lt;strong&gt;SHGs (Self Help Groups)&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;It replaced the Agricultural Credit Department (ACD) and Rural Planning and Credit Cell (RPCC) of Reserve Bank of India, and Agricultural Refinance and Development Corporation (ARDC).&lt;/li&gt;
	&lt;li&gt;It has been accredited with &amp;ldquo;matters concerning policy, planning, and operations in the field of credit for agriculture and other economic activities in rural areas in India&amp;rdquo;.&lt;/li&gt;
	&lt;li&gt;The &lt;strong&gt;Reserve Bank of India (RBI) recently sold its entire stakes in the National Bank for Agriculture &amp;amp; Rural Development (NABARD)&lt;/strong&gt; and &lt;strong&gt;National Housing Bank&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;The decision to divest its entire stake was taken based on the recommendations of the second Narasimham Committee.&lt;/li&gt;
	&lt;li&gt;The government now holds a 100 percent stake in both NHB and NABARD.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर है, अर्थात&amp;nbsp;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;नेशनल बैंक फॉर एग्रीकल्चर एंड रूरल डेवलपमेंट&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;।&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;नेशनल बैंक फॉर एग्रीकल्चर एंड रूरल डेवलपमेंट&lt;/span&gt;&lt;strong&gt; &lt;/strong&gt;&lt;/u&gt;की स्थापना वर्ष &lt;strong&gt;1982 &lt;/strong&gt;में बी. सिवरामन की अध्यक्षता में कृषि और ग्रामीण विकास के लिए संस्थागत ऋण (CRAFICARD) समिति की व्यवस्था की समीक्षा करने के लिए की गई थी।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;नाबार्ड एक &lt;strong&gt;शीर्ष विकास बैंक&lt;/strong&gt; है।&lt;/li&gt;
	&lt;li&gt;NABARD के प्रमुख कार्यों में साख&amp;nbsp;सहायता&amp;nbsp;के माध्यम से कृषि और ग्रामीण विकास का प्रचार और विकास शामिल है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;RRB&lt;/span&gt;&amp;nbsp;(क्षेत्रीय ग्रामीण बैंक), &lt;strong&gt;सहकारी बैंक &lt;/strong&gt;और &lt;span style=&quot;font-weight: 700;&quot;&gt;SHG&lt;/span&gt;&amp;nbsp;&lt;strong&gt;(स्वयं सहायता समूह)&lt;/strong&gt; पर नाबार्ड &lt;strong&gt;पर्यवेक्षी प्राधिकरण है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;इसने भारतीय रिजर्व बैंक और कृषि पुनर्वित्त और विकास निगम (ARDC) के कृषि ऋण विभाग (ACD) और ग्रामीण नियोजन और साख प्रकोष्ठ (RPCC) का स्थान ले लिया।&lt;/li&gt;
	&lt;li&gt;इसे &amp;quot;भारत में ग्रामीण क्षेत्रों में कृषि और अन्य आर्थिक गतिविधियों के लिए ऋण के क्षेत्र में नीति, योजना और संचालन से संबंधित मामलों&amp;quot; से मान्यता प्राप्त है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;भारतीय रिजर्व बैंक (RBI) ने हाल ही में नेशनल बैंक फॉर एग्रीकल्चर एंड रूरल डेवलपमेंट&lt;/strong&gt;&lt;strong&gt; (NABARD) &lt;/strong&gt;और &lt;strong&gt;राष्ट्रीय आवास बैंक में अपने पूरे शेयर बेचे हैं।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;इसकी पूरी हिस्सेदारी को विभाजित करने का निर्णय दूसरी नरसिम्हम समिति की सिफारिशों के आधार पर लिया गया था।&lt;/li&gt;
	&lt;li&gt;सरकार अब NHB और NABARD दोनों में 100 प्रतिशत हिस्सेदारी रखती है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;Jupiter.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The gas giants of our solar system are &lt;strong&gt;Jupiter, Saturn, Uranus, and Neptune&lt;/strong&gt;.

	&lt;ul&gt;
		&lt;li&gt;These four large planets, also called &lt;strong&gt;jovian planets after Jupiter, reside in the outer part of the solar system past the orbits of Mars and the asteroid belt.&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;A gas giant is a large planet mostly composed of helium and/or hydrogen.
	&lt;ul&gt;
		&lt;li&gt;These planets, like Jupiter and Saturn in our solar system, don&amp;#39;t have hard surfaces and instead have swirling gases above a solid core.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;The planet is any of the large bodies that orbit the Sun, including Mercury, Venus, Earth, Mars, Jupiter, Saturn, Uranus, and Neptune, in the order of closeness to the Sun.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर&amp;nbsp;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;बृहस्पति&lt;/span&gt;&lt;/u&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;हमारे सौर मंडल के गैस दिग्गज &lt;strong&gt;बृहस्पति, शनि, यूरेनस और नेपच्यून हैं&lt;/strong&gt;।

	&lt;ul&gt;
		&lt;li&gt;ये चार बड़े ग्रह, जिन्हें &lt;strong&gt;बृहस्पति के बाद जोवियन ग्रह भी कहा जाता है, मंगल की कक्षाओं और क्षुद्रग्रह बेल्ट के पीछे सौर मंडल के बाहरी हिस्से में रहते हैं।&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;एक &lt;span style=&quot;display: none;&quot;&gt;&amp;nbsp;&lt;/span&gt;गैस विशाल&lt;span style=&quot;display: none;&quot;&gt;&amp;nbsp;&lt;/span&gt; एक बड़ा ग्रह है जो ज्यादातर हीलियम और / या हाइड्रोजन से बना है।

	&lt;ul&gt;
		&lt;li&gt;हमारे सौर मंडल में बृहस्पति और शनि जैसे ग्रहों की सतह कठोर नहीं है और इसके बजाय एक ठोस कोर के ऊपर गैसें घूमती हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;ग्रह सूर्य के निकटता के क्रम में बुध, शुक्र, पृथ्वी, मंगल, बृहस्पति, शनि, यूरेनस और नेप्च्यून सहित सूर्य की परिक्रमा करने वाले बड़े पिंडों में से कोई भी है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;15&lt;sup&gt;th&lt;/sup&gt;&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&amp;nbsp;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;Droupadi Murmu&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;​Droupadi Murmu &lt;/strong&gt;was elected the &lt;strong&gt;15&lt;/strong&gt;&lt;sup&gt;&lt;strong&gt;th&lt;/strong&gt;&amp;nbsp;&lt;/sup&gt;President of India.&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;Since&lt;strong&gt; July 25, 2022&lt;/strong&gt;, &lt;strong&gt;Droupadi Murmu&lt;/strong&gt;, also known as &lt;strong&gt;Puti Biranchi Tudu&lt;/strong&gt;, has held the office of India&amp;#39;s &lt;strong&gt;15th&lt;/strong&gt; president.&lt;/li&gt;
		&lt;li&gt;She was born on&lt;strong&gt; June 20, 1958&lt;/strong&gt;. After &lt;strong&gt;Pratibha Patil&lt;/strong&gt;, she is the second woman to hold the position and the first member of a tribal community to do so.&lt;/li&gt;
		&lt;li&gt;Along with being the first President born in&lt;strong&gt; Independent India&lt;/strong&gt;, she is also the youngest person to hold the position.&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&amp;nbsp;On &lt;strong&gt;June 20, 1958&lt;/strong&gt;, &lt;strong&gt;Droupadi Murmu&lt;/strong&gt; was born to a &lt;strong&gt;Santali &lt;/strong&gt;family in the village of &lt;strong&gt;Uparbeda&lt;/strong&gt; in the &lt;strong&gt;Rairangpur&lt;/strong&gt;, &lt;strong&gt;Odisha&lt;/strong&gt;, neighborhood of &lt;strong&gt;Baidaposi&lt;/strong&gt;. &lt;strong&gt;Biranchi Narayan Tudu&lt;/strong&gt;, her father, was a farmer.&lt;/li&gt;
	&lt;li&gt;Her father and grandfather served as the local council&amp;#39;s traditional leaders, or &lt;strong&gt;Sarpanch &lt;/strong&gt;(Gram Panchayat).&lt;/li&gt;
	&lt;li&gt;They gave her the name&lt;strong&gt; Puti Tudu&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;Her teacher changed her name from&lt;strong&gt; Durpadi to Droupadi&lt;/strong&gt;, and she had previously gone by the names &lt;strong&gt;Dorpdi &lt;/strong&gt;and &lt;strong&gt;Durpadi&lt;/strong&gt;.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;15वां&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&amp;nbsp;&lt;strong&gt;द्रौपदी मुर्मू&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;द्रौपदी मुर्मू&lt;/strong&gt; देश के &lt;strong&gt;15 वी&lt;/strong&gt;&amp;nbsp;राष्ट्रपति चुनी गयी।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;25 जुलाई&lt;/strong&gt; &lt;strong&gt;2022&lt;/strong&gt; से &lt;strong&gt;द्रौपदी मुर्मू&lt;/strong&gt;, जिन्हें &lt;strong&gt;पुटी बिरंची&lt;/strong&gt; &lt;strong&gt;टुडु&lt;/strong&gt; के नाम से भी जाना जाता है, ने भारत के &lt;strong&gt;15वें&lt;/strong&gt; राष्ट्रपति का पद संभाला है।&lt;/li&gt;
		&lt;li&gt;उनका जन्म &lt;strong&gt;20 जून 1958&lt;/strong&gt; को हुआ था, &lt;strong&gt;प्रतिभा पाटिल&lt;/strong&gt; के बाद, वह पद धारण करने वाली दूसरी महिला हैं और ऐसा करने वाली आदिवासी समुदाय की पहली सदस्य हैं।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;स्वतंत्र भारत&lt;/strong&gt; में पैदा होने वाली पहली राष्ट्रपति होने के साथ, वह पद धारण करने वाली सबसे कम उम्र की व्यक्ति भी हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;20 जून 1958&lt;/strong&gt; को &lt;strong&gt;द्रौपदी मुर्मू&lt;/strong&gt; का जन्म &lt;strong&gt;ओडिशा&lt;/strong&gt; के &lt;strong&gt;रायरांगपुर&lt;/strong&gt; के &lt;strong&gt;उपरबेड़ा&lt;/strong&gt; गांव में एक &lt;b&gt;संथाली&lt;/b&gt;&amp;nbsp;परिवार में हुआ था। उनके पिता &lt;strong&gt;बिरंची नारायण टुडू&lt;/strong&gt; किसान थे।&lt;/li&gt;
	&lt;li&gt;उनके पिता और दादा स्थानीय परिषद के पारंपरिक नेताओं, या &lt;strong&gt;सरपंच&lt;/strong&gt; (ग्राम पंचायत) के रूप में सेवा की।&lt;/li&gt;
	&lt;li&gt;उन्होंने उन्हे&amp;nbsp;&lt;strong&gt;पुटी टुडु&lt;/strong&gt; नाम दिया।&lt;/li&gt;
	&lt;li&gt;उनके शिक्षक ने उनका नाम &lt;strong&gt;दुरपदी&lt;/strong&gt; से बदलकर &lt;strong&gt;द्रौपदी&lt;/strong&gt; कर दिया था, और वह पहले दोरपदी और दुरपदी नाम से जानी जाती थीं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The Correct Answer is&amp;nbsp;&lt;strong&gt;&lt;u&gt;option 2.&lt;/u&gt;&lt;/strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Directive Principles of State Policy (DPSP):&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;Article 50 &lt;/strong&gt;of the Indian Constitution specifically enjoins the &lt;strong&gt;separation of the judiciary from the executive in the public services of the state&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;&lt;em&gt;&lt;strong&gt;The correct answer is option 2.&lt;/strong&gt;&lt;/em&gt;&lt;/li&gt;
		&lt;li&gt;The DPSPs,&lt;strong&gt; found in Articles 36 to 51&lt;/strong&gt;, guide the state in formulating policies and laws, but they are not enforceable by any court.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Preamble:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;The Preamble is the introduction to the Constitution and sets out the philosophy and objectives of the Constitution, but it does not specifically mention the separation of judiciary from the executive.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Seventh Schedule:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;The Seventh Schedule of the Constitution deals with the distribution of legislative powers between the Union and the States. It does not relate to the separation of powers between the judiciary and the executive.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;The &lt;strong&gt;separation of judiciary from the executive&lt;/strong&gt; is a &lt;strong&gt;fundamental feature&lt;/strong&gt; of the Constitution, aimed at maintaining the &lt;strong&gt;independence and impartiality of the judiciary.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;strong&gt;&lt;u&gt;विकल्प 2&lt;/u&gt;&lt;/strong&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;राज्य के नीति निर्देशक तत्व (DPSP):&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;भारतीय संविधान का &lt;strong&gt;अनुच्छेद 50&lt;/strong&gt; विशेष रूप से &lt;strong&gt;राज्य की सार्वजनिक सेवाओं में न्यायपालिका को कार्यपालिका से अलग करने का निर्देश देता है&lt;/strong&gt;।&lt;/li&gt;
		&lt;li&gt;&lt;em&gt;&lt;strong&gt;सही उत्तर विकल्प 2 है।&lt;/strong&gt;&lt;/em&gt;&lt;/li&gt;
		&lt;li&gt;DPSP, &lt;strong&gt;अनुच्छेद 36 से 51&lt;/strong&gt; में पाए जाते हैं, जो राज्य को नीतियां और कानून बनाने में मार्गदर्शन करते हैं, लेकिन वे किसी भी न्यायालय द्वारा लागू करने योग्य नहीं हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;प्रस्तावना:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;प्रस्तावना संविधान की प्रस्तावना है और संविधान की दर्शन और उद्देश्यों को प्रस्तुत करती है, लेकिन यह विशेष रूप से न्यायपालिका को कार्यपालिका से अलग करने का उल्लेख नहीं करती है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;सातवीं अनुसूची:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;संविधान की सातवीं अनुसूची संघ और राज्यों के बीच विधायी शक्तियों के वितरण से संबंधित है। यह न्यायपालिका और कार्यपालिका के बीच शक्तियों के पृथक्करण से संबंधित नहीं है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;न्यायपालिका और कार्यपालिका का पृथक्करण&lt;/strong&gt; संविधान की एक &lt;strong&gt;मूलभूत विशेषता&lt;/strong&gt; है, जिसका उद्देश्य न्यायपालिका की &lt;strong&gt;स्वतंत्रता और निष्पक्षता&lt;/strong&gt; बनाए रखना है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Jawaharlal Nehru&lt;/span&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;These words were given by&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;the first prime minister of India Pt Jawaharlal Nehru&lt;/span&gt;&amp;nbsp;on the eve of India&amp;#39;s Independence, towards midnight on 14 August 1947.

	&lt;ul&gt;
		&lt;li&gt;In his speech he mentioned, &amp;quot;at the stroke of midnight when the world sleeps, India will awake to life and freedom&amp;quot;.&amp;nbsp;&lt;/li&gt;
		&lt;li&gt;Pt. Jawaharlal Nehru was born in Allahabad on November 14, 1889.&lt;/li&gt;
		&lt;li&gt;The famous book&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;quot;The Discovery of India&amp;quot;&lt;/span&gt;&amp;nbsp;is written by&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Pt Jawaharlal Nehru.&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Lord Mountbatten&lt;/span&gt;&amp;nbsp;was&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;the last Viceroy&amp;nbsp;&lt;/span&gt;of India and&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;the first Governor of independent India.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Dr. Rajendra Prasad&lt;/span&gt;&amp;nbsp;was the&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;first President of India.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर&amp;nbsp;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;जवाहरलाल नेहरू&lt;/span&gt;&lt;/u&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;ये शब्द&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;भारत के प्रथम प्रधानमंत्री पं&amp;nbsp;जवाहरलाल नेहरू&amp;nbsp;&lt;/span&gt;ने भारत की स्वतंत्रता की पूर्व संध्या पर 14 अगस्त 1947 की आधी रात को दिए थे।

	&lt;ul&gt;
		&lt;li&gt;अपने भाषण में उन्होंने उल्लेख किया, &lt;strong&gt;&amp;quot;एट द स्ट्रोक ऑफ़ मिडनाइट, व्हेन द वर्ल्ड स्लीप्स, इंडिया विल अवेक टू लाइफ एंड फ्रीडम&amp;quot;।&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;पं&amp;nbsp;जवाहरलाल नेहरू का जन्म 14 नवंबर, 1889 को इलाहाबाद में हुआ था।&lt;/li&gt;
		&lt;li&gt;प्रसिद्ध पुस्तक&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;quot;द डिस्कवरी ऑफ इंडिया&amp;quot;,&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;पं&amp;nbsp;जवाहरलाल नेहरू&lt;/span&gt;&amp;nbsp;द्वारा लिखी गई है।​&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;लॉर्ड माउंटबेटन भारत के अंतिम वायसराय और स्वतंत्र भारत के पहले गवर्नर&amp;nbsp;&lt;/span&gt;थे।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;डॉ. राजेंद्र प्रसाद भारत के पहले राष्ट्रपति&lt;/span&gt;&amp;nbsp;थे।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Statutory Liquidity Ratio&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&amp;nbsp;&lt;strong&gt;Statutory Liquidity Ratio(SLR):-&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;Commercial banks provide long-term credit to the government by investing their funds in government securities and short-term finance by purchasing Treasury Bills. This comes under SLR.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Cash Reserve Ratio(CRR):-&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;CRR is a specific part of the total deposit that is held as a reserve by the commercial banks mandated by RBI.&lt;/li&gt;
		&lt;li&gt;This reserve must be reserved in cash or cash equivalent.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Liquidity Adjustment Facility&lt;/strong&gt;&lt;strong&gt;:&lt;/strong&gt;-
	&lt;ul&gt;
		&lt;li&gt;A &lt;strong&gt;liquidity adjustment facility&lt;/strong&gt; (LAF) is a tool used in monetary policy, primarily by the Reserve Bank of India (RBI) that allows banks to borrow money through repurchase agreements&amp;nbsp;or to make loans to the RBI through reverse repo agreements.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Debt Service Obligation:&lt;/strong&gt;-
	&lt;ul&gt;
		&lt;li&gt;Debt service is the cash that is required to cover the repayment of interest and principal on a debt for a particular period.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;वैधानिक तरलता अनुपात&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;वैधानिक तरलता अनुपात (एसएलआर): -&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;वाणिज्यिक बैंक सरकारी प्रतिभूतियों में अपने धन का निवेश करके और राजकोषीय&lt;span class=&quot;hin_dict_span&quot; style=&quot;background: 0px 0px rgb(255, 255, 255);   &quot;&gt;&lt;span itemprop=&quot;itemListElement&quot;&gt; (&lt;/span&gt;&lt;/span&gt;ट्रेजरी) बिलों को खरीदकर अल्पकालिक वित्त द्वारा सरकार को दीर्घकालिक ऋण प्रदान करते हैं। यह एसएलआर के अंतर्गत आता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;नकद आरक्षित अनुपात (सीआरआर): -&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;सीआरआर कुल जमा का एक विशिष्ट हिस्सा है जिसे आरबीआई द्वारा अनिवार्य वाणिज्यिक बैंकों द्वारा रिजर्व के रूप में रखा जाता है।&lt;/li&gt;
		&lt;li&gt;यह रिजर्व नकद या नकद समकक्ष में आरक्षित होना चाहिए।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;चलनिधि समायोजन सुविधा:-&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;तरलता समायोजन सुविधा&lt;/strong&gt; (एलएएफ) मौद्रिक नीति में उपयोग किया जाने वाला एक उपकरण है, मुख्य रूप से भारतीय रिजर्व बैंक (आरबीआई) द्वारा जो बैंकों को पुनर्खरीद समझौतों के माध्यम से धन उधार लेने या रिवर्स रेपो समझौतों के माध्यम से आरबीआई को ऋण देने की अनुमति देता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;ऋण सेवा दायित्व:-&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;ऋण सेवा वह नकद है, जो किसी विशेष अवधि के लिए ऋण पर ब्याज और मूलधन के पुनर्भुगतान&amp;nbsp;के लिए आवश्यक है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;width:400px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:140px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;W. C. Roentgen&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:454px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;Produced and detected electromagnetic radiation in a wavelength range known as X-rays&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:140px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;Albert Einstein&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:454px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;developed the theory of relativity, one of the two pillars of modern physics&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:140px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;Samuel Cohen&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:454px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;Father of the neutron bomb.&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:140px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;&lt;strong&gt;Edward Teller&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:454px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;&lt;strong&gt;Edward Teller was a Hungarian-American theoretical physicist, known as &amp;quot;the father of the hydrogen bomb.&amp;rdquo;&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;<br><br>&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;width:400px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;height:42px; width:149px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;डब्ल्यू. सी. रोएंटगेन&amp;nbsp;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;height:42px; width:465px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;एक तरंग दैर्ध्य रेंज में विद्युत चुम्बकीय विकिरण का उत्पादन और खोज की जिसे एक्स-किरण के रूप में जाना जाता है&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;height:31px; width:149px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;अल्बर्ट आइंस्टीन&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;height:31px; width:465px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;आधुनिक भौतिकी के दो स्तंभों में से एक, सापेक्षता के सिद्धांत का विकास किया&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;height:19px; width:149px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;सैमुअल कोहेन&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;height:19px; width:465px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;न्यूट्रॉन बम के खोजकर्ता&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;height:22px; width:149px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;&lt;strong&gt;एडवर्ड टेलर&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;height:22px; width:465px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;&lt;strong&gt;एडवर्ड टेलर एक हंगरी-अमेरिकी सैद्धांतिक भौतिक विज्ञानी थे, जिन्हें &amp;quot;हाइड्रोजन बम का जनक&amp;quot; कहा जाता था।&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;A group of states&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li id=&quot;firstHeading&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Mahajanapadas:&lt;/span&gt;​

	&lt;ul&gt;
		&lt;li&gt;The&amp;nbsp;Mahajanapadas&amp;nbsp;from Maha:&amp;nbsp;Great, and Janapada: foothold of a people were &lt;strong&gt;sixteen&amp;nbsp;kingdoms or group of states.&amp;nbsp;&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;They existed in Northern&amp;nbsp;ancient India&amp;nbsp;from the &lt;strong&gt;sixth to fourth centuries BCE during the&amp;nbsp;second urbanization&amp;nbsp;period.&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;strong&gt;Ancient&amp;nbsp;Buddhist texts&amp;nbsp;like the&amp;nbsp;Anguttara Nikaya&amp;nbsp;make frequent&lt;/strong&gt; reference to sixteen great kingdoms and republics which had developed and flourished in a belt stretching from&amp;nbsp;Gandhara&amp;nbsp;in the northwest to&amp;nbsp;Anga&amp;nbsp;in the eastern part of the&amp;nbsp;Indian subcontinent.&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;They are -&lt;strong&gt; Kashi, Kosala, Anga, Magadha, Vajji, Malla, Chedi, Vatsa, Kuru, Panchala, Machcha, Surasena, Assaka, Avanti, Gandhara and Kamboja.&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;These Mahajanpadas are &lt;strong&gt;either Monarchy or Republics (Ganasanghas).&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;The &lt;strong&gt;important Republics &lt;/strong&gt;of this period were the&lt;strong&gt; Sakyas of Kapilavastu and the Licchavis of Vaishali.&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;The important &lt;strong&gt;Monarchical Mahajanpadas of this period were Kaushambi (Vatsa), Magadha, Kosala and Avanti.&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;They included parts of the &lt;strong&gt;trans-Vindhyan&amp;nbsp;region&amp;nbsp;and all had developed prior to the rise of Buddhism&lt;/strong&gt; in India.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;&lt;span class=&quot;VIiyi&quot; lang=&quot;hi&quot;&gt;&lt;span class=&quot;JLqJ4b ChMk0b&quot; data-language-for-alternatives=&quot;hi&quot; data-language-to-translate-into=&quot;en&quot; data-phrase-index=&quot;0&quot;&gt;&lt;span&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;राज्यों का एक समूह&lt;/strong&gt;&lt;/u&gt; है।&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li id=&quot;firstHeading&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;महाजनपद:&lt;/span&gt;​

	&lt;ul&gt;
		&lt;li&gt;&lt;span class=&quot;VIiyi&quot; lang=&quot;hi&quot;&gt;&lt;span class=&quot;JLqJ4b&quot; data-language-for-alternatives=&quot;hi&quot; data-language-to-translate-into=&quot;en&quot; data-phrase-index=&quot;0&quot;&gt;&lt;span&gt;महा: महान और जनपद: लोगों के पैर रखने का स्थान, से व्युत्पन्न महाजनपद &lt;strong&gt;सोलह साम्राज्यों या राज्यों का समूह&lt;/strong&gt; था। &lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span class=&quot;VIiyi&quot; lang=&quot;hi&quot;&gt;&lt;span class=&quot;JLqJ4b&quot; data-language-for-alternatives=&quot;hi&quot; data-language-to-translate-into=&quot;en&quot; data-phrase-index=&quot;0&quot;&gt;&lt;span&gt;वे &lt;strong&gt;द्वितीय शहरीकरण अवधि के दौरान छठी से चौथी शताब्दी ईसा पूर्व तक &lt;/strong&gt;उत्तरी प्राचीन भारत में मौजूद थे। &lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;अंगुत्तर निकाय जैसे प्राचीन बौद्ध ग्रंथ सोलह महान साम्राज्यों और गणराज्यों का अक्सर उल्लेख करते हैं जो भारतीय उपमहाद्वीप के उत्तर-पश्चिम में गांधार से लेकर पूर्वी भाग में अंग तक फैले एक क्षेत्र में विकसित हुए और फले-फूले थे।&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span class=&quot;VIiyi&quot; lang=&quot;hi&quot;&gt;&lt;span class=&quot;JLqJ4b&quot; data-language-for-alternatives=&quot;hi&quot; data-language-to-translate-into=&quot;en&quot; data-phrase-index=&quot;0&quot;&gt;&lt;span&gt;वे हैं - &lt;strong&gt;काशी, कोसल, अंग, मगध, वज्जी, मल्ल, चेदि, वत्स, कुरु, पांचाल, मच्छ, सुरसेन, असका, अवंती, गांधार और कम्बोज।&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span class=&quot;VIiyi&quot; lang=&quot;hi&quot;&gt;&lt;span class=&quot;JLqJ4b&quot; data-language-for-alternatives=&quot;hi&quot; data-language-to-translate-into=&quot;en&quot; data-phrase-index=&quot;0&quot;&gt;&lt;span&gt;ये महाजनपद &lt;strong&gt;या तो राजशाही या गणराज्य (गणसंघ) &lt;/strong&gt;हैं।&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span class=&quot;VIiyi&quot; lang=&quot;hi&quot;&gt;&lt;span class=&quot;JLqJ4b&quot; data-language-for-alternatives=&quot;hi&quot; data-language-to-translate-into=&quot;en&quot; data-phrase-index=&quot;0&quot;&gt;&lt;span&gt;इस अवधि के &lt;strong&gt;महत्वपूर्ण गणराज्य&lt;/strong&gt; &lt;strong&gt;कपिलवस्तु के शाक्य और वैशाली के लिच्छवी&lt;/strong&gt; थे। &lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span class=&quot;VIiyi&quot; lang=&quot;hi&quot;&gt;&lt;span class=&quot;JLqJ4b&quot; data-language-for-alternatives=&quot;hi&quot; data-language-to-translate-into=&quot;en&quot; data-phrase-index=&quot;0&quot;&gt;&lt;span&gt;&lt;strong&gt;इस अवधि&lt;/strong&gt; के महत्वपूर्ण&lt;strong&gt; राजशाही महाजनपद कौशाम्बी (वत्स), मगध, कोसल और अवंती&lt;/strong&gt; थे। &lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;उनमें &lt;strong&gt;ट्रांस-विंध्य क्षेत्र के&lt;/strong&gt; कुछ हिस्से शामिल थे और भारत में &lt;strong&gt;सभी बौद्ध धर्म के उदय से पहले विकसित हुए थे।&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp; &lt;u&gt;&lt;strong&gt;VD Savarkar&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Abhinav Bharat secret society was organised by VD Savarkar in &lt;strong&gt;1904&lt;/strong&gt;.

	&lt;ul&gt;
		&lt;li&gt;It was founded by &lt;strong&gt;V D Savarkar&lt;/strong&gt; and his brother Ganesh Damodar Savarkar.&lt;/li&gt;
		&lt;li&gt;The society believed in the &lt;strong&gt;armed rebellion &lt;/strong&gt;which carried out a few assassinations of British officials.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;About Veer Savarkar:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;​VD Savarkar or Vinayak Damodar Savarkar&lt;/strong&gt; was born on May 28, 1883, in Bhagur, a village near Nashik in Maharashtra.&lt;/li&gt;
		&lt;li&gt;Savarkar was associated with the &lt;strong&gt;India House&lt;/strong&gt; and founded student societies like the&lt;strong&gt; Abhinav Bharat Society&lt;/strong&gt; and the&lt;strong&gt; Free India Society&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;Veer Savarkar was a freedom fighter, politician, lawyer, writer, social reformer, and formulator of the Hindutva philosophy.&lt;/li&gt;
		&lt;li&gt;The airport at &lt;strong&gt;Port Blair &lt;/strong&gt;in Andaman and Nicobar&amp;#39;s capital was renamed &lt;strong&gt;Veer Savarkar International Airport&lt;/strong&gt; in 2002.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;
&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Khudiram Bose &lt;/strong&gt;was part of&lt;strong&gt; Anushilan Samiti&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Shyamji Krishna Verma&amp;nbsp;&lt;/strong&gt;founded the Indian Home Rule Society, India House, and The Indian Sociologist in London.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Lala Hardayal &lt;/strong&gt;founded the &lt;strong&gt;Ghadar movement&lt;/strong&gt;.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;वी.डी. सावरकर&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;अभिनव भारत नामक गुप्त &lt;span style=&quot;&quot;&gt;संगठन&amp;nbsp;&lt;/span&gt; का निर्माण&amp;nbsp;वीडी सावरकर ने &lt;strong&gt;1904 &lt;/strong&gt;में किया था।

	&lt;ul&gt;
		&lt;li&gt;इसकी स्थापना &lt;strong&gt;वी. डी. सावरकर&lt;/strong&gt; और उनके भाई गणेश दामोदर सावरकर ने की थी।&lt;/li&gt;
		&lt;li&gt;संगठन&amp;nbsp;&lt;strong&gt;सशस्त्र विद्रोह &lt;/strong&gt;में विश्वास करता था जो &lt;span style=&quot;&quot;&gt;कुछ&amp;nbsp;&lt;/span&gt;&amp;nbsp;ब्रिटिश अधिकारियों की हत्याओं को अंजाम देता था।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;वी.डी. सावरकर के बारे में:
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;वी.डी. सावरकर या विनायक दामोदर सावरकर&lt;/strong&gt; का जन्म 28 मई, 1883 को महाराष्ट्र के नासिक के पास भगुर में हुआ था।&lt;/li&gt;
		&lt;li&gt;सावरकर &lt;strong&gt;इंडिया हाउस &lt;/strong&gt;से जुड़े थे और अभिनव भारत तथा&amp;nbsp;फ्री इंडिया &lt;span style=&quot;&quot;&gt;संगठन&lt;/span&gt; जैसे छात्र &lt;span style=&quot;&quot;&gt;संगठनों&lt;/span&gt;&amp;nbsp;की स्थापना की।&lt;/li&gt;
		&lt;li&gt;
		&lt;div class=&quot;gtx-body&quot; style=&quot;display: inline;  margin: 5px auto; padding: 5px 0px; &quot;&gt;वीर सावरकर एक स्वतंत्रता सेनानी, राजनीतिज्ञ, वकील, लेखक, समाज सुधारक और हिंदुत्व दर्शन के सूत्रधार थे।&lt;/div&gt;
		&lt;/li&gt;
		&lt;li&gt;
		&lt;div class=&quot;gtx-body&quot; style=&quot;display: inline;  margin: 5px auto; padding: 5px 0px; &quot;&gt;अंडमान और निकोबार की राजधानी&amp;nbsp;&lt;strong&gt;पोर्ट ब्लेयर&lt;/strong&gt; के हवाई अड्डे का नाम बदलकर 2002 में &lt;strong&gt;वीर सावरकर अंतर्राष्ट्रीय हवाई अड्डा &lt;/strong&gt;रखा गया।&lt;/div&gt;
		&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;
&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;खुदीराम बोस अनुशीलन समिति&lt;/strong&gt; का हिस्सा थे।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;श्यामजी कृष्ण वर्मा&lt;/strong&gt; ने लंदन में इंडियन होम रूल सोसाइटी, इंडिया हाउस और द इंडियन सोशियोलॉजिस्ट की स्थापना की।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;लाला हरदयाल&lt;/strong&gt; ने &lt;strong&gt;ग़दर आंदोलन&lt;/strong&gt; की स्थापना की।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;option 4&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The Buland Darwaza (meaning &amp;quot;Gate of Magnificence&amp;quot;) was built by Emperor Akbar in 1575 at Fatehpur Sikri. &lt;em&gt;&lt;strong&gt;Hemce, option 4 is correct.&lt;/strong&gt;&lt;/em&gt;&lt;/li&gt;
	&lt;li&gt;It was constructed to commemorate Akbar&amp;#39;s victory over Gujarat in 1573.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Location: &lt;/strong&gt;Fatehpur Sikri, Uttar Pradesh&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Height: &lt;/strong&gt;Approximately 54 meters, making it one of the tallest gateways in the world&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Architectural Style: &lt;/strong&gt;Mughal architecture with red sandstone and marble inlays&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Inscriptions:&lt;/strong&gt; Includes Persian inscriptions praising Akbar and Islamic teachings&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;विकल्प 4&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;बुलंद दरवाज़ा (&amp;quot;महिमा का द्वार&amp;quot; अर्थ) सम्राट अकबर द्वारा 1575 में फतेहपुर सीकरी में बनवाया गया था। &lt;em&gt;&lt;strong&gt;इसलिए, विकल्प 4 सही है।&lt;/strong&gt;&lt;/em&gt;&lt;/li&gt;
	&lt;li&gt;इसका निर्माण 1573 में गुजरात पर अकबर की विजय के उपलक्ष्य में किया गया था।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;स्थान:&lt;/strong&gt; फतेहपुर सीकरी, उत्तर प्रदेश&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;ऊँचाई:&lt;/strong&gt; लगभग 54 मीटर, जो इसे दुनिया के सबसे ऊँचे द्वारों में से एक बनाता है&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;वास्तुशिल्प शैली:&lt;/strong&gt; लाल बलुआ पत्थर और संगमरमर की जड़ाई के साथ मुगल वास्तुकला&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;शिलालेख:&lt;/strong&gt; इसमें अकबर और इस्लामी शिक्षाओं की प्रशंसा करने वाले फ़ारसी शिलालेख शामिल हैं&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The Correct answer is &lt;u&gt;&lt;strong&gt;Bhopal&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color: (33, 37, 41);&quot;&gt;
	&lt;li&gt;The &lt;strong&gt;Bhopal&lt;/strong&gt; disaster, also known as the &lt;strong&gt;Bhopal gas tragedy&lt;/strong&gt;, occurred in December 1984.&lt;/li&gt;
	&lt;li&gt;It happened at the &lt;strong&gt;Union Carbide India Limited (UCIL) pesticide plant&lt;/strong&gt; in Bhopal, Madhya Pradesh.&lt;/li&gt;
	&lt;li&gt;A leak of &lt;strong&gt;methyl isocyanate (MIC) gas&lt;/strong&gt; and other chemicals resulted in a highly toxic cloud.&lt;/li&gt;
	&lt;li&gt;The disaster led to the immediate deaths of thousands of people and long-term health issues for many more.&lt;/li&gt;
	&lt;li&gt;The Bhopal gas tragedy is often referred to as one of the world&amp;#39;s &lt;strong&gt;worst industrial disasters&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;The incident highlighted the need for &lt;strong&gt;strict industrial safety standards&lt;/strong&gt; and &lt;strong&gt;emergency preparedness&lt;/strong&gt;.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&amp;nbsp;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Hyderabad&lt;/strong&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;Hyderabad&lt;/strong&gt; is the capital city of the southern Indian state of &lt;strong&gt;Telangana&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;It is known for its &lt;strong&gt;historical sites&lt;/strong&gt; like the &lt;strong&gt;Charminar&lt;/strong&gt; and &lt;strong&gt;Golconda Fort&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;Hyderabad is also a major center for the &lt;strong&gt;technology industry&lt;/strong&gt; in India, often referred to as &lt;strong&gt;Cyberabad&lt;/strong&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Patna&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;Patna&lt;/strong&gt; is the capital city of the Indian state of &lt;strong&gt;Bihar&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;It is one of the oldest continuously inhabited places in the world.&lt;/li&gt;
		&lt;li&gt;Historically known as &lt;strong&gt;Pataliputra&lt;/strong&gt;, it was a significant city in ancient India.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Nagpur&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;Nagpur&lt;/strong&gt; is a major city in the Indian state of &lt;strong&gt;Maharashtra&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;It is known for being the &lt;strong&gt;geographical center of India&lt;/strong&gt;, marked by the &lt;strong&gt;Zero Mile Stone&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;Nagpur is also famous for its production of &lt;strong&gt;oranges&lt;/strong&gt;, earning it the nickname &lt;strong&gt;Orange City&lt;/strong&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;भोपाल&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color: (33, 37, 41);&quot;&gt;
	&lt;li&gt;&lt;strong&gt;भोपाल&lt;/strong&gt; गैस त्रासदी, जिसे &lt;strong&gt;भोपाल गैस दुर्घटना&lt;/strong&gt; के रूप में भी जाना जाता है, दिसंबर 1984 में हुई थी।&lt;/li&gt;
	&lt;li&gt;यह मध्य प्रदेश के भोपाल में &lt;strong&gt;यूनियन कार्बाइड इंडिया लिमिटेड (UCIL) की कीटनाशक संयंत्र&lt;/strong&gt; में हुई थी।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;मिथाइल आइसोसायनेट (MIC) गैस&lt;/strong&gt; और अन्य रसायनों के रिसाव के परिणामस्वरूप एक अत्यधिक विषाक्त बादल बना।&lt;/li&gt;
	&lt;li&gt;इस दुर्घटना के कारण हजारों लोगों की तत्काल मृत्यु हो गई और कई और लोगों को लंबे समय तक स्वास्थ्य समस्याओं का सामना करना पड़ा।&lt;/li&gt;
	&lt;li&gt;भोपाल गैस त्रासदी को अक्सर दुनिया की &lt;strong&gt;सबसे खराब औद्योगिक आपदाओं&lt;/strong&gt; में से एक माना जाता है।&lt;/li&gt;
	&lt;li&gt;इस घटना ने &lt;strong&gt;कड़े औद्योगिक सुरक्षा मानकों&lt;/strong&gt; और &lt;strong&gt;आपातकालीन तैयारी&lt;/strong&gt; की आवश्यकता पर प्रकाश डाला।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;हैदराबाद&lt;/strong&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;हैदराबाद&lt;/strong&gt; दक्षिण भारत के तेलंगाना राज्य की राजधानी है।&lt;/li&gt;
		&lt;li&gt;यह अपने &lt;strong&gt;ऐतिहासिक स्थलों&lt;/strong&gt; जैसे &lt;strong&gt;चारमीनार&lt;/strong&gt; और &lt;strong&gt;गोलकोंडा किला&lt;/strong&gt; के लिए जाना जाता है।&lt;/li&gt;
		&lt;li&gt;हैदराबाद भारत में &lt;strong&gt;प्रौद्योगिकी उद्योग&lt;/strong&gt; का एक प्रमुख केंद्र भी है, जिसे अक्सर &lt;strong&gt;साइबरबाद&lt;/strong&gt; कहा जाता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;पटना&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;पटना&lt;/strong&gt; भारत के बिहार राज्य की राजधानी है।&lt;/li&gt;
		&lt;li&gt;यह दुनिया के सबसे पुराने लगातार बसे हुए स्थानों में से एक है।&lt;/li&gt;
		&lt;li&gt;ऐतिहासिक रूप से &lt;strong&gt;पाटलिपुत्र&lt;/strong&gt; के रूप में जाना जाता है, यह प्राचीन भारत में एक महत्वपूर्ण शहर था।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;नागपुर&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;नागपुर&lt;/strong&gt; भारत के महाराष्ट्र राज्य का एक प्रमुख शहर है।&lt;/li&gt;
		&lt;li&gt;यह भारत का &lt;strong&gt;भौगोलिक केंद्र&lt;/strong&gt; होने के लिए जाना जाता है, जिसे &lt;strong&gt;जीरो माइल स्टोन&lt;/strong&gt; द्वारा चिह्नित किया गया है।&lt;/li&gt;
		&lt;li&gt;नागपुर अपने &lt;strong&gt;संतरे&lt;/strong&gt; के उत्पादन के लिए भी प्रसिद्ध है, जिससे इसे &lt;strong&gt;ऑरेंज सिटी&lt;/strong&gt; का उपनाम मिला है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;Marina Beach.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Marina Beach&lt;/strong&gt;&amp;nbsp;is the longest beach in India.

	&lt;ul&gt;
		&lt;li&gt;Marina beach is located&amp;nbsp;in C&lt;strong&gt;hennai, Tamil Nadu.&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;It lies along the &lt;strong&gt;Bay of Bengal.&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;Marina Beach is also the &lt;strong&gt;world&amp;rsquo;s second-longest beach.&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot; text-align: justify;&quot;&gt;The beach was&amp;nbsp;renovated by Governor &lt;strong&gt;Mountstuart Elphinstone Grant Duff &lt;/strong&gt;in the 1880s.&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;Two prominent statues of Mahatma Gandhi is situated&amp;nbsp;on the Marina beach.&lt;/li&gt;
		&lt;li&gt;Marina Beach is one of the most crowded beaches in India.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Juhu Beach&lt;/strong&gt; is located in Mumbai in Maharashtra.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Dandi Beach&lt;/strong&gt; is&amp;nbsp;located in Dandi village, Gujarat.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Puri Beach&lt;/strong&gt; is located in Puri,&amp;nbsp;Odisha.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही जवाब &lt;u&gt;&lt;strong&gt;मरीना&amp;nbsp;समुद्र तट&lt;/strong&gt;&lt;/u&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;मरीना&amp;nbsp;समुद्र तट &lt;/strong&gt;भारत का सबसे लंबा समुद्र तट है।

	&lt;ul&gt;
		&lt;li&gt;मरीना&amp;nbsp;समुद्र तट&lt;strong&gt; चेन्नई, तमिलनाडु&lt;/strong&gt; में स्थित है।&lt;/li&gt;
		&lt;li&gt;यह &lt;strong&gt;बंगाल की खाड़ी &lt;/strong&gt;के साथ स्थित है।&lt;/li&gt;
		&lt;li&gt;मरीना समुद्र तट &lt;strong&gt;विश्व का दूसरा सबसे लंबा समुद्र तट &lt;/strong&gt;भी है।&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;&quot;&gt;समुद्र तट का जीर्णोद्धार&amp;nbsp;&lt;/span&gt;1880 के दशक में गवर्नर &lt;strong&gt;माउंटस्टार्ट एल्फिंस्टन ग्रांट डफ&lt;/strong&gt; द्वारा&amp;nbsp;किया गया था।&lt;/li&gt;
		&lt;li&gt;महात्मा गांधी की दो प्रमुख प्रतिमाएं मरीना समुद्र तट पर स्थित हैं।&lt;/li&gt;
		&lt;li&gt;मरीना समुद्र तट भारत के सबसे भीड़भाड़ वाले समुद्र तटों में से एक है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;जुहू समुद्र तट &lt;/strong&gt;महाराष्ट्र में मुंबई में स्थित है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;दांडी समुद्र तट&lt;/strong&gt;&amp;nbsp;गुजरात के दांडी गाँव में स्थित है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;पुरी समुद्र तट&lt;/strong&gt; ओडिशा के पुरी में स्थित है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Credit Cards&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;u style=&quot;font-size: 21px; font-weight: bolder; font-family: var(--bs-body-font-family); text-align: var(--bs-body-text-align);&quot;&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Credit cards are commonly referred to as &lt;strong&gt;plastic money&lt;/strong&gt; because they are made of plastic and allow users to make purchases without the need for physical cash.&lt;/li&gt;
	&lt;li&gt;They are financial instruments issued by banks or financial institutions, enabling users to borrow funds within a pre-approved credit limit.&lt;/li&gt;
	&lt;li&gt;Credit cards provide convenience, allowing users to make &lt;strong&gt;cashless transactions&lt;/strong&gt; both online and offline.&lt;/li&gt;
	&lt;li&gt;They offer additional benefits such as &lt;strong&gt;rewards points, cashback, discounts, and EMI (Equated Monthly Installment) options&lt;/strong&gt;, making them a preferred mode of payment for many.&lt;/li&gt;
	&lt;li&gt;Unlike debit cards, credit cards allow users to pay for purchases later, offering a short-term credit period without interest, provided the balance is paid in full by the due date.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Fixed Deposit (Option 1):&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;A fixed deposit (FD) is a financial instrument offered by banks where a fixed sum of money is deposited for a specific tenure to earn guaranteed interest.&lt;/li&gt;
		&lt;li&gt;Fixed deposits are not cashless transaction tools but are primarily savings instruments.&lt;/li&gt;
		&lt;li&gt;The interest rate on an FD is higher than a standard savings account, and premature withdrawal may attract a penalty.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Bearer Cheques (Option 3):&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;A bearer cheque is a type of cheque that is payable to the person presenting it at the bank, regardless of the name written on the cheque.&lt;/li&gt;
		&lt;li&gt;It is a physical document and cannot be classified as plastic money or a cashless payment method.&lt;/li&gt;
		&lt;li&gt;Bearer cheques are prone to misuse if lost or stolen as anyone holding the cheque can encash it.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Demand Drafts (Option 4):&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;A demand draft (DD) is a prepaid negotiable instrument issued by a bank, guaranteeing payment to the specified payee.&lt;/li&gt;
		&lt;li&gt;Unlike credit cards, demand drafts require the payer to deposit funds in advance and are used for secure, large transactions.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Plastic Money:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;Plastic money refers to credit cards, debit cards, prepaid cards, and other similar financial tools made of plastic that enable cashless transactions.&lt;/li&gt;
		&lt;li&gt;It has gained immense popularity due to its convenience, security, and ability to support digital transactions in an increasingly cashless economy.&lt;/li&gt;
		&lt;li&gt;Plastic money has significantly contributed to the global push toward digitalization and financial inclusion.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;क्रेडिट कार्ड&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&amp;nbsp;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;क्रेडिट कार्ड को आमतौर पर &lt;strong&gt;प्लास्टिक मनी&lt;/strong&gt; कहा जाता है क्योंकि वे प्लास्टिक से बने होते हैं और उपयोगकर्ताओं को भौतिक नकदी की आवश्यकता के बिना खरीदारी करने की अनुमति देते हैं।&lt;/li&gt;
	&lt;li&gt;वे बैंकों या वित्तीय संस्थानों द्वारा जारी किए गए वित्तीय साधन हैं, जो उपयोगकर्ताओं को पूर्व-अनुमोदित क्रेडिट सीमा के भीतर धन उधार लेने में सक्षम बनाते हैं।&lt;/li&gt;
	&lt;li&gt;क्रेडिट कार्ड सुविधा प्रदान करते हैं, जिससे उपयोगकर्ता ऑनलाइन और ऑफलाइन दोनों जगह &lt;strong&gt;कैशलेस लेनदेन&lt;/strong&gt; कर सकते हैं।&lt;/li&gt;
	&lt;li&gt;वे अतिरिक्त लाभ प्रदान करते हैं जैसे कि &lt;strong&gt;रिवॉर्ड पॉइंट, कैशबैक, छूट और EMI&amp;nbsp; (इक्वेटेड मंथली इन्सटॉलमेंट) विकल्प&lt;/strong&gt;, जो उन्हें कई लोगों के लिए भुगतान का पसंदीदा तरीका बनाते हैं।&lt;/li&gt;
	&lt;li&gt;डेबिट कार्ड के विपरीत, क्रेडिट कार्ड उपयोगकर्ताओं को बाद में खरीदारी के लिए भुगतान करने की अनुमति देते हैं, बिना ब्याज के एक छोटी अवधि के लिए क्रेडिट प्रदान करते हैं, बशर्ते कि नियत तारीख तक शेष राशि का पूरा भुगतान कर दिया जाए।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;सावधि जमा (विकल्प 1):&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;फिक्स्ड डिपाजिट&amp;nbsp;(FD) बैंकों द्वारा दिया जाने वाला एक वित्तीय साधन है जहां गारंटीड ब्याज अर्जित करने के लिए एक विशिष्ट अवधि के लिए एक निश्चित राशि जमा की जाती है।&lt;/li&gt;
		&lt;li&gt;सावधि जमा कैशलेस लेनदेन उपकरण नहीं हैं, बल्कि मुख्य रूप से बचत उपकरण हैं।&lt;/li&gt;
		&lt;li&gt;FD पर ब्याज दर एक मानक बचत खाते से अधिक है, और समय से पहले निकासी पर जुर्माना लग सकता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;वाहक चेक (विकल्प 3):&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;वाहक चेक एक प्रकार का चेक है जो बैंक में प्रस्तुत करने वाले व्यक्ति को देय होता है, भले ही चेक पर कोई भी नाम लिखा हो।&lt;/li&gt;
		&lt;li&gt;यह एक भौतिक दस्तावेज है और इसे प्लास्टिक मनी या कैशलेस भुगतान विधि के रूप में वर्गीकृत नहीं किया जा सकता है।&lt;/li&gt;
		&lt;li&gt;वाहक चेक खो जाने या चोरी हो जाने पर दुरुपयोग की संभावना होती है क्योंकि चेक रखने वाला कोई भी व्यक्ति इसे भुना सकता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;डिमांड ड्राफ्ट (विकल्प 4):&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;डिमांड ड्राफ्ट (DD) एक बैंक द्वारा जारी किया गया एक प्रीपेड नेगोशिएबल इंस्ट्रूमेंट है, जो निर्दिष्ट आदाता को भुगतान की गारंटी देता है।&lt;/li&gt;
		&lt;li&gt;क्रेडिट कार्ड के विपरीत, डिमांड ड्राफ्ट के लिए भुगतानकर्ता को अग्रिम में धन जमा करने की आवश्यकता होती है और इसका उपयोग सुरक्षित, बड़े लेनदेन के लिए किया जाता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;प्लास्टिक मनी:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;प्लास्टिक मनी क्रेडिट कार्ड, डेबिट कार्ड, प्रीपेड कार्ड और प्लास्टिक से बने अन्य समान वित्तीय उपकरणों को संदर्भित करता है जो कैशलेस लेनदेन को सक्षम करते हैं।&lt;/li&gt;
		&lt;li&gt;इसने अपनी सुविधा, सुरक्षा और तेजी से कैशलेस अर्थव्यवस्था में डिजिटल लेनदेन का समर्थन करने की क्षमता के कारण अपार लोकप्रियता हासिल की है।&lt;/li&gt;
		&lt;li&gt;प्लास्टिक मनी ने डिजिटलीकरण और वित्तीय समावेशन की दिशा में वैश्विक जोर में महत्वपूर्ण योगदान दिया है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;Kanchipuram&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The ca&lt;span id=&quot;cke_bm_7465S&quot; style=&quot;display: none;&quot;&gt;&amp;nbsp;&lt;/span&gt;pital city of the&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;Pallavas&lt;/span&gt;&amp;nbsp;was&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Kanchipuram.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;ul&gt;
	&lt;li&gt;The Pallavas emerged as a formidable power in the South around the 4th century AD and were at the height of their power in the seventh century AD.&lt;/li&gt;
	&lt;li&gt;They were able to sustain&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;their rule for about 500 years.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;They buil&lt;span id=&quot;cke_bm_7465E&quot; style=&quot;display: none;&quot;&gt;&amp;nbsp;&lt;/span&gt;t&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;great cities, centres of learning, temples, and sculptures and influenced a large part of Southeast Asia in culture.&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Simha Vishnu is considered the founder&amp;nbsp;of the Pallavas.&lt;/span&gt;

	&lt;ul&gt;
		&lt;li&gt;He put an end to the political disturbances created by Kalabhras.&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;The Land up to Kaveri&lt;/span&gt;&amp;nbsp;was acquired by him.&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Mahendravarman I is considered to be the greatest ruler of the Pallavas.&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;His reign was marked by many architectural and literary achievements which would lay the foundations of the future Art and Culture of South India.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Narasimhavarman II&amp;nbsp;built the Shore Temple and&amp;nbsp;the Kanchi Kailasanathar Temple at Mahabalipuram.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;These&amp;nbsp;temples are based&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;on the Rajsingh style.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Hiuen Tsang &lt;/strong&gt;visited Kanchipuram, the capital of Pallavas, during the reign of &lt;strong&gt;Narasimha Varman I.&lt;strong&gt;​&lt;/strong&gt;&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width:350px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;K&lt;strong&gt;ingdom&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;Capital&lt;/strong&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;Vijayanagara Empire&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;Hampi&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;Wadiyar Dynasty&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;Mysore&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;Pushyabhuti dynasty (Harshavardhana )&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;Kannauj&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;कांचीपुरम&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;पल्लवों&lt;/span&gt; की राजधानी &lt;span style=&quot;font-weight: 700;&quot;&gt;कांचीपुरम थी।&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;ul&gt;
	&lt;li&gt;पल्लव चौथी शताब्दी ईस्वी के आसपास दक्षिण में एक दुर्जेय शक्ति के रूप में उभरे और सातवीं शताब्दी ईस्वी में अपनी शक्ति के चरम पर थे।&lt;/li&gt;
	&lt;li&gt;वे &lt;span style=&quot;font-weight: 700;&quot;&gt;लगभग 500 वर्षों तक अपने शासन को बनाए रखने में सक्षम रहे।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;उन्होंने महान शहर, शिक्षा के केंद्र, मंदिर और मूर्तियां बनाईं और संस्कृति में दक्षिण पूर्व एशिया के एक बड़े हिस्से को प्रभावित किया।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सिंह विष्णु को पल्लवों का संस्थापक माना जाता है।&lt;/span&gt;

	&lt;ul&gt;
		&lt;li&gt;उन्होंने कालभ्रस द्वारा बनाई गई राजनीतिक गड़बड़ी को समाप्त कर दिया।&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;कावेरी तक की भूमि&lt;/span&gt; उसके द्वारा अधिग्रहित की गई थी।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;महेंद्रवर्मन प्रथम को पल्लवों का सबसे महान शासक माना जाता है।&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;उनके शासनकाल को कई स्थापत्य और साहित्यिक उपलब्धियों द्वारा चिह्नित किया गया था जो दक्षिण भारत की भविष्य की कला और संस्कृति की नींव रखते हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;नरसिंहवर्मन द्वितीय ने महाबलीपुरम में शोर मंदिर और कांची कैलासनाथर मंदिर का निर्माण किया।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;ये मंदिर &lt;span style=&quot;font-weight: 700;&quot;&gt;राजसिंह शैली पर आधारित हैं।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;ह्वेन त्सांग&lt;/strong&gt; ने &lt;strong&gt;नरसिंह वर्मन प्रथम&lt;/strong&gt; के शासनकाल के दौरान पल्लवों की राजधानी कांचीपुरम का दौरा किया था।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width:350px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;&lt;font color=&quot; &quot;&gt;साम्राज्य&lt;/font&gt;&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;&lt;font color=&quot; &quot;&gt;राजधानी&lt;/font&gt;&lt;/strong&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot; &quot;&gt;विजयनगर साम्राज्य&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot; &quot;&gt;हम्पी&lt;/font&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot; &quot;&gt;वाडियार राजवंश&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot; &quot;&gt;मैसूर&lt;/font&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot; &quot;&gt;पुष्यभूति वंश (हर्षवर्धन)&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot; &quot;&gt;कन्नौज&lt;/font&gt;&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p style=&quot;color:  (33, 37, 41);&quot;&gt;The correct answer is &lt;span style=&quot;font-weight: bolder;&quot;&gt;16&lt;/span&gt;.&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt; &lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color:  (33, 37, 41);&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Mahajanapadas:&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color:  (33, 37, 41);&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;As the rulers of the Mahajanapadas were building huge forts&lt;/span&gt;, maintaining big armies, they needed more resources.&lt;/li&gt;
	&lt;li&gt;And they needed officials to collect these. So, instead of depending on occasional gifts brought by people, as in the case of the Raja of the Janapadas, they started collecting regular taxes.&lt;/li&gt;
	&lt;li&gt;Taxes on crops were the most important.&lt;/li&gt;
	&lt;li&gt;This was because agriculture was the main occupation at that time.&lt;/li&gt;
	&lt;li&gt;Usually, &lt;span style=&quot;font-weight: 700;&quot;&gt;the tax was fixed at 1/6th of what was produced. &lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;This was known as bhaga or a share.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;For example, a weaver or a smith may have had to work for a day every month for the king.&lt;/li&gt;
	&lt;li&gt;During the &lt;span style=&quot;font-weight: bolder;&quot;&gt;second urbanisation period&lt;/span&gt; in ancient India, there were &lt;span style=&quot;font-weight: bolder;&quot;&gt;sixteen kingdoms&lt;/span&gt; that existed during the &lt;span style=&quot;font-weight: bolder;&quot;&gt;sixth to fourth century&lt;/span&gt; BCE known as &lt;span style=&quot;font-weight: bolder;&quot;&gt;Mahajanapadas.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;The Buddhist text &lt;span style=&quot;font-weight: bolder;&quot;&gt;Angutara Nikaya&lt;/span&gt; mention &lt;span style=&quot;font-weight: bolder;&quot;&gt;16&lt;/span&gt; &lt;span style=&quot;font-weight: bolder;&quot;&gt;Mahajanapadas.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width:350px;&quot;&gt;
	&lt;thead&gt;
		&lt;tr&gt;
			&lt;th scope=&quot;row&quot;&gt;Name of Mahajanapadas&lt;/th&gt;
			&lt;th scope=&quot;col&quot;&gt;Capital of Mahajanapadas&lt;/th&gt;
			&lt;th scope=&quot;col&quot;&gt;Today Location&lt;/th&gt;
		&lt;/tr&gt;
	&lt;/thead&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;th scope=&quot;row&quot;&gt;Asmaka or Assaka&lt;/th&gt;
			&lt;td&gt;Potali&lt;/td&gt;
			&lt;td&gt;Banks of Godavari&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;th scope=&quot;row&quot;&gt;Avanti&lt;/th&gt;
			&lt;td&gt;Ujjaini or Mahismati&lt;/td&gt;
			&lt;td&gt;Malwa and Madhya Pradesh&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;th scope=&quot;row&quot;&gt;Anga&lt;/th&gt;
			&lt;td&gt;Champa/Champanagri&lt;/td&gt;
			&lt;td&gt;Munger and Bhagalpur&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;th scope=&quot;row&quot;&gt;Chedi&lt;/th&gt;
			&lt;td&gt;Sothivati&lt;/td&gt;
			&lt;td&gt;Bundelkhand region&lt;/td&gt;
		&lt;/tr&gt;
